-- Poems batch 166
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('a274fcf3-f042-48cc-8a19-c975abb333c9','九月一日晨起風物凄然不勝懷遠之思作五首寄和父憨申併煩轉致湖池二州也  其二','趙蕃','宋','宋诗','song-poetry','','[]','節佳重九近，風急授衣初。',48,'全唐诗/poet.song.165000.json','["節佳重九近，風急授衣初。", "茱菊年齡邁，楓檉日夜疎。", "欲題懷遠句，頻展寄來書。", "憨子能思我，申兒更憶渠。"]'),
('da6cd2a4-261f-4e26-9c16-abb1aab1289e','九月一日晨起風物凄然不勝懷遠之思作五首寄和父憨申併煩轉致湖池二州也  其三','趙蕃','宋','宋诗','song-poetry','','[]','秋氣故悲哉，連陰况不開。',48,'全唐诗/poet.song.165000.json','["秋氣故悲哉，連陰况不開。", "黄花九日近，白髮數莖催。", "山際擎新塔，江邊峙舊臺。", "謾看雲日暮，安得雁同來。"]'),
('f8263687-adda-4156-a2b8-361a7268a34c','九月一日晨起風物凄然不勝懷遠之思作五首寄和父憨申併煩轉致湖池二州也  其四','趙蕃','宋','宋诗','song-poetry','','[]','姨母比苦脛，涉秋今若何。',48,'全唐诗/poet.song.165000.json','["姨母比苦脛，涉秋今若何。", "音書君定密，離苦我何多。", "鳬舄思文瑞，燈窗想驥和。", "何能俱款集，未厭數經過。"]'),
('3904669c-f4c2-4c83-8dce-886f966ab220','九月一日晨起風物凄然不勝懷遠之思作五首寄和父憨申併煩轉致湖池二州也  其五','趙蕃','宋','宋诗','song-poetry','','[]','秋浦新爲別，秋風闕寄書。',48,'全唐诗/poet.song.165000.json','["秋浦新爲別，秋風闕寄書。", "雖然聲問闊，未覺夢魂疎。", "杜牧登臨後，宛陵吟詠餘。", "三冬如有暇，五字不妨渠。"]'),
('728eb986-4f18-4df2-9e69-a1c28ee84b57','重陽前一日同成父二兒遊新庵','趙蕃','宋','宋诗','song-poetry','','[]','細雨不濕路，薄雲空礙山。',48,'全唐诗/poet.song.165000.json','["細雨不濕路，薄雲空礙山。", "窮居嫌局趣，乘興偶躋攀。", "並水楓初落，懸崖菊未斑。", "清游了無累，短句不須刪。"]'),
('4e7227f0-5cef-4206-8e36-a346cf16c2f0','楊謹仲和頃者三詩見貽復次韻六首  其一','趙蕃','宋','宋诗','song-poetry','','[]','江南秋得閏，草木向遲彫。',48,'全唐诗/poet.song.165000.json','["江南秋得閏，草木向遲彫。", "正性失松檜，羣生同艾蕭。", "漂流又舟楫，隠約念簞瓢。", "賸暑猶須葛，誰能遠致韶。"]'),
('7e9b1106-c883-47f5-92f3-cc25cadf7294','楊謹仲和頃者三詩見貽復次韻六首  其二','趙蕃','宋','宋诗','song-poetry','','[]','去年才一識，何意復茲行。',48,'全唐诗/poet.song.165000.json','["去年才一識，何意復茲行。", "隠墅全依郭，幽居亦占名。", "萬金真國士，十室漫鄉評。", "漢制誰綿蕝，且徵齊魯生。"]'),
('5caaf894-d527-42eb-b722-7eddd3e6037e','楊謹仲和頃者三詩見貽復次韻六首  其三','趙蕃','宋','宋诗','song-poetry','','[]','功名誤黑頭，晚卧此山幽。',48,'全唐诗/poet.song.165000.json','["功名誤黑頭，晚卧此山幽。", "落拓揚執戟，浮沉馬少游。", "豆芻千里駿，煙草五湖鷗。", "早晚相從去，高深日縱搜。"]'),
('1f26a250-f500-4c01-89ef-cad6529e01eb','楊謹仲和頃者三詩見貽復次韻六首  其四','趙蕃','宋','宋诗','song-poetry','','[]','病骨覺難强，鬢華驚易彫。',48,'全唐诗/poet.song.165000.json','["病骨覺難强，鬢華驚易彫。", "壯懷鯨訪李，老習蚓同蕭。", "久已思拋笏，悠哉曷泛瓢。", "東遊穴探禹，西上石賓韶。"]'),
('3034e06a-48aa-44a0-99fc-e1d68d09c845','楊謹仲和頃者三詩見貽復次韻六首  其五','趙蕃','宋','宋诗','song-poetry','','[]','江湖余所樂，歲月老于行。',48,'全唐诗/poet.song.165000.json','["江湖余所樂，歲月老于行。", "酒有杯中趣，詩無世上名。", "悠悠真自得，悄悄莫加評。", "尚要高交友，風期同死生。"]'),
('5d0163c1-0aa6-4928-a13b-3286bb12d42d','楊謹仲和頃者三詩見貽復次韻六首  其六','趙蕃','宋','宋诗','song-poetry','','[]','不減浣花頭，仍兼事事幽。',48,'全唐诗/poet.song.165000.json','["不減浣花頭，仍兼事事幽。", "渾忘帝城札，好在竹林遊。", "有意求如願，無機防海鷗。", "秋凉入吾樹，舊讀定能搜。"]'),
('0f38942f-0307-4cb2-b594-f83c8c910268','次韻莫令因迓使者同泛舟至漂神已而誤焉問宿臨江鍾氏之閣二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','我割僅鉛刀，公銛比孟勞。',48,'全唐诗/poet.song.165000.json','["我割僅鉛刀，公銛比孟勞。", "莫酬談絕倒，難和句揮毫。", "既誤前驅遠，不妨乘興高。", "悠然風月底，脫略異官曹。"]'),
('414bce1d-1445-4d9e-984e-215db643239d','次韻莫令因迓使者同泛舟至漂神已而誤焉問宿臨江鍾氏之閣二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','璧月儼中懸，村空聽悄然。',48,'全唐诗/poet.song.165000.json','["璧月儼中懸，村空聽悄然。", "借床依樹閣，輟棹上灘船。", "物外我懷趣，區中公了緣。", "異時殊出處，安否要詩傳。"]'),
('5a11ef77-c5de-4146-8d22-7cc5647cf255','慶伯以二詩送別已而又辱同廣聲追送慶伯復有所賦併次韻爲答三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','在昔歌詩義，嘗關治亂音。',48,'全唐诗/poet.song.165000.json','["在昔歌詩義，嘗關治亂音。", "流傳縱今體，陶寫亦吾心。", "未答論交作，還賡送別吟。", "識君于此道，亦復用功深。"]'),
('15d86bab-3f95-4850-b074-c5ad8b75c1ae','慶伯以二詩送別已而又辱同廣聲追送慶伯復有所賦併次韻爲答三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','凜凜君中外，堂堂國盛明。',48,'全唐诗/poet.song.165000.json','["凜凜君中外，堂堂國盛明。", "曾聞百年契，豈待一朝盟。", "老矣我何事，勉哉君勿輕。", "科名雖世業，直道是家聲。"]'),
('c7f7d6af-4ac7-472e-bd10-1239f3480d62','慶伯以二詩送別已而又辱同廣聲追送慶伯復有所賦併次韻爲答三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','試問爲黔郡，何如與質要。',48,'全唐诗/poet.song.165000.json','["試問爲黔郡，何如與質要。", "其行既穹絕，有思只飄蕭。", "但悔嶮投足，未論官折腰。", "同舟故能送，折簡不勞招。"]'),
('ce6fcd5e-9d92-4c28-85ed-4d8d93716e53','再來常州昭禮出示虞山往來詩卷先是昭禮與予共載昭禮上虞山予過溧陽昭禮有詩次韻','趙蕃','宋','宋诗','song-poetry','','[]','舟人厭牽挽，我輩樂縈紆。',48,'全唐诗/poet.song.165000.json','["舟人厭牽挽，我輩樂縈紆。", "晨起愁分背，逢人屢問塗。", "看君著屐進，雅勝折腰趨。", "此段真高邁，詩中不可無。"]'),
('7bcec1ea-53ba-43df-bd6d-3935e3950754','次畢叔文見貽二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','山川略吳楚，歲月涉春秋。',48,'全唐诗/poet.song.165000.json','["山川略吳楚，歲月涉春秋。", "爲米媿元亮，乘舟思子猷。", "黑貂塵土重，白鬢雪霜稠。", "志合成三益，詩來減四愁。"]'),
('f42ef539-3804-420d-bfcc-d2213c023d07','次畢叔文見貽二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','寂寞吾知貴，紛華世所榮。',48,'全唐诗/poet.song.165000.json','["寂寞吾知貴，紛華世所榮。", "常評敗素紫，孰愈濁纓清。", "爵祿心無食，山林志有盟。", "幽居自空谷，哲婦乃傾城。"]'),
('5130037d-8003-4014-abab-a29b1cf60110','次季奕見懷','趙蕃','宋','宋诗','song-poetry','','[]','雨脚何其厚，雲頭不易空。',48,'全唐诗/poet.song.165000.json','["雨脚何其厚，雲頭不易空。", "病憐山叟甚，詩喜故人通。", "慰藉殷勤裏，吟哦悵望中。", "地爐無熱火，林屋但鳴風。"]'),
('fc4ebeac-55ab-488b-a698-0dc86b39733c','次韻歐陽伯威見和','趙蕃','宋','宋诗','song-poetry','','[]','宗派滔滔是，于今得障流。',48,'全唐诗/poet.song.165000.json','["宗派滔滔是，于今得障流。", "無悲和者寡，故愈暗中投。", "我願下取履，君其高卧樓。", "穹岡如許割，肯愛一官休。"]'),
('29198ebf-613f-4a6b-9410-1c20be476619','劉兄垂示同張兄遊向園呈先生詩卷次韻','趙蕃','宋','宋诗','song-poetry','','[]','聞道輿籃出，興懷反棹時。',48,'全唐诗/poet.song.165000.json','["聞道輿籃出，興懷反棹時。", "身雖縛官簿，心豈忘筇枝。", "已後斜川集，方賡人日詩。", "因君竹林詠，動我故園思。"]'),
('5c401f08-eacd-4f3b-8391-9b2af009b514','次韻子肅懷遠齋併以見及','趙蕃','宋','宋诗','song-poetry','','[]','如公人物表，上下孰分床。',48,'全唐诗/poet.song.165000.json','["如公人物表，上下孰分床。", "但有官成集，初無智作囊。", "所嗟人契闊，不爲雨悲凉。", "顧我端何幸，新詩獲夜光。"]'),
('c032f7b0-5435-4c52-9a72-ff13d3a1cbab','陳擇之經過以贛守留尚書得祠亟歸別之其行甚遽途中有詩見寄次韻','趙蕃','宋','宋诗','song-poetry','','[]','過我不停軌，嗔公但憶歸。',48,'全唐诗/poet.song.165000.json','["過我不停軌，嗔公但憶歸。", "民思河內借，士失荆州依。", "別去目易極，詩來寒益衣。", "今時未爲貴，歲晚望荆扉。"]'),
('2a6a097c-86d6-49a1-9d33-36757c16d117','僉判丈兩賜新字韻詩因次韻兼簡文顯','趙蕃','宋','宋诗','song-poetry','','[]','連朝枉詩句，俊逸且清新。',48,'全唐诗/poet.song.165000.json','["連朝枉詩句，俊逸且清新。", "歎我徒勞思，知公固絕人。", "林園能數駕，風雨未妨辰。", "作底周夫子，關門懶似真。"]'),
('b6669c08-542b-483c-b06d-ec7499d80d77','次韻審知寄來二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','一日復一日，何勝一萬周。',48,'全唐诗/poet.song.165000.json','["一日復一日，何勝一萬周。", "有山皆崒崒，無水不悠悠。", "爲我謀歸策，將詩說舊遊。", "山林與城市，吾亦任乘流。"]'),
('a4b7484d-92d3-45b5-977c-e1bc348707e4','次韻審知寄來二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','書去愁難悉，詩來造愈奇。',48,'全唐诗/poet.song.165000.json','["書去愁難悉，詩來造愈奇。", "爲言僧可寓，爲念橐空垂。", "鳴鴂驚時晚，羈鴻暫水湄。", "逆風仍上水，日月是難期。"]'),
('cc963d06-4e46-41bf-b253-150412fd5389','復次韻呈沅陵諸丈并懷在伯二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','逸興猶鷗白，殘驅異犢黄。',48,'全唐诗/poet.song.165000.json','["逸興猶鷗白，殘驅異犢黄。", "青衫漫蠻府，黄帽合鱸鄉。", "既自老將至，何由心甚長。", "倘能藏斗酒，未暇博西凉。"]'),
('7babb368-26b2-47b9-b0f9-eea1d7bad00e','復次韻呈沅陵諸丈并懷在伯二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','佳詩如雋永，餘論敢雌黄。',48,'全唐诗/poet.song.165000.json','["佳詩如雋永，餘論敢雌黄。", "幸甚官同府，懷哉居擇鄉。", "江湖身固遠，風月興何長。", "勿作湘纍弔，行賡殿閣凉。"]'),
('4bc7f660-6d8b-4c14-a3a0-d2448c0a27c9','成父有詩懷斯遠次韻','趙蕃','宋','宋诗','song-poetry','','[]','港汊自相見，去來元一風。',48,'全唐诗/poet.song.165000.json','["港汊自相見，去來元一風。", "無寧敢天怨，亦未决途窮。", "白社明朝是，南山幾驛中。", "君歸不能遠，我去若爲同。"]'),
('06014246-c8f9-4a05-8892-c1724fc64083','次韻吳仲權鎰見簡','趙蕃','宋','宋诗','song-poetry','','[]','今代風騷將，先生合冠軍。',48,'全唐诗/poet.song.165000.json','["今代風騷將，先生合冠軍。", "幾年求識面，數刻遂離羣。", "江急舟難駐，風回櫓細聞。", "還家經醉卧，斜日對爐熏。"]'),
('b79f7203-8f50-4585-ae38-a7ddc800675b','教授丈作黄字韻詩十首愈出愈奇而有作法孰爲凉之句何耶因次韻以見窘','趙蕃','宋','宋诗','song-poetry','','[]','苦思髭催白，交馳耳困黄。',48,'全唐诗/poet.song.165000.json','["苦思髭催白，交馳耳困黄。", "欣欣貪得侶，落落異殊鄉。", "顧欲窮余短，安能敵衆長。", "蒹葭倚玉樹，華衮照龐凉。"]'),
('aa6bac68-3e01-4362-bf15-61d28e3036f4','廣文先生送詩方思所以報之而未得忽鸝落庭樹殆天與此韻也李君在傍知狀','趙蕃','宋','宋诗','song-poetry','','[]','君亭摇鷺羽，我樹下鸝黄。',48,'全唐诗/poet.song.165000.json','["君亭摇鷺羽，我樹下鸝黄。", "政爾無何境，能來底處鄉。", "搜尋疑日短，吟諷喜風長。", "獨愧非韓敵，聯詩效納凉。"]'),
('c58a4d53-5056-4ce8-b100-1bebb837ff82','次王照鄰滕彥真韻二首  其一','趙蕃','宋','宋诗','song-poetry','','["\u534e\u5c71"]','黄妳能生睡，朱絃孰寫憂。',48,'全唐诗/poet.song.165000.json','["黄妳能生睡，朱絃孰寫憂。", "客居茲已病，歸去合成謀。", "華嶽雖遥吏，陶窗得素求。", "小舟何日具，湖水正漫洲。"]'),
('40fd17d0-4a29-4f3f-b024-895d4f2080f7','次王照鄰滕彥真韻二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','王子詩如照，滕侯隠似真。',48,'全唐诗/poet.song.165000.json','["王子詩如照，滕侯隠似真。", "倘來寧取遇，居易若爲屯。", "酬倡雖纔始，風期自夙親。", "江湖縱悠遠，德盛罔非鄰。"]'),
('d22bb475-50bf-46dc-8b2a-daa7286db0da','次滕彥真韻三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','地接沅湘古，人留屈賈香。',48,'全唐诗/poet.song.165000.json','["地接沅湘古，人留屈賈香。", "政須煩勝士，時爲發幽光。", "貽我祛愁具，懷君待月章。", "朦朧成少味，失喜見琳瑯。"]'),
('c66e4d81-ed07-4685-b005-a1cb11427083','次滕彥真韻三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','暫作長沙住，侵尋兩過年。',48,'全唐诗/poet.song.165000.json','["暫作長沙住，侵尋兩過年。", "蕭然唯壁立，終矣欠蓬編。", "盡室嗟長客，歸途喜再緣。", "還家定何許，當在早梅前。"]'),
('515e4457-a2f7-436a-96bc-7b3d257e7166','次滕彥真韻三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','我欲湘西看，行須覓渡船。',48,'全唐诗/poet.song.165000.json','["我欲湘西看，行須覓渡船。", "何如臨絕頂，得以盡長川。", "鷗鷺煙雲表，蚊虻埃𡏖前。", "隠寧分大小，那更別山鄽。"]'),
('13d57cae-0123-4844-a7f7-88cf5ea70fc1','次韻叔驥兼呈伯瑞二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','晚作臨邛客，相如真倦游。',48,'全唐诗/poet.song.165000.json','["晚作臨邛客，相如真倦游。", "又成悲卒歲，及此問歸舟。", "共隠期他日，相逢記此州。", "江湖有來雁，可以謝書不。"]'),
('65e762d4-a74b-4fd5-b683-f304a88ee143','次韻叔驥兼呈伯瑞二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','貽我五字句，清詩曷以酬。',48,'全唐诗/poet.song.165000.json','["貽我五字句，清詩曷以酬。", "端知檄愈疾，未信酒忘憂。", "多難屢瀕死，諸兄虛見收。", "病駒叨蓆秣，顧影益增羞。"]'),
('af1bc1f0-4a60-496e-97af-275fa98ca686','陳丞以南安寨上所得二詩及到龍泉聞余戍地最遠見懷二首爲寄次韻  其一','趙蕃','宋','宋诗','song-poetry','','[]','郴州何許是，山遠水仍多。',48,'全唐诗/poet.song.165000.json','["郴州何許是，山遠水仍多。", "江徼重重柵，田夫戶戶戈。", "雷同嗟不早，嘆我亦奔波。", "未必甘如此，而今敢謂何。"]'),
('a075332f-2a89-4329-acab-10e2bc440edf','陳丞以南安寨上所得二詩及到龍泉聞余戍地最遠見懷二首爲寄次韻  其二','趙蕃','宋','宋诗','song-poetry','','[]','路窮千澗底，人絕萬山旁。',48,'全唐诗/poet.song.165000.json','["路窮千澗底，人絕萬山旁。", "暝宿茅寮冷，晨炊土竈荒。", "多年布衾裂，倍覺夜蔬香。", "有底從軍樂，題詩日在忙。"]'),
('afac0319-363f-425b-9cc9-ee15e8840f8d','陳丞以南安寨上所得二詩及到龍泉聞余戍地最遠見懷二首爲寄次韻  其三','趙蕃','宋','宋诗','song-poetry','','[]','問我能嗟遠，如公肯見卑。',48,'全唐诗/poet.song.165000.json','["問我能嗟遠，如公肯見卑。", "十分期一見，四首僅蒙詩。", "儻許抄傳可，何堪絕贈宜。", "雖然籍湜輩，附此姓名知。"]'),
('130f8539-7739-4710-a67e-c7a30e888afc','陳丞以南安寨上所得二詩及到龍泉聞余戍地最遠見懷二首爲寄次韻  其四','趙蕃','宋','宋诗','song-poetry','','[]','剪茅仍伐木，去凸亦鉏坳。',48,'全唐诗/poet.song.165000.json','["剪茅仍伐木，去凸亦鉏坳。", "響屐無驚謝，投金政擬郊。", "百年終顯晦，一稔在肥磽。", "隠地兩成隔，頹牆空長梢。"]'),
('8a28e18a-d41c-4a6a-8cf8-8e9f303156cf','再用前韻并寄孫推官四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','試覓圖經看，宜章路幾多。',48,'全唐诗/poet.song.165000.json','["試覓圖經看，宜章路幾多。", "彼謀寧去穴，吾備且橫戈。", "累土生平地，安流起丈波。", "計愚無可採，敢復問云何。"]'),
('da2437cb-2175-4364-82e4-10a9388d0127','再用前韻并寄孫推官四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','恍惚迷來際，周章失去傍。',48,'全唐诗/poet.song.165000.json','["恍惚迷來際，周章失去傍。", "怕聞行戍遠，愁聽哭田荒。", "要挽天河水，方焚玉帳香。", "夷吾政分閫，吾黨詎應忙。"]'),
('ad3fb1a1-39cd-4fd6-b450-23f983c2bbee','再用前韻并寄孫推官四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','青雲懷趣逸，黄綬屈官卑。',48,'全唐诗/poet.song.165000.json','["青雲懷趣逸，黄綬屈官卑。", "屢捧將軍檄，一哦從事詩。", "少陵憂有在，充國事多宜。", "儻上休兵議，因人願早知。"]'),
('bf557a9d-d0ed-4520-b16e-e9ee71f983d2','再用前韻并寄孫推官四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','我亦端渠似，圖中見此坳。',48,'全唐诗/poet.song.165000.json','["我亦端渠似，圖中見此坳。", "一身非憚嶮，十日未窮郊。", "問水水源絕，逢山山石磽。", "政便安蹇足，敢說負蕭梢。"]'),
('a31a2b65-3f91-462d-b8d1-6bee5e715a32','次韻深父送行','趙蕃','宋','宋诗','song-poetry','','[]','吾行殊坎坷，此地極淹留。',48,'全唐诗/poet.song.165000.json','["吾行殊坎坷，此地極淹留。", "少欲破萬卷，老惟思一邱。", "謾言詩作祟，長愧食爲謀。", "穮蔉君其務，農良乃有秋。"]'),
('8aee6705-59f2-4b34-8c9f-91e4a4dd7a7b','子進示懷玉詩卷有歸途見懷恨不同遊二詩次韻  其一','趙蕃','宋','宋诗','song-poetry','','[]','望壓大江東，茲峰獨著雄。',48,'全唐诗/poet.song.165000.json','["望壓大江東，茲峰獨著雄。", "潛珍伏其下，神畫隠於中。", "舊俗多龐說，因公得髓窮。", "從今逢有問，身與到山同。"]'),
('ec0a31b7-6ebf-4cbe-a0a7-c064fa98be82','子進示懷玉詩卷有歸途見懷恨不同遊二詩次韻  其二','趙蕃','宋','宋诗','song-poetry','','[]','山有英靈在，眼應青白分。',48,'全唐诗/poet.song.165000.json','["山有英靈在，眼應青白分。", "問禪公得髓，呈佛我無文。", "意賞人知獨，神遊默固羣。", "清詩傳妙旨，讀罷雨花紛。"]'),
('9214a3c6-338a-4bd0-bded-d8ad5db362d5','贛丞曾幼度相邀過明叔買江天閣幼度有詩明叔與成父弟皆和之亦次韻','趙蕃','宋','宋诗','song-poetry','','[]','落本千山迥，空江一带橫。',48,'全唐诗/poet.song.165000.json','["落本千山迥，空江一带橫。", "畫圖非意匠，詩句亦天成。", "老我頭今白，逢渠眼暫明。", "詰朝山嶽隔，杯面莫多爭。"]'),
('1cae9daa-f345-49bb-aa73-f11adb58af07','遠齋頃寄在湖日所作三詩舟中次韻  其一','趙蕃','宋','宋诗','song-poetry','','[]','黜陟無新報，山川懷昔人。',48,'全唐诗/poet.song.165000.json','["黜陟無新報，山川懷昔人。", "詩能言我志，貧不累吾身。", "登眺盡遺勝，經行那厭頻。", "江頭釣竿客，何物是玄真。"]'),
('65f35014-877b-43c2-a51e-b2b8dd2247ff','遠齋頃寄在湖日所作三詩舟中次韻  其二','趙蕃','宋','宋诗','song-poetry','','[]','近日杭州見，殷勤蒙置樽。',48,'全唐诗/poet.song.165000.json','["近日杭州見，殷勤蒙置樽。", "別來幾朝夕，書問欠寒溫。", "譚妙元超詣，詩高外語言。", "何當從杖履，底盡得深論。"]'),
('ce51733c-8446-42ce-b9f1-518e78c7299d','遠齋頃寄在湖日所作三詩舟中次韻  其三','趙蕃','宋','宋诗','song-poetry','','[]','向來吳楚隔，書札苦難通。',48,'全唐诗/poet.song.165000.json','["向來吳楚隔，書札苦難通。", "信與衢相接，我歸公亦同。", "寓懷須酒聖，適意豈詩窮。", "情性思陶冶，吾寧較拙工。"]'),
('3e053f8b-bf20-4bd7-9381-848077e14645','次韻愚卿留別','趙蕃','宋','宋诗','song-poetry','','[]','有約端能赴，如君信可人。',48,'全唐诗/poet.song.165000.json','["有約端能赴，如君信可人。", "解衝衡嶽雪，寧問海棠春。", "雨後雖懸榻，泥塗政沒輪。", "笑談能款款，書札勝頻頻。"]'),
('9a3dbea1-807f-4b04-b524-ec3c93ec4244','次韻鄭季奕見寄二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','暑退伏纔末，月明秋又中。',48,'全唐诗/poet.song.165000.json','["暑退伏纔末，月明秋又中。", "蛩多喧向夕，蟬寂罷吟風。", "留滯周南事，蒼茫阮籍窮。", "寄書無厚祿，猶喜見詩工。"]'),
('70e09a72-95db-41e0-b18b-bda1a4e73f6a','次韻鄭季奕見寄二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','一寫山中信，自嗟天外人。',48,'全唐诗/poet.song.165000.json','["一寫山中信，自嗟天外人。", "詩無詠貧士，政豈失窮民。", "已悟哀仍樂，勿論亨與屯。", "我交非勢利，寧有白頭新。"]'),
('7e8d492a-7f52-4abf-ae1d-d7b87aeb1345','次韻黄子耕因任伯起見寄之作','趙蕃','宋','宋诗','song-poetry','','[]','客有能相覓，書來慰我思。',48,'全唐诗/poet.song.165000.json','["客有能相覓，書來慰我思。", "貧寧可詩罪，老不悟書癡。", "舊友厪長憶，新交曷取知。", "况渠停軌日，政我出山時。"]'),
('85e66fd1-7f1a-4f49-a9ce-55ff5c6b9b65','三詩寄郭古夫  其一','趙蕃','宋','宋诗','song-poetry','','[]','巫峽聞歸旆，瀟湘說定居。',48,'全唐诗/poet.song.165000.json','["巫峽聞歸旆，瀟湘說定居。", "若親千里面，曾捧一緘書。", "山檜風霜老，江楓日夜疎。", "窮秋已凉冷，體候復何如。"]'),
('4545859d-6eaa-4386-b183-3aa1ad47d6d7','三詩寄郭古夫  其二','趙蕃','宋','宋诗','song-poetry','','[]','往日臺郎選，今年散吏員。',48,'全唐诗/poet.song.165000.json','["往日臺郎選，今年散吏員。", "詞華推匠哲，問學得師傳。", "視草應栖掖，談經合細旃。", "諸公曷逃責，詔旨尚求賢。"]'),
('e027218a-111a-472b-bbc2-d5ebdbbd72db','三詩寄郭古夫  其三','趙蕃','宋','宋诗','song-poetry','','[]','丐去秋今晚，能歸歲且徐。',48,'全唐诗/poet.song.165000.json','["丐去秋今晚，能歸歲且徐。", "須公一尊酒，勝我十年書。", "生死交情異，乖離人事疎。", "如聞厚風誼，何敢自趦趄。"]'),
('41dfd474-4793-4638-b3d0-f791c98edb89','至夜讀子肅詩卷帖','趙蕃','宋','宋诗','song-poetry','','[]','應接有不暇，幽憂能頓除。',48,'全唐诗/poet.song.165000.json','["應接有不暇，幽憂能頓除。", "明當增短日，後且愴離居。", "恨我平生友，翻成咫尺疎。", "爲生端不易，作客又何如。"]'),
('c1f7c68b-daf1-4c9f-ad79-5b7f02a3094b','午飯資福寺','趙蕃','宋','宋诗','song-poetry','','[]','病骨怯秋凜，羸驂疲路長。',48,'全唐诗/poet.song.165000.json','["病骨怯秋凜，羸驂疲路長。", "人烟少行店，樓閣見僧房。", "憇息今成暫，從游舊不忘。", "却塵看姓字，淮楚路茫茫。"]'),
('45a11267-d846-436f-8f42-dd40bba32092','二月十九日同兩都監沅陵令尉餞敘浦簿公子興福  其一','趙蕃','宋','宋诗','song-poetry','','[]','隨處野花發，所須村酒沽。',48,'全唐诗/poet.song.165000.json','["隨處野花發，所須村酒沽。", "江平初出岸，山好漸成圖。", "從此經行地，能留物色無。", "少陵那老蜀，張翰政思吳。"]'),
('a62dd2ee-d613-4af9-a112-918633c0c4ac','二月十九日同兩都監沅陵令尉餞敘浦簿公子興福  其二','趙蕃','宋','宋诗','song-poetry','','[]','慨我復成留，辭君重作愁。',48,'全唐诗/poet.song.165000.json','["慨我復成留，辭君重作愁。", "春風渺歸鴈，野水迥浮鷗。", "已別還來見，因行亦當游。", "同僚二三子，杯酒互相酬。"]'),
('5476c401-2f77-4a17-8cf0-9af082f1b7fb','過明叔有詩次韻','趙蕃','宋','宋诗','song-poetry','','[]','出門無所詣，引興獨茲長。',48,'全唐诗/poet.song.165000.json','["出門無所詣，引興獨茲長。", "萬事一杯酒，三春百草芳。", "暇能過巷隠，癡豈累官忙。", "久坐疑成晚，樵歸漁返鄉。"]'),
('3aa0d6b4-d0ea-46da-bbf2-6e691e3dc1cf','春盡','趙蕃','宋','宋诗','song-poetry','','[]','南國春方盡，南風吹晝長。',48,'全唐诗/poet.song.165000.json','["南國春方盡，南風吹晝長。", "野香花襲草，秀色麥侵桑。", "客子政懷倦，田家任苦忙。", "悵予終愧汝，垂老未渠央。"]'),
('232047b5-7bf2-41d9-925f-89d49a127525','春盡日','趙蕃','宋','宋诗','song-poetry','','[]','山密風蟠木，簷疎雨著窗。',48,'全唐诗/poet.song.165000.json','["山密風蟠木，簷疎雨著窗。", "擁衣憎舊絮，酌酒愛新缸。", "放意初無累，冥觀久已降。", "一春今日盡，歸夢渺三江。"]'),
('22f36d9d-16c1-4688-b645-729a5bebca83','寄在伯二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','積雨旱凉天，南風下水船。',48,'全唐诗/poet.song.165000.json','["積雨旱凉天，南風下水船。", "江山渾未識，魚稻不論錢。", "在路幾何日，得詩多少篇。", "何當重相見，尊酒話蟬聯。"]'),
('2ecbc1c0-1253-4e38-a447-b03b845a3a0a','寄在伯二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','成我中興年，朝家政急賢。',48,'全唐诗/poet.song.165000.json','["成我中興年，朝家政急賢。", "侍臣更論薦，東閣重招延。", "子去當茲日，才惟莫與先。", "習軒經濟學，於此定爲川。"]'),
('96027155-7e0b-4e82-b80e-9cd99bb51ba5','寄鄭伯元','趙蕃','宋','宋诗','song-poetry','','[]','文學崔斯立，才名鄭廣文。',48,'全唐诗/poet.song.165000.json','["文學崔斯立，才名鄭廣文。", "傳聞定省暇，不廢簿書勤。", "流落誰如我，交親更念君。", "水西佳絕處，詩就想超羣。"]'),
('f3c32fc2-74c3-4d6c-9256-73693be6cdbf','寄徐季益四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','不見徐夫子，於今已二年。',48,'全唐诗/poet.song.165000.json','["不見徐夫子，於今已二年。", "轉頭疑夙昔，屈指悟推遷。", "書欠洪喬寄，詩煩阿買傳。", "相思到極地，把誦一悠然。"]'),
('e1347507-2807-4bf5-81bd-10e55daa0156','寄徐季益四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','君不減徐穉，豫章仍主人。',48,'全唐诗/poet.song.165000.json','["君不減徐穉，豫章仍主人。", "結交非勢利，此客况清真。", "今日山中友，他年席上珍。", "玉堂如伴直，怨句不須陳。"]'),
('8a660643-5276-4073-afff-8a98c7f93f51','寄徐季益四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','呂氏多人物，譬之珠玉淵。',48,'全唐诗/poet.song.165000.json','["呂氏多人物，譬之珠玉淵。", "世官渠有命，家學定誰傳。", "籍甚羣公譽，皆云正字賢。", "掖垣君舊識，聊與話當年。"]'),
('5a68f228-2e74-4562-9820-416a9126392c','寄徐季益四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','我已非青鬢，君今定白鬚。',48,'全唐诗/poet.song.165000.json','["我已非青鬢，君今定白鬚。", "田園稍治否，寢飯比佳無。", "聞道爲歸計，何當出此塗。", "相期一邂逅，得以話艱虞。"]'),
('f85580db-c28b-409c-8242-7600c1d12659','寄公擇兼問訊季益二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昨分携地，陰風送酒杯。',48,'全唐诗/poet.song.165000.json','["憶昨分携地，陰風送酒杯。", "深嗟九日菊，未說一枝梅。", "我友多貧士，夫君况茂才。", "行藏苟無媿，流落未須哀。"]'),
('d7e4bb63-d2c1-4521-9567-be15db97c382','寄公擇兼問訊季益二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','孺子家何在，溪邊百尺臺。',48,'全唐诗/poet.song.165000.json','["孺子家何在，溪邊百尺臺。", "句追唐甫白，詞鄙漢鄒枚。", "此士誠高遯，諸公謾挽推。", "因過問消息，幾日送詩來。"]'),
('280358b5-8326-46d0-91a7-83f426f92be1','寄審知并屬彥博三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','病榻論詩罷，僧輿趨駕歸。',48,'全唐诗/poet.song.165000.json','["病榻論詩罷，僧輿趨駕歸。", "倦書疎竹几，多夢遶湖扉。", "赤葉霜前墜，黄花雨後稀。", "直堪凋鬢髮，何祇減腰圍。"]'),
('7485f875-7fc3-4b59-bed7-1da20abbc42c','寄審知并屬彥博三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','地迥林逃斫，湖深水易平。',48,'全唐诗/poet.song.165000.json','["地迥林逃斫，湖深水易平。", "鄰多爲圃住，門有趁虛行。", "遊釣昔愛此，林廬曾屬情。", "誰歟二畝乞，已矣一枝營。"]'),
('0e34a9b3-832f-4ed0-9b1f-df61fd322afc','寄審知并屬彥博三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','豫章稠衆木，孔翠逐羣飛。',48,'全唐诗/poet.song.165000.json','["豫章稠衆木，孔翠逐羣飛。", "梁棟期終用，文章莫露機。", "枉爲時俗忌，空使寸心違。", "語以王郎子，因來答是非。"]'),
('fdb82f02-32b9-4a3e-a23d-e1a8070d1cb0','寄成父并帖彥博審知  其一','趙蕃','宋','宋诗','song-poetry','','[]','貧賤分離苦，飄流日月除。',48,'全唐诗/poet.song.165000.json','["貧賤分離苦，飄流日月除。", "重沽分歲酒，空展寄來書。", "祖印書齊架，章泉竹遶廬。", "生涯故在此，調護合何如。"]'),
('1e927944-13dc-4128-81f2-360f4c44d7a6','寄成父并帖彥博審知  其二','趙蕃','宋','宋诗','song-poetry','','[]','霜落湖邊路，林疎溪上居。',48,'全唐诗/poet.song.165000.json','["霜落湖邊路，林疎溪上居。", "向來行載酒，今日問憑書。", "一飽異初計，五言真累渠。", "故人誰我念，煩爲語王徐。"]'),
('6e0f6f01-689c-49f9-88d8-1bd57fd3071b','寄懷伯瑞','趙蕃','宋','宋诗','song-poetry','','[]','四海今詩伯，三衢聊署曹。',48,'全唐诗/poet.song.165000.json','["四海今詩伯，三衢聊署曹。", "望之甘錄錄，桀溺病滔滔。", "有志躬簑笠，寧能類桔槹。", "我交天下士，如子未多遭。"]'),
('23d4aa15-c289-4085-8ce4-c0b59fc8e24a','文叔轉送畏知初到長沙寄諸弟及示同志二詩次韻寄畏知二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','山林容我病，道路憶君長。',48,'全唐诗/poet.song.165000.json','["山林容我病，道路憶君長。", "忽枉瀟湘句，中含屈宋香。", "細參同晤語，深卷勝書行。", "歸棹知非遠，胡爲苦念鄉。"]'),
('0f7a0417-6c43-498c-a387-978223ffe883','文叔轉送畏知初到長沙寄諸弟及示同志二詩次韻寄畏知二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','聞道湖南幕，人無第二流。',48,'全唐诗/poet.song.165000.json','["聞道湖南幕，人無第二流。", "文書有餘暇，風月可銷憂。", "夢遠寧能續，詩成謾益愁。", "幽庭步春草，雞撼屋山頭。"]'),
('a01b2be5-0e81-471a-a5bc-c4be6260412a','寄明叔且示逸遠','趙蕃','宋','宋诗','song-poetry','','[]','別我已似久，起予當有詩。',48,'全唐诗/poet.song.165000.json','["別我已似久，起予當有詩。", "筠窗坐風雨，兒輩樂塤箎。", "歸日近休日，春時盛此時。", "觀山仍快閣，太史昔幽期。"]'),
('d92e353a-4f08-4ce1-89a4-1a7a6d64d999','寄李寧卿','趙蕃','宋','宋诗','song-poetry','','[]','不寄來南錄，但傳多景詩。',48,'全唐诗/poet.song.165000.json','["不寄來南錄，但傳多景詩。", "長安分袂後，湘水寄書時。", "我欲歸三徑，君方聞四馳。", "未知回首地，寧有盍簪期。"]'),
('df38ddf3-8a8c-4495-9c2c-195a520a3f6e','以舊詩寄投謝昌國三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','昔在方齋老，南遊爲我言。',48,'全唐诗/poet.song.165000.json','["昔在方齋老，南遊爲我言。", "廬陵得佳士，康樂有賢孫。", "許可渠不易，殷勤相與論。", "元賓雖已矣，所與見如存。"]'),
('3c2ceb2d-b192-4b26-8661-95e61e5fb8de','以舊詩寄投謝昌國三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我有江西役，清江公所鄉。',48,'全唐诗/poet.song.165000.json','["我有江西役，清江公所鄉。", "放舟頻下上，欲見苦參商。", "扁榜書皆到，流傳句必香。", "何當仍大嚼，鼎味也先嘗。"]'),
('06a65a12-d8df-448e-90a0-29ade19fcc08','以舊詩寄投謝昌國三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','活法公家論，東萊盖有承。',48,'全唐诗/poet.song.165000.json','["活法公家論，東萊盖有承。", "先生真伯仲，小子愧雲仍。", "昧昧鼠爲璞，紛紛蟲語冰。", "今朝方見佛，平日謾依僧。"]'),
('6a170355-3c05-42cc-a1a6-68e37b5e4cf9','寄周文顯二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','我敬周夫子，安貧得士常。',48,'全唐诗/poet.song.165000.json','["我敬周夫子，安貧得士常。", "眇然居陋巷，隠若卧襄陽。", "應對昔爲役，滯濡今阻方。", "雖慙壽陵步，猶擬舊君傍。"]'),
('54b33871-5d56-4171-a728-22a8bbf937ec','寄周文顯二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','白雪郢中少，青蠅楚國多。',48,'全唐诗/poet.song.165000.json','["白雪郢中少，青蠅楚國多。", "知音自古爾，讒口奈渠何。", "皎皎寧遭汙，冥冥豈畏羅。", "秋風下庭葉，乃見貫時柯。"]'),
('54dcfb3e-4134-477e-b1a9-4c66417641c7','寄懷徐行仲','趙蕃','宋','宋诗','song-poetry','','[]','夢想西禪寺，春陰遶夏池。',48,'全唐诗/poet.song.165000.json','["夢想西禪寺，春陰遶夏池。", "投枝語鳥雀，叩檻出魚龜。", "用舍平生學，嬉娛即是詩。", "覓公端不晚，江漲即東之。"]'),
('56d6788a-74ef-4e96-b7ff-59e7d093e585','聞楊謹仲得車輅院又聞其哭妻有寄','趙蕃','宋','宋诗','song-poetry','','[]','得酒不孤酌，有詩仍寄看。',48,'全唐诗/poet.song.165000.json','["得酒不孤酌，有詩仍寄看。", "親舂聞失伴，執戟報除官。", "浩蕩皆鷗鷺，翱翔豈鳳鸞。", "嘗評峽江上，山水似嚴湍。"]'),
('7af7c348-e704-4131-8bb8-effc7b9df0dc','寄明叔','趙蕃','宋','宋诗','song-poetry','','[]','聞道南池上，日來幽事多。',48,'全唐诗/poet.song.165000.json','["聞道南池上，日來幽事多。", "株株摇弱柳，柄柄出擎荷。", "長夏端能好，新詩况可歌。", "無庸問凡楚，一以付無何。"]'),
('0cc49e85-4f58-4c4b-bc2f-9f89294bd457','寄劉伯山','趙蕃','宋','宋诗','song-poetry','','[]','魁梧任嘲劇，短少盖風流。',48,'全唐诗/poet.song.165000.json','["魁梧任嘲劇，短少盖風流。", "邂逅爲頤解，殷勤成刺投。", "遥知江夏閣，不減仲宣樓。", "頗願相從去，湖南兵未休。"]'),
('96125003-5d08-4686-b3e8-16bf336e0ec2','寄王彥博','趙蕃','宋','宋诗','song-poetry','','[]','年來困犇走，事與素心違。',48,'全唐诗/poet.song.165000.json','["年來困犇走，事與素心違。", "歲晏草木肅，天高鴻鴈微。", "故人天外別，尺素眼中稀。", "問我還鄉旆，春風當與歸。"]'),
('d0c7751b-ad5b-4395-a5d6-83d84fe5929d','因曾相士寄韋南雄','趙蕃','宋','宋诗','song-poetry','','[]','窈窕梅花嶺，風流燕寢香。',48,'全唐诗/poet.song.165000.json','["窈窕梅花嶺，風流燕寢香。", "如聞省條教，復道富篇章。", "近作凡幾首，新來無一行。", "因人問無量，併遣驗徵黄。"]'),
('cd386aed-9f26-45a2-b53e-50a53907b469','次韻歐陽伯威因書見寄','趙蕃','宋','宋诗','song-poetry','','[]','病過一春事，不惟嗟索居。',48,'全唐诗/poet.song.165000.json','["病過一春事，不惟嗟索居。", "酒杯疎到手，藥裹每關予。", "曹務寧知馬，悲歌豈爲魚。", "故人能枉問，安否報何如。"]'),
('24c6c6cf-3a5d-480b-93b5-b074937fc36f','撫州初程夜寄孫溫叟甘叔異','趙蕃','宋','宋诗','song-poetry','','[]','水激成悲壯，星稀乍有無。',48,'全唐诗/poet.song.165000.json','["水激成悲壯，星稀乍有無。", "店荒容託宿，酒遠懶能沽。", "冉冉非今日，遑遑媿此途。", "孫甘兩奇逸，蕭颯舊憐吾。"]'),
('ff97fa4c-c46e-40e3-b1f3-8ed2c053dbad','周愚卿同內子遊仰山南嶽後予一日行途中寄之','趙蕃','宋','宋诗','song-poetry','','["\u8861\u5c71"]','溟濛初莫辨，飄灑忽成妍。',48,'全唐诗/poet.song.165000.json','["溟濛初莫辨，飄灑忽成妍。", "地豈三千界，山迷尺五天。", "畫圖寧有此，言句可無傳。", "却恨與周子，行差一日先。"]'),
('b0ca5f2c-a6c5-4462-ab3b-1ac43b80d069','寄胡達孝二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','中庸有胡公，千騎乃安豐。',48,'全唐诗/poet.song.165000.json','["中庸有胡公，千騎乃安豐。", "氣自論詩合，情因敘舊通。", "莫窺鴻鵠志，相望馬牛風。", "邂逅長安使，丁寧覓置筒。"]'),
('b7601a1c-1ae0-4cca-8745-4dbaf08075f7','寄胡達孝二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','問訊安豐守，開藩且半年。',48,'全唐诗/poet.song.165000.json','["問訊安豐守，開藩且半年。", "秋收多少麥，春闢幾何田。", "但使民能足，端知化已宣。", "譽毋求赫赫，腹肯媿便便。"]'),
('1e44b064-850e-4015-996d-a88983311342','用斯遠韻寄趙湖州三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','竄迹窮閻底，求交四海中。',48,'全唐诗/poet.song.165000.json','["竄迹窮閻底，求交四海中。", "爲懷黄閣老，長詠白蘋風。", "遠祿寧堪藉，吾身未適終。", "何山道場麓，政爾屬君公。"]'),
('9b35cda5-5c60-49ee-b5bd-a87e1ecf0528','用斯遠韻寄趙湖州三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','薄暮雨如馳，中宵月半規。',48,'全唐诗/poet.song.165000.json','["薄暮雨如馳，中宵月半規。", "真成憶玄度，不是突西施。", "蟬墮風枝急，蛩鳴露草垂。", "不眠還索句，自笑欲奚爲。"]'),
('0e9594b8-dfdb-488e-9d6d-ded93a70f95e','用斯遠韻寄趙湖州三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','別去雖天外，書行每便中。',48,'全唐诗/poet.song.165000.json','["別去雖天外，書行每便中。", "晝吟宵不斷，夜夢曉還空。", "時用有顯晦，交情無達窮。", "看公與徐孺，寧復計違從。"]'),
('8c322348-b132-4b69-a06e-6d393aadd0e4','寄趙湖州','趙蕃','宋','宋诗','song-poetry','','[]','平生清遠地，幾首往來詩。',48,'全唐诗/poet.song.165000.json','["平生清遠地，幾首往來詩。", "獨負尋山債，長年屬夢思。", "故人今五馬，薄宦乃南夷。", "要寄登臨勝，當來墨妙碑。"]'),
('c2f479c1-2912-4554-a45c-b3da4dcfaf81','寄周畏知','趙蕃','宋','宋诗','song-poetry','','[]','書疏雖能數，飄零可奈何。',48,'全唐诗/poet.song.165000.json','["書疏雖能數，飄零可奈何。", "每懷談緒遠，更益鬢絲多。", "治行今難及，聲名保不磨。", "公寧免騰踏，我乃願婆娑。"]'),
('fb774f1a-da74-4c0b-ba55-9d556c991b08','寄李處州','趙蕃','宋','宋诗','song-poetry','','[]','近別遂累日，逢人空附書。',48,'全唐诗/poet.song.165000.json','["近別遂累日，逢人空附書。", "雖能道所以，未辱報何如。", "千里江山外，一春風雨餘。", "夢成同泛宅，起欲命籃輿。"]'),
('d83b491f-ba4b-4622-af4c-32e6d31dd7ab','寄喻叔奇','趙蕃','宋','宋诗','song-poetry','','[]','雨雪長安日，覊栖獨旅時。',48,'全唐诗/poet.song.165000.json','["雨雪長安日，覊栖獨旅時。", "累觴欣會面，到處益潜悲。", "舊識文章伯，今猶國子師。", "何當一持節，來惠楚人爲。"]'),
('d48c7c59-bf0d-4a25-8ce8-c304de2f28b6','斯遠徐兄携李丈子永去冬江上詩卷來成四十字寄李','趙蕃','宋','宋诗','song-poetry','','[]','建鄴復當塗，征行歲又徂。',48,'全唐诗/poet.song.165000.json','["建鄴復當塗，征行歲又徂。", "青山奠椒桂，白鷺泊菰蒲。", "人物豪三國，文章到兩都。", "因君俾傳誦，使我不枝梧。"]'),
('fc8f2476-7f1e-464c-b272-53f9b47ae1bb','聞曾幼度近况於陳擇之作二詩覓使寄之  其一','趙蕃','宋','宋诗','song-poetry','','[]','自辱緘書報，於今歲有秋。',48,'全唐诗/poet.song.165000.json','["自辱緘書報，於今歲有秋。", "飄流聞客語，消息解人憂。", "薦牘新頻上，詩聲舊得優。", "君歸定蓬閣，我去復炎州。"]'),
('ff4f3c4e-4a0e-4914-880b-2f4eb1ae031c','聞曾幼度近况於陳擇之作二詩覓使寄之  其二','趙蕃','宋','宋诗','song-poetry','','[]','夜醉江天閣，賦詩殊未央。',48,'全唐诗/poet.song.165000.json','["夜醉江天閣，賦詩殊未央。", "自茲悲契闊，誰復慰凄凉。", "有抱何由寫，因詩得寄將。", "丁寧贛江水，莫憚遡流長。"]'),
('63ca5728-93d3-4e95-ab83-fbb871a5c93d','成父弟書來報朱先生過玉山留南山一日且有題名余不及從杖履爲恨輒成鄙句寄斯遠彥章且示成父','趙蕃','宋','宋诗','song-poetry','','[]','聞道朱夫子，南山盡日留。',48,'全唐诗/poet.song.165000.json','["聞道朱夫子，南山盡日留。", "經行還阻見，會合信難謀。", "湛輩我無與，顔徒君好修。", "題名凡幾字，好爲刻巖幽。"]'),
('db3cd20f-3c72-4e83-b0d4-24d3ad9f53ca','寄呂謙益卿三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','多謝臨湘尉，書來併枉詩。',48,'全唐诗/poet.song.165000.json','["多謝臨湘尉，書來併枉詩。", "夜吟忘夕寐，晨誦愈朝饑。", "我亦窮耽此，君仍老嗜茲。", "雖然不相棄，竟爾欲奚爲。"]'),
('bbcb56bc-4b84-4351-b08f-d4690edd70aa','寄呂謙益卿三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','一尉荒山裏，高名四海中。',48,'全唐诗/poet.song.165000.json','["一尉荒山裏，高名四海中。", "初非大夫逐，定自溧陽窮。", "薦士猶王政，招魂已變風。", "懷今更思古，佇立晚江空。"]'),
('d8269bc7-de9e-4f78-9f2d-7e17b5f07e54','寄呂謙益卿三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','誨我肱三折，思君腸九回。',48,'全唐诗/poet.song.165000.json','["誨我肱三折，思君腸九回。", "盡忠真藥石，欲報異瓊瑰。", "交道孰云喪，古風今未頹。", "狂言喙三尺，百罰酒深杯。"]'),
('0d0d8c4c-bebc-4364-b2a9-200db0f20e06','代書寄呂益卿','趙蕃','宋','宋诗','song-poetry','','[]','問訊臨湘尉，冬來定若何。',48,'全唐诗/poet.song.165000.json','["問訊臨湘尉，冬來定若何。", "凶年無盜否，清俸及時麽。", "再見不易得，惠詩空復哦。", "素書慵寫得，此紙字無多。"]'),
('e984a54c-e95c-46e5-b8af-e075ee09b9b8','示嚴君','趙蕃','宋','宋诗','song-poetry','','[]','酒債未忘索，詩狂無用嗔。',48,'全唐诗/poet.song.165000.json','["酒債未忘索，詩狂無用嗔。", "年華猶是臘，風日已如春。", "我鬢蕭蕭白，庭柯濯濯新。", "晚來暄暖劇，還遣振懸鶉。"]'),
('dbf9c71c-ee95-4f7b-9a8e-c9156be397b6','臧正卿示舊所唱酬秋字韻詩軸要季承同用韻贈之','趙蕃','宋','宋诗','song-poetry','','[]','平生人物論，自謂富陽秋。',48,'全唐诗/poet.song.165000.json','["平生人物論，自謂富陽秋。", "滿世多遺恨，相逢足破愁。", "獨憐金錯罄，虛負木瓜投。", "風節他年事，期君折檻游。"]'),
('f8b1d4d9-e65c-4d22-894d-0e4b1fbd495e','夜坐示進之兼懷文叔','趙蕃','宋','宋诗','song-poetry','','[]','貧病人誰數，情親肯見存。',48,'全唐诗/poet.song.165000.json','["貧病人誰數，情親肯見存。", "掩窗同此夜，撥火共殘溫。", "未暇飯飽喫，且從文細論。", "平生松谷老，同姓與君敦。"]'),
('72b81331-d0f1-47b6-b321-64ce86864d02','用韻示成父','趙蕃','宋','宋诗','song-poetry','','[]','林動風微掃，庭空月正方。',48,'全唐诗/poet.song.165000.json','["林動風微掃，庭空月正方。", "不知晝已短，但覺夜初長。", "了了游乖舊，駸駸老至將。", "街頭賣紫角，甕裏灑鵝黄。"]'),
('96519ae4-549b-4566-9b28-7e1a013f3d29','示成父','趙蕃','宋','宋诗','song-poetry','','[]','雨重冬裘薄，泥深古道賒。',48,'全唐诗/poet.song.165000.json','["雨重冬裘薄，泥深古道賒。", "東西但烟嶂，高下絕風花。", "斲句病肝腎，食寒愁齒牙。", "赴期元不後，分路各從家。"]'),
('8f1b60e6-7ecb-4ffc-9463-03b236264ea4','同子肅過玉汝飲題玉汝壁二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','躑躅來千里，崎嶇爲一饑。',48,'全唐诗/poet.song.165000.json','["躑躅來千里，崎嶇爲一饑。", "客情方慘慘，雪意又垂垂。", "萬事豈無命，百窮寧坐詩。", "前賢有如此，而汝欲何爲。"]'),
('7acc476d-1e3b-43aa-833e-1d416d1d6adf','同子肅過玉汝飲題玉汝壁二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','晚日雖云短，故情能爾長。',48,'全唐诗/poet.song.165000.json','["晚日雖云短，故情能爾長。", "杯行要陶寫，賦就復凄凉。", "此別會不免，有懷寧遽忘。", "明當視清鏡，應已變蒼蒼。"]'),
('d405f3bf-718a-426f-9620-de12202ab339','雨中簡章令','趙蕃','宋','宋诗','song-poetry','','[]','夜雨仍朝雨，知時復後時。',48,'全唐诗/poet.song.165000.json','["夜雨仍朝雨，知時復後時。", "禾囷愆黍稌，麥地及耘耔。", "屢起瞻行旆，頻成閲贈詩。", "渠方謹期會，君自念疲羸。"]'),
('a1b47abf-08f7-461f-b96f-c6b57708bac5','晚雨後虹蜺並見','趙蕃','宋','宋诗','song-poetry','','[]','薄雷收淡雨，雌蜺映雄虹。',48,'全唐诗/poet.song.165000.json','["薄雷收淡雨，雌蜺映雄虹。", "雲擁奇峰出，霞飛散綺紅。", "渠無畫手妙，我久作詩工。", "汎汎身隨梗，蕭蕭鬢似蓬。"]'),
('fc0ff5ea-efc0-4a17-8130-2c3f341fddca','早醉','趙蕃','宋','宋诗','song-poetry','','[]','晨起倦烏巾，還傾老瓦盆。',48,'全唐诗/poet.song.165000.json','["晨起倦烏巾，還傾老瓦盆。", "自知中了了，人謂日昏昏。", "迤邐谿山別，披紛鴈鶩喧。", "春風得亡頼，幽趣與誰論。"]'),
('262f7571-ecd2-488e-8894-462697737992','晚行','趙蕃','宋','宋诗','song-poetry','','[]','溪上晚來雨，江西東泝船。',48,'全唐诗/poet.song.165000.json','["溪上晚來雨，江西東泝船。", "波停鏡平墜，霞散綺相鮮。", "老火滋煩濁，初凉灑靜便。", "題詩差落耳，把酒又茫然。"]'),
('cea85b68-41cb-4d1a-8e60-95f5619d3e7b','驟寒二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','一晴疑尚暑，一雨頓能寒。',48,'全唐诗/poet.song.165000.json','["一晴疑尚暑，一雨頓能寒。", "氣候從茲變，病軀那得安。", "頻聞風淅淅，不見日團團。", "附火貪新燎，添衣怯带寬。"]'),
('aeb1b1c9-5e18-4bec-bea9-4de191dbb320','驟寒二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','日薄林園靜，天寒鳥雀微。',48,'全唐诗/poet.song.165000.json','["日薄林園靜，天寒鳥雀微。", "無人行古徑，有客滯荆扉。", "疾病淹時久，新朋枉問稀。", "漸諳風俗異，還覺歲年非。"]'),
('65a75073-58b2-4a27-8e28-9542c15cbba2','黄昏驟寒','趙蕃','宋','宋诗','song-poetry','','[]','過午風猶怒，及昏寒驟增。',48,'全唐诗/poet.song.165000.json','["過午風猶怒，及昏寒驟增。", "衣皆袷無絮，被只楮非繒。", "所賦端如此，誰令病不勝。", "更憐餘習在，挾冊自篝燈。"]'),
('ed491d4a-4b6d-4c04-b235-69d2d9b25786','夜坐觀書作','趙蕃','宋','宋诗','song-poetry','','[]','久矣疎黄卷，欣然對短檠。',48,'全唐诗/poet.song.165000.json','["久矣疎黄卷，欣然對短檠。", "燈寒度窗影，雨驟落簷聲。", "伏枕身雖憊，觀書眼尚明。", "带經真有道，發冢復何情。"]'),
('ee347dc8-7316-4f53-b12a-2374923d361d','枕上  其一','趙蕃','宋','宋诗','song-poetry','','[]','鼠上書檠暗，巢驚甕牖明。',48,'全唐诗/poet.song.165000.json','["鼠上書檠暗，巢驚甕牖明。", "不眠知夜久，欲起怕寒生。", "城與江山近，秋添鼓角清。", "經營纔五字，展轉欲殘更。"]'),
('368ef75b-229f-46d5-ad02-2d3de0dab804','枕上  其二','趙蕃','宋','宋诗','song-poetry','','[]','風雨雜荒更，晨雞不暇鳴。',48,'全唐诗/poet.song.165000.json','["風雨雜荒更，晨雞不暇鳴。", "客程難去住，秋感易凄清。", "强說騷爲僕，那知錢是兄。", "長貧自吾事，未用悔平生。"]'),
('98cda2e6-5c65-4978-a3de-6e3d1e561403','乞曉','趙蕃','宋','宋诗','song-poetry','','[]','乞曉占雲物，過東還過西。',48,'全唐诗/poet.song.165000.json','["乞曉占雲物，過東還過西。", "已因月仰瓦，真驗水平溪。", "齊楚自得失，短長從鶴鷖。", "誰能效巢穴，聊得寄詩題。"]'),
('5375368d-384f-4f05-aac7-e9353e1cd936','十五夜玩月有懷','趙蕃','宋','宋诗','song-poetry','','[]','四海中秋月，三衢上水船。',48,'全唐诗/poet.song.165000.json','["四海中秋月，三衢上水船。", "棲遲猶故我，飄泊記今年。", "烏有空成句，無何不具錢。", "還家知不遠，飛去苦無緣。"]'),
('96648258-9c81-48e3-83fb-951dc789c1b1','自吉水乘月放舟至玄潭','趙蕃','宋','宋诗','song-poetry','','[]','木葉未盡脫，水光真接天。',48,'全唐诗/poet.song.165000.json','["木葉未盡脫，水光真接天。", "蒼然江上石，兀爾渡頭船。", "酒有三杯飽，詩無萬斛泉。", "冥冥鴻鵠舉，渺渺鷺鷗眠。"]'),
('c7941603-fac4-4da4-a239-22efcee044cc','月夜','趙蕃','宋','宋诗','song-poetry','','[]','振厲山風作，咆哮澗水喧。',48,'全唐诗/poet.song.165000.json','["振厲山風作，咆哮澗水喧。", "不堪蛙取閙，更奈鴨能言。", "月色雖云好，雲浮竟自繁。", "白頭清不寐，止酒罷芳樽。"]'),
('d478b1bc-4727-4971-8b9f-83fa18fbeffa','餘干月夜','趙蕃','宋','宋诗','song-poetry','','[]','風月隨地有，溪山天下稀。',48,'全唐诗/poet.song.165000.json','["風月隨地有，溪山天下稀。", "臨流醒客寐，靜夜覺漁歸。", "浥浥露侵鬢，飛飛螢點衣。", "鷺鷗棲亦穩，知我故忘機。"]'),
('c2cc9be4-fe16-47f6-8fb7-7c30afdde756','晨起示聖仙寮主','趙蕃','宋','宋诗','song-poetry','','[]','薄酒亦得醉，熟眠無所聞。',48,'全唐诗/poet.song.165000.json','["薄酒亦得醉，熟眠無所聞。", "林園夜飄雨，窗戶曉封雲。", "米藉鄰翁易，衣尋宿火薰。", "爲官君笑我，樂道我輸君。"]'),
('a1c949dd-131b-456d-8c3d-a590853296b3','和祖上人見貽','趙蕃','宋','宋诗','song-poetry','','[]','久客黄金盡，思歸白髮添。',48,'全唐诗/poet.song.165000.json','["久客黄金盡，思歸白髮添。", "春泥妨驛路，細雨泊僧簷。", "驟喜詩情浹，還增酒律嚴。", "雲山會終往，瓶錫豈長淹。"]'),
('b2e32005-2b6a-4105-8640-7dcf63dd4267','呈慧力然老','趙蕃','宋','宋诗','song-poetry','','[]','慧力知名寺，混融開士英。',48,'全唐诗/poet.song.165000.json','["慧力知名寺，混融開士英。", "宗乘真繼祖，翰墨亦兼名。", "更用終何得，悠然聽此生。", "懷哉躬井碓，永絕世塵攖。"]'),
('3ce9a187-ca50-4059-8264-3dc1d0217c53','比因和首座詩有故欲撩公嬾是真之句名其室曰嬾真知客一窗對青山尤可愛名其軒曰遥碧屬王君進之書榜爲之賦詩二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','少日經禪暇，猶餘文字嬉。',48,'全唐诗/poet.song.165000.json','["少日經禪暇，猶餘文字嬉。", "老來無復事，日用亦奚爲。", "衲被忘宵度，團蒲失晝移。", "謂公真是嬾，如我不其癡。"]'),
('91664fd7-8166-49da-93c9-42073ace4c45','比因和首座詩有故欲撩公嬾是真之句名其室曰嬾真知客一窗對青山尤可愛名其軒曰遥碧屬王君進之書榜爲之賦詩二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','窗戶潔仍間，峯巒列以攢。',48,'全唐诗/poet.song.165000.json','["窗戶潔仍間，峯巒列以攢。", "舊因行脚見，今得坐禪看。", "明晦陰晴變，青黄草木觀。", "本來元不動，是可學心安。"]'),
('c80ba053-e7f6-41c6-ad52-a3a58b18201d','漁父','趙蕃','宋','宋诗','song-poetry','','[]','自得江湖樂，信無朝市求。',48,'全唐诗/poet.song.165000.json','["自得江湖樂，信無朝市求。", "扁舟載妻子，沒齒是春秋。", "見客如成愕，問魚多掉頭。", "嚴陵疑可亞，范蠡豈其流。"]'),
('025f7316-022b-4bb3-a901-d29943776aa1','招謝丈簽判出郊','趙蕃','宋','宋诗','song-poetry','','[]','桃李競芳春，晨粧故斬新。',48,'全唐诗/poet.song.165000.json','["桃李競芳春，晨粧故斬新。", "周遭遍晴野，絡繹動遊人。", "閉戶端無事，命車當及辰。", "澄流带修竹，足以奉清真。"]'),
('52ed4be4-ff9a-46f5-85d2-1b934cd847be','同諸友送潘文叔出郊','趙蕃','宋','宋诗','song-poetry','','[]','數月卧城郭，茲晨歷郊原。',48,'全唐诗/poet.song.165000.json','["數月卧城郭，茲晨歷郊原。", "林鶑語聲近，陂鷺背影翻。", "稻栽已遍畝，桑採無剩園。", "因行一欣爾，送友重惘然。"]'),
('038c7e04-f233-4698-bf9d-00acb8679069','十六日出迓客','趙蕃','宋','宋诗','song-poetry','','[]','逢迎非我事，且逐衆人行。',48,'全唐诗/poet.song.165000.json','["逢迎非我事，且逐衆人行。", "粗識郊原趣，因茲詩句成。", "黄華菜誰主，自喚鳥何名。", "忽憶來時路，還思去日程。"]'),
('004ed1b0-98a5-45c1-a2b4-c1385a4a9e03','分宜示沈弟','趙蕃','宋','宋诗','song-poetry','','[]','水後雖頹圮，江邊不寂寥。',48,'全唐诗/poet.song.165000.json','["水後雖頹圮，江邊不寂寥。", "囂聲收市井，落景見漁樵。", "喜我扁舟泊，勞君半道要。", "他鄉惟表弟，茲語驗今宵。"]'),
('acd4706d-c4b2-4957-a4a4-a14783ad1ef0','次韻師契早過東園','趙蕃','宋','宋诗','song-poetry','','[]','舊說東西圃，新知上下池。',48,'全唐诗/poet.song.165000.json','["舊說東西圃，新知上下池。", "山亭猶有記，水館獨無碑。", "疏鑿由今守，登臨要子詩。", "倦游吾老矣，况復思多遲。"]'),
('d2964267-c7aa-4fd7-a97b-171e9709b910','湖州親舊  其一','趙蕃','宋','宋诗','song-poetry','','[]','去住兩無由，終成上客舟。',48,'全唐诗/poet.song.165000.json','["去住兩無由，終成上客舟。", "香如添酒病，雨亦带離愁。", "兩岸青青柳，空江點點鷗。", "總堪添鬢白，不必問春秋。"]'),
('8d5e1fc8-ed3e-4811-9458-fa191e3ee305','湖州親舊  其二','趙蕃','宋','宋诗','song-poetry','','[]','搔首對青波，蕭蕭半欲皤。',48,'全唐诗/poet.song.165000.json','["搔首對青波，蕭蕭半欲皤。", "不關年運迫，政爲別離多。", "落魄空長恨，飄零謾短歌。", "殘春與倦客，已矣更如何。"]'),
('d1e411e9-4d6c-4438-ad6a-178e7e1a3908','口占示成父','趙蕃','宋','宋诗','song-poetry','','[]','雨暴落何方，空成掣電光。',48,'全唐诗/poet.song.165000.json','["雨暴落何方，空成掣電光。", "凄凉風陡變，黯黮月微妨。", "就取征衣蓋，共談三徑荒。", "蟬連幾徹曉，有恨故悢悢。"]'),
('91de0fad-0800-48ae-ac53-5937728f07da','早行示同舟','趙蕃','宋','宋诗','song-poetry','','[]','了了晴山見，紛紛宿霧空。',48,'全唐诗/poet.song.165000.json','["了了晴山見，紛紛宿霧空。", "樵歸婦腰斧，漁罷叟收筒。", "但取登臨適，何須吟嘯工。", "平生釣臺路，明日與君同。"]'),
('95abbc53-8ccc-408b-bdd2-54d52b1b58cd','早起登覽有懷山居','趙蕃','宋','宋诗','song-poetry','','[]','日出早煙消，舟行不待招。',48,'全唐诗/poet.song.165000.json','["日出早煙消，舟行不待招。", "乍明村市塢，初露遠山椒。", "勝處宜規隠，浮生只浪飄。", "章泉在何許，遶塹碧蕭蕭。"]'),
('e40f4f97-e5be-4216-9c10-766108483068','和折子明丈閑居雜興十首  其一','趙蕃','宋','宋诗','song-poetry','','[]','維南有衡嶽，一掃衆山空。',48,'全唐诗/poet.song.165000.json','["維南有衡嶽，一掃衆山空。", "天既柄斯假，祭應儀比公。", "穹林行莫盡，傑句古來供。", "歎息緇黄輩，昏燈及曉鐘。"]'),
('06cfb60f-194c-4748-b830-52d1b074b496','和折子明丈閑居雜興十首  其二','趙蕃','宋','宋诗','song-poetry','','[]','江清山照影，山浄水爲容。',48,'全唐诗/poet.song.165000.json','["江清山照影，山浄水爲容。", "縱復俯仍仰，難分邊與中。", "雲興繪後素，雨合聽思聰。", "安得漁舟去，於斯作釣翁。"]'),
('d18c1709-b4cf-4174-be0f-b2d8d06f6129','和折子明丈閑居雜興十首  其三','趙蕃','宋','宋诗','song-poetry','','[]','賞識元非易，登臨政爾難。',48,'全唐诗/poet.song.165000.json','["賞識元非易，登臨政爾難。", "要須窮應接，寧可肆譏彈。", "勝踐千年近，高風六月寒。", "由來炯水玉，固愈耀朱丹。"]'),
('922ab75d-0b39-428c-a175-01007078d180','和折子明丈閑居雜興十首  其四','趙蕃','宋','宋诗','song-poetry','','[]','水匯終趨海，葵傾必向陽。',48,'全唐诗/poet.song.165000.json','["水匯終趨海，葵傾必向陽。", "欲行疑或使，將下盍先翔。", "聽爾玄嘲白，從渠本校黄。", "生平志濠濮，老去客沅湘。"]'),
('dd5d9728-c210-4c09-85f2-a75ea8c88604','和折子明丈閑居雜興十首  其五','趙蕃','宋','宋诗','song-poetry','','[]','詩有江西派，首書江夏黄。',48,'全唐诗/poet.song.165000.json','["詩有江西派，首書江夏黄。", "精神如有得，形似直堪忘。", "拱把至合抱，江流由濫觴。", "屹然成巨室，勇若泛飛艎。"]'),
('6d6e160d-4534-4449-b125-f78dfdd004ed','和折子明丈閑居雜興十首  其六','趙蕃','宋','宋诗','song-poetry','','[]','萬里江山助，千年蘇李師。',48,'全唐诗/poet.song.165000.json','["萬里江山助，千年蘇李師。", "紛紛多假力，落落要真知。", "巧手寧無僞，徐行不厭遲。", "文章自公器，造物匪人私。"]'),
('130fa1fc-1b66-4798-88dc-26f05914f666','和折子明丈閑居雜興十首  其七','趙蕃','宋','宋诗','song-poetry','','[]','未話田園薄，唯關道路長。',48,'全唐诗/poet.song.165000.json','["未話田園薄，唯關道路長。", "春風又寒食，多病祇殊方。", "緬想迎門問，深思暴橐香。", "無勞謝猿鶴，好爲約求羊。"]'),
('37ba4ce2-4df5-400b-99d7-4eb3791d6c53','和折子明丈閑居雜興十首  其八','趙蕃','宋','宋诗','song-poetry','','[]','抄寫猶前日，吟哦遂隔年。',48,'全唐诗/poet.song.165000.json','["抄寫猶前日，吟哦遂隔年。", "真成墜眢井，未易及深泉。", "曷日仙能至，何時彈比圓。", "自非深致力，寧識貴吾賢。"]'),
('08c0d98b-6dea-4014-aca4-a0dcfcfcd905','和折子明丈閑居雜興十首  其九','趙蕃','宋','宋诗','song-poetry','','[]','徑草餘幽色，盆蘭有靜芳。',48,'全唐诗/poet.song.165000.json','["徑草餘幽色，盆蘭有靜芳。", "取窮應有在，雖病亦無傷。", "暫得閉門坐，已勝趨道傍。", "鴻斯遠繒繳，木豈願青黄。"]'),
('d0241ce3-b504-4857-8f70-75b18fc190b3','和折子明丈閑居雜興十首  其一○','趙蕃','宋','宋诗','song-poetry','','[]','人說居閑久，園今數畝開。',48,'全唐诗/poet.song.165000.json','["人說居閑久，園今數畝開。", "荒榛除舊舍，規畫見新材。", "鬰鬰宜深芘，堂堂豈易摧。", "遐思挹湘水，高興擬裴臺。"]'),
('c508db04-c746-4514-b98d-c844580cc083','呈閭丘四舅二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昨都城見，於今歲月長。',48,'全唐诗/poet.song.165000.json','["憶昨都城見，於今歲月長。", "中間各憂患，重對兩悲凉。", "課最舅材顯，詩窮甥鬢蒼。", "相逢又相別，客路况冰霜。"]'),
('8b6e3b4f-ec46-4f07-8871-cf0f0a124a51','呈閭丘四舅二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','不識高安縣，飽聞明恕堂。',48,'全唐诗/poet.song.165000.json','["不識高安縣，飽聞明恕堂。", "毋卑百里小，未覺四年長。", "議論兼秦漢，規模類越杭。", "廟堂方急此，已試乃爲良。"]'),
('84471b52-53ef-4760-8d4f-dbe274021918','晚晴','趙蕃','宋','宋诗','song-poetry','','[]','溪雨無常度，陰晴日幾回。',48,'全唐诗/poet.song.165000.json','["溪雨無常度，陰晴日幾回。", "山容朝政合，水面晚仍開。", "乍覺巉巖盡，又看平遠來。", "高人欠摩詰，空爲襪留材。"]'),
('6a69cdfd-ea6a-4291-a048-c2e3bab1b54b','詠晴  其一','趙蕃','宋','宋诗','song-poetry','','[]','冥冥十日雨，不見海棠梨。',48,'全唐诗/poet.song.165000.json','["冥冥十日雨，不見海棠梨。", "霽色晨初上，禽聲樂可知。", "春衣猶故褐，薄飯祇朝虀。", "自信端如此，流行任所之。"]'),
('2a4e2fd6-a256-4c44-9bd7-6a1e2d7153ec','詠晴  其二','趙蕃','宋','宋诗','song-poetry','','[]','敗屋兩三間，隨僧且住山。',48,'全唐诗/poet.song.165000.json','["敗屋兩三間，隨僧且住山。", "詩無一朝廢，官有十年閑。", "日上花明野，雞啼門掩關。", "春風從草草，老態已斑斑。"]'),
('9dff4cb7-7f56-4e5d-ba91-ebdfb8806135','雪晴','趙蕃','宋','宋诗','song-poetry','','[]','啟戶猶飛雪，披衣忽報晴。',48,'全唐诗/poet.song.165000.json','["啟戶猶飛雪，披衣忽報晴。", "慵爲踞爐坐，喜作出門行。", "草凍袍爭色，梅殘玉墮英。", "未能憂旱苦，聊復快詩情。"]'),
('6cc092e7-0b9b-482f-83a2-7c9b2b39a60a','秋聲','趙蕃','宋','宋诗','song-poetry','','[]','何處忽秋聲，千崖萬壑并。',48,'全唐诗/poet.song.165000.json','["何處忽秋聲，千崖萬壑并。", "不知繇雨故，直覺太清生。", "絺綌且重著，褐裘須漸營。", "晚禾資秀實，尚有暖而晴。"]'),
('294140ce-6cc2-478e-83ce-0757291fde92','次韻簽判丈因旱而作及喜雨二詩  其一','趙蕃','宋','宋诗','song-poetry','','[]','稍愆梅熟雨，似作旱時風。',48,'全唐诗/poet.song.165000.json','["稍愆梅熟雨，似作旱時風。", "此柄知誰宰，皇天不病農。", "桑麻初告畢，倉廩舊猶豐。", "莫起焦熬歎，當期滲漉通。"]'),
('beb047e7-fa86-45f1-86af-0abfbb7b6892','次韻簽判丈因旱而作及喜雨二詩  其二','趙蕃','宋','宋诗','song-poetry','','[]','在家乃慮國，此事古人風。',48,'全唐诗/poet.song.165000.json','["在家乃慮國，此事古人風。", "蚤作欣聞雨，歡謠欲助農。", "不須詢父老，斷可驗凶豐。", "藥裹從茲屏，詩筒要數通。"]'),
('78497db0-3f41-4da3-afe2-7c5e40a03e20','雨餘','趙蕃','宋','宋诗','song-poetry','','[]','雨餘還返照，牆面亦高林。',48,'全唐诗/poet.song.165000.json','["雨餘還返照，牆面亦高林。", "獨坐殘書卷，支頤谷鳥吟。", "百年今半過，三逕豈遐心。", "日莫重蕭瑟，悲歌不自任。"]'),
('3c3e80a0-3ae6-4ee4-8945-550f3629d09b','大雨連晝夜不止','趙蕃','宋','宋诗','song-poetry','','[]','天漏誰能補，河傾勢未平。',48,'全唐诗/poet.song.165000.json','["天漏誰能補，河傾勢未平。", "踞床如露處，曳履學泥行。", "朽柱芝菌出，斷溝蝌蚪生。", "南公安已慣，北客見猶驚。"]'),
('5666e201-c8e5-419e-b541-f6a1ae1e0f71','連雨','趙蕃','宋','宋诗','song-poetry','','[]','夜窗連曉枕，城郭與山林。',48,'全唐诗/poet.song.165000.json','["夜窗連曉枕，城郭與山林。", "旱苦七八月，雨欣三日霖。", "殊勝建武穀，更愈櫟陽金。", "斗食端可直，胡爲久滯淫。"]'),
('a001ad86-03ce-40f7-b23a-d53bc84a3c90','連雨書事','趙蕃','宋','宋诗','song-poetry','','[]','麥熟蠶將老，晴須雨不宜。',48,'全唐诗/poet.song.165000.json','["麥熟蠶將老，晴須雨不宜。", "頻年荒已甚，一飽此爲期。", "陛下故勤理，爾民無怨咨。", "磨鎌亦裝簇，晴日會當披。"]'),
('2088fa42-0c29-4709-bd00-9e9658070cb8','連雨','趙蕃','宋','宋诗','song-poetry','','[]','窗外簷絕雨，檻前山返雲。',48,'全唐诗/poet.song.165000.json','["窗外簷絕雨，檻前山返雲。", "細聽還摵摵，觸眼又紛紛。", "旱昔晨昏望，淫今晝夜聞。", "平生憂國願，敢廢野人芹。"]'),
('ba521a3f-1707-49b1-8289-5d7ef5063487','次韻張王臣既晴復雨欲去尚留見示且以識別二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','逾月能連雨，今晨少散陰。',48,'全唐诗/poet.song.165000.json','["逾月能連雨，今晨少散陰。", "病寬遊子念，愁豁老農心。", "始慮春成旱，那知夏苦淫。", "舉頭問白日，恇怯一何深。"]'),
('1b76607a-06cb-4792-bbe2-c411769864f4','次韻張王臣既晴復雨欲去尚留見示且以識別二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我住難期夏，君歸豈待秋。',48,'全唐诗/poet.song.165000.json','["我住難期夏，君歸豈待秋。", "投章同縞带，共敝愈輕裘。", "浩浩羣屬玉，陰陰黄栗留。", "敘行如有寄，伺處覓孤舟。"]'),
('a2834c8d-8cf5-40eb-91d1-15ee08954082','二月十日雨','趙蕃','宋','宋诗','song-poetry','','[]','喜雪仍喜雨，相須旬日期。',48,'全唐诗/poet.song.165000.json','["喜雪仍喜雨，相須旬日期。", "天民終自卹，歲事可前知。", "起我泛舟役，思渠荷笠詩。", "嗔人問米價，王掾果真癡。"]'),
('bc559bda-a07b-404b-99ac-a1c493576b12','雨中不出呈斯遠兼示成父四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','燠甚宜爲雨，晴來又復陰。',48,'全唐诗/poet.song.165000.json','["燠甚宜爲雨，晴來又復陰。", "霜風吹不變，雪霰已相侵。", "寒且依鑪密，泥防著屐深。", "未能從子去，何暇復梅尋。"]'),
('3a36d92c-df21-40a9-a773-74d83431a456','雨中不出呈斯遠兼示成父四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','歲事今無幾，來歸畧未安。',48,'全唐诗/poet.song.165000.json','["歲事今無幾，來歸畧未安。", "若爲佳抱發，頼有好詩看。", "賸欲江村訪，却遭天氣寒。", "雪猶思剡曲，雨亦過蘇端。"]'),
('f654f43e-c0b7-44d7-a5fb-e8fa8b5a1140','雨中不出呈斯遠兼示成父四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','湖外頻年客，江東邇日歸。',48,'全唐诗/poet.song.165000.json','["湖外頻年客，江東邇日歸。", "欲知年事迫，看取鬢毛非。", "寄意雖梅柳，關心在蕨薇。", "令余倒芒屨，須子叩柴扉。"]'),
('596f1793-fb57-410e-8169-ac98da09f108','雨中不出呈斯遠兼示成父四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','兄髮久已白，弟顔那得紅。',48,'全唐诗/poet.song.165000.json','["兄髮久已白，弟顔那得紅。", "從今喜朝夕，不復恨西東。", "耕稼真吾事，詩書是祖風。", "扶犂有餘暇，把卷不妨同。"]'),
('9ff61e9d-55bd-49a7-b567-d5b9082b358a','雨望偶題','趙蕃','宋','宋诗','song-poetry','','[]','漠漠青山雨，霏霏白鷺煙。',48,'全唐诗/poet.song.165000.json','["漠漠青山雨，霏霏白鷺煙。", "詩材來遠近，畫本極中邊。", "流落雖天外，登臨頼目前。", "浮生纔幾日，此地欲三年。"]'),
('b777eb36-628e-46fc-a52b-49908407bae5','雨中四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','積此簷間雨，驟茲山下谿。',48,'全唐诗/poet.song.165000.json','["積此簷間雨，驟茲山下谿。", "真成亂昏晝，何止礙輪蹄。", "雲變看蒼狗，泥深聽竹雞。", "不能同憒憒，政爾合栖栖。"]'),
('dfeb5888-a421-4614-8338-47736f541278','雨中四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','古屋先知雨，空林易得風。',48,'全唐诗/poet.song.165000.json','["古屋先知雨，空林易得風。", "階除滋綠草，門巷擁丹楓。", "衣褐從茲迫，稻粱安得豐。", "病來方止酒，愁絕若爲攻。"]'),
('c3e2d2ad-3755-477a-8a1a-ca184bcf16d8','雨中四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','瀏瀏簷雨暮，蕭蕭窗竹秋。',48,'全唐诗/poet.song.165000.json','["瀏瀏簷雨暮，蕭蕭窗竹秋。", "蚊雷宵罷響，螢火暗停流。", "政爾具絺綌，又當營褐裘。", "桑麻豈無地，卒歲負悠悠。"]'),
('89b1a686-9b03-4117-815c-82c8362084b2','雨中四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','稍稍風頭變，侵侵雨脚來。',48,'全唐诗/poet.song.165000.json','["稍稍風頭變，侵侵雨脚來。", "峯巒忽成暗，雲霧亦旋開。", "謾易炎凉候，無矜狡獪才。", "天高獨鳥度，林合亂蟬哀。"]'),
('87c5389a-271a-41c0-a0c1-b3167ba44187','八日雨是日期成父來已而不至','趙蕃','宋','宋诗','song-poetry','','[]','一雨毋嫌驟，炎蒸得解圍。',48,'全唐诗/poet.song.165000.json','["一雨毋嫌驟，炎蒸得解圍。", "桃笙疎不御，蕉萐頓忘揮。", "月暗螢偷照，風清蟲趣機。", "所思期不至，還是掩荆扉。"]'),
('63a3d86a-8040-4230-b441-b9fb5f287883','雨後','趙蕃','宋','宋诗','song-poetry','','[]','前朝呼蜥蜴，今雨跳蝦蟇。',48,'全唐诗/poet.song.165000.json','["前朝呼蜥蜴，今雨跳蝦蟇。", "聽罷僧鐘擊，停聞廟鼓撾。", "長饑逭遊子，樂歲慰田家。", "未得江東信，頻看天外鴉。"]'),
('5b6abebc-70a6-4481-9686-dfce3e8f3da7','昨日過縣齋莫令方以闕雨爲言薄晚雨作山行書呈','趙蕃','宋','宋诗','song-poetry','','[]','草樹高低濕，陂塘曲折通。',48,'全唐诗/poet.song.165000.json','["草樹高低濕，陂塘曲折通。", "鳩鳴朝未已，雨氣曉猶濛。", "念發堂皇上，雲生山谷中。", "滯留公勿厭，更享一年豐。"]'),
('cdda58e1-3084-4906-a413-157336e1328a','明日雨不止風加甚','趙蕃','宋','宋诗','song-poetry','','[]','大雨曉未止，疾風朝更顛。',48,'全唐诗/poet.song.165000.json','["大雨曉未止，疾風朝更顛。", "茅飛疎我屋，禾偃病民田。", "未可專時戾，多繇得地偏。", "雖然豈無念，衣薄尚無綿。"]'),
('f2937d82-c8ca-426d-bb70-68a8c4fb0cf6','六月十三日四更登舟縣岸遲明抵薉步宿雨猶濕昨夕近郭風而不雨不知此間蓋滂沱也','趙蕃','宋','宋诗','song-poetry','','[]','月落艣咿啞，曉登江上家。',48,'全唐诗/poet.song.165000.json','["月落艣咿啞，曉登江上家。", "衝田多偃稻，直岸有頹沙。", "始悟雨如許，更欣晴亦佳。", "林中尚餘滴，不管墊烏紗。"]'),
('8a2dffd3-d91c-4b8c-8e5a-75cca12af30f','八日夜雨九日不止','趙蕃','宋','宋诗','song-poetry','','[]','中夜忽聞雨，遲明殊未收。',48,'全唐诗/poet.song.165000.json','["中夜忽聞雨，遲明殊未收。", "都緣數日熱，變此一庭秋。", "不但梅當熟，從來夏或裘。", "可憐方止酒，何日畔牢愁。"]'),
('72106acd-bb7d-4666-be76-c8c0b1441b18','雨脚','趙蕃','宋','宋诗','song-poetry','','[]','雨脚纔能駐，風頭倏又高。',48,'全唐诗/poet.song.165000.json','["雨脚纔能駐，風頭倏又高。", "未成曾點服，猶衣仲由袍。", "斗食塵埃媿，束書燈火勞。", "丁丁幾樵斧，汎汎一漁舠。"]'),
('c37b97b2-2457-4724-9770-e22c38324fb7','月方上雨忽作','趙蕃','宋','宋诗','song-poetry','','[]','作底浮雲合，從何細雨零。',48,'全唐诗/poet.song.165000.json','["作底浮雲合，從何細雨零。", "庭中方照影，葉上已傳聽。", "耿耿深翻鵲，飄飄暗墮螢。", "倦身拋曲几，高枕對疎櫺。"]'),
('f1037560-4873-4586-85fc-aa07d0d39b60','雨作','趙蕃','宋','宋诗','song-poetry','','[]','晚泊魚蝦聚，蚤行葭葦叢。',48,'全唐诗/poet.song.165000.json','["晚泊魚蝦聚，蚤行葭葦叢。", "紛紛腥落日，裊裊亂長空。", "風既滯游子，雨仍愁社公。", "真成才欲盡，有句不能工。"]'),
('be4d4c6d-9461-4a51-8452-f70f57ca65f2','寓舍遭雨漏甚','趙蕃','宋','宋诗','song-poetry','','[]','無計補天漏，寧關以瓦爲。',48,'全唐诗/poet.song.165000.json','["無計補天漏，寧關以瓦爲。", "晝居衣數燎，宵卧枕頻移。", "憒悶長憑酒，窮愁更有詩。", "何須僂句問，可向穴居知。"]'),
('75f5adc9-6e92-41dc-bfaf-607b6a2aa4fd','舟中雨作','趙蕃','宋','宋诗','song-poetry','','[]','旱而逢小雨，月亦當季秋。',48,'全唐诗/poet.song.165000.json','["旱而逢小雨，月亦當季秋。", "便覺重陽近，還成一舸遊。", "關余荒徑菊，媿爾沒波鷗。", "詩就雲如卷，推篷得縱求。"]'),
('77ea8d43-a6c5-4d09-8cd4-705ce7fb1bd5','連雨有作','趙蕃','宋','宋诗','song-poetry','','[]','往晴憂小旱，今雨慰深望。',48,'全唐诗/poet.song.165000.json','["往晴憂小旱，今雨慰深望。", "細聽林園響，如聞粳稻香。", "客來無褦襶，興可傲羲皇。", "恨我瘍居體，孤渠醉作鄉。"]'),
('6a10a9de-5d56-4f4c-9499-f10eec2a625e','八日五日雨','趙蕃','宋','宋诗','song-poetry','','[]','小雨新凉進，遥山翠靄分。',48,'全唐诗/poet.song.165000.json','["小雨新凉進，遥山翠靄分。", "稻粱先告病，粟麥晚收勳。", "助爾農人喜，嗟余課子勤。", "跨馿窮有相，琢句老無聞。"]'),
('4d3259b0-752f-453d-b10c-512521f42da5','八月十二夜至十六夜皆無月賦詩三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','月向中秋俟，陰從一夕愆。',48,'全唐诗/poet.song.165000.json','["月向中秋俟，陰從一夕愆。", "望中孤老眼，暗裏聳吟肩。", "燈婢深留照，桃笙冷廢眠。", "思兮在何許，有夢隔山川。"]'),
('ffdf4f6e-05c2-4002-9cf3-d0047ac96376','八月十二夜至十六夜皆無月賦詩三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','雨後凉雖在，秋中月遂孤。',48,'全唐诗/poet.song.165000.json','["雨後凉雖在，秋中月遂孤。", "未妨疎狡兔，端恐失遺珠。", "屢起瞻雲漢，還成候挈壺。", "清羸祇益苦，庭樹有棲烏。"]'),
('92ce1d06-c98d-4ba1-bac3-c08c5642c83e','八月十二夜至十六夜皆無月賦詩三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','已失連宵望，猶餘此夕謀。',48,'全唐诗/poet.song.165000.json','["已失連宵望，猶餘此夕謀。", "疎明時遞見，暗淡幸空休。", "無復丹梯意，居然四壁幽。", "有懷千萬種，都付一搔頭。"]'),
('02e62e9e-2070-42a3-bc48-67da188fa637','中秋不見月次韻元衡十四夜江干步月五言','趙蕃','宋','宋诗','song-poetry','','[]','月待今宵滿，秋空此夕中。',48,'全唐诗/poet.song.165000.json','["月待今宵滿，秋空此夕中。", "與君俱客路，而我欠詩工。", "短髮添新白，頹顔失舊紅。", "波長嬉屬玉，渚遠愴賓鴻。"]'),
('a4658067-5738-463d-9aa9-70299e4973f8','中秋不見月得斯遠所寄詩有懷兼呈遠父成父','趙蕃','宋','宋诗','song-poetry','','[]','中秋不見月，空傳江左詩。',48,'全唐诗/poet.song.165000.json','["中秋不見月，空傳江左詩。", "陰晴定俱爾，離合政關茲。", "亦復婆娑否，還成賦詠爲。", "溪南舊遊地，誰與共襟期。"]'),
('d45828c0-e80f-4328-8928-15c40ce804a8','三夜不見月','趙蕃','宋','宋诗','song-poetry','','[]','中秋隔明日，月色比常佳。',48,'全唐诗/poet.song.165000.json','["中秋隔明日，月色比常佳。", "晨氣早已肅，暮雲深更遮。", "巡簷徒四立，顧影晚興嗟。", "桂旱猶藏蘂，橘秋反吐花。"]'),
('b3953588-4685-4cb9-8198-edf25901c3d9','是夕再題','趙蕃','宋','宋诗','song-poetry','','[]','只道陰能蔽，那知吹忽開。',48,'全唐诗/poet.song.165000.json','["只道陰能蔽，那知吹忽開。", "蕭蕭故差勝，皎皎適何來。", "起看寧辭倦，放吟無自哀。", "雖然不可久，白露點蒼苔。"]'),
('5e557188-d7a4-4232-9000-d5c9ee5ecf98','九日晦日雨忽雜霰','趙蕃','宋','宋诗','song-poetry','','[]','九月霰維集，南方見未曾。',48,'全唐诗/poet.song.165000.json','["九月霰維集，南方見未曾。", "馬寒添瑟縮，我瘦益崚嶒。", "窮相有如此，昔人誰似能。", "樹深鴉屢落，灘遠鴈相譍。"]'),
('72651cc3-0116-4db6-b6fc-ad9625c4815e','十一月大雷雨','趙蕃','宋','宋诗','song-poetry','','[]','疾雷驚萬里，凍雨落三更。',48,'全唐诗/poet.song.165000.json','["疾雷驚萬里，凍雨落三更。", "未暇尋洪範，誰能究五行。", "短檠無焰續，高枕待天明。", "鐘省成深省，雞聲匪惡聲。"]'),
('aa519175-2f82-4ec0-ae49-327f132361ac','十一月十五日風大作偶成四十字','趙蕃','宋','宋诗','song-poetry','','[]','江南無此風，羸疾詎煩攻。',48,'全唐诗/poet.song.165000.json','["江南無此風，羸疾詎煩攻。", "異事真同颶，夸辭嬾問雄。", "梅猶隠荆棘，菊已墮蒿蓬。", "坐撥寒灰盡，詩成欠得工。"]'),
('6853d440-1f14-4d46-a1a8-3d55ec7e1334','臘月二十四夜同成父對所傳贛陳丞詩作此寄陳','趙蕃','宋','宋诗','song-poetry','','[]','旁舍箠楚息，小齋燈火同。',48,'全唐诗/poet.song.165000.json','["旁舍箠楚息，小齋燈火同。", "猶貪誦詩好，未暇問人窮。", "笑我尉方暇，憶渠丞不聾。", "移官故相近，得句可郵筒。"]'),
('0a7ef48c-6b50-4997-a446-0bf34aac4492','立春日自城還縣道中作','趙蕃','宋','宋诗','song-poetry','','[]','晴烟生野聚，凍雪被山田。',48,'全唐诗/poet.song.165000.json','["晴烟生野聚，凍雪被山田。", "樹樹梅花下，芊芊麥秀邊。", "青春今日立，白髮此身憐。", "更想癡兒女，悲啼憶去年。"]'),
('f2d70ec4-14cc-4bfa-bf49-2abfeab7e630','舊縣道中二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','昨日風既止，今晨風未收。',48,'全唐诗/poet.song.165000.json','["昨日風既止，今晨風未收。", "浮波羨幽鳥，喚雨怕鳴鳩。", "遺寺荒村裏，貞祠古渡頭。", "登高謝能賦，物色漫分留。"]'),
('32649771-4321-468d-902e-584eebc929f8','舊縣道中二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','綠樹依平岸，平波映綠蕪。',48,'全唐诗/poet.song.165000.json','["綠樹依平岸，平波映綠蕪。", "中分雖有路，四極却成湖。", "艇子時三兩，漁村定有無。", "誰其爲題作，東野覓詩圖。"]'),
('8c67edee-0f1f-4531-a38d-bdaf1b751af5','五月二十一日徙寓智門二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','來歸迨一載，借屋已三遷。',48,'全唐诗/poet.song.165000.json','["來歸迨一載，借屋已三遷。", "易覺林間寺，難求郭外田。", "瓶儲朝乏粟，市糴日增錢。", "屢起瞻雲漢，今年甚去年。"]'),
('30201f47-f49c-4580-936b-54cf22d793f9','五月二十一日徙寓智門二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','欲去未能去，暫留還此留。',48,'全唐诗/poet.song.165000.json','["欲去未能去，暫留還此留。", "參差喬木合，映带野塘幽。", "父老記舊築，孫曾非昔遊。", "惟餘補陀像，香火得勤修。"]'),
('3360179d-b78b-4d4a-a15c-c79a2f0046d9','六月十五日時閔雨甚矣三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','一雨向何落，衆蟬空此鳴。',48,'全唐诗/poet.song.165000.json','["一雨向何落，衆蟬空此鳴。", "乍欣凉吹入，已復斷霞橫。", "尚擬通宵聽，何妨礙月明。", "豐凶終有數，憂苦自相并。"]'),
('cd378758-3af5-44e0-ac08-ec45c2edcb25','六月十五日時閔雨甚矣三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','萬室望霓願，千村車水歌。',48,'全唐诗/poet.song.165000.json','["萬室望霓願，千村車水歌。", "民勞已至此，天意定如何。", "朝聽聞爭米，宵傳說借禾。", "始焉因食飯，終矣事干戈。"]'),
('ed45b772-a3fe-4327-9872-a8aa01fd8d24','六月十五日時閔雨甚矣三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','去此林篁蔽，出茲溪谷深。',48,'全唐诗/poet.song.165000.json','["去此林篁蔽，出茲溪谷深。", "倍能明病眼，頓覺洗塵襟。", "問隠平生志，依僧夙昔心。", "危亭已無跡，斷刻尚堪臨。"]'),
('46006557-18f3-44c2-85d9-a3dec4a00957','連日欲雨輒爲風所敗','趙蕃','宋','宋诗','song-poetry','','[]','不雨又一月，望霓空衆心。',48,'全唐诗/poet.song.165000.json','["不雨又一月，望霓空衆心。", "雷師非敢怠，風伯故相侵。", "國祀居常典，天誅徯下臨。", "誰能奮韓筆，併爲丐商霖。"]'),
('9efc2f38-68c9-4886-be6a-0c10ec12a4e1','初七日雨殊未沾足作四十字','趙蕃','宋','宋诗','song-poetry','','[]','上天憐久旱，赫日變濃陰。',48,'全唐诗/poet.song.165000.json','["上天憐久旱，赫日變濃陰。", "要使今年熟，須成三日霖。", "蕭疎財却暑，點滴謾過林。", "問我無田客，那懷閔雨心。"]'),
('e9d2afce-4d67-46db-8256-7fcb90efb221','遲曉微雨已而復止','趙蕃','宋','宋诗','song-poetry','','[]','曉雨初傳聽，晨窗已斷聞。',48,'全唐诗/poet.song.165000.json','["曉雨初傳聽，晨窗已斷聞。", "日行將杲杲，雲起更紛紛。", "不似歲且盡，直疑春向分。", "南方故諳此，北叟漫驚云。"]'),
('16ac4e58-6e15-4628-9dd8-9e5a1b8f0beb','僕自乙酉至今凡四冬至皆在覊旅感慨成詩','趙蕃','宋','宋诗','song-poetry','','[]','至日長爲客，天涯空浩歎。',48,'全唐诗/poet.song.165000.json','["至日長爲客，天涯空浩歎。", "貧知學道力，晚悟作詩難。", "故舊勞相問，功名夢已殘。", "書生例難蹇，未可厭寒酸。"]'),
('7a26995f-5db8-42bf-adbc-c884012caddd','玉汝從溧陽來辱李晦菴以詩問訊次韻寄答二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','新詩明勝錦，健筆快於錐。',48,'全唐诗/poet.song.165000.json','["新詩明勝錦，健筆快於錐。", "工部深陶冶，昌黎雜怪奇。", "殷勤能寄遠，風俗頼扶衰。", "屢作挑燈讀，何勝對雨思。"]'),
('6113e46e-08fe-400a-a75b-6eeb1fb355ce','玉汝從溧陽來辱李晦菴以詩問訊次韻寄答二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','有身真有累，無地亦無錐。',48,'全唐诗/poet.song.165000.json','["有身真有累，無地亦無錐。", "遇事頻三北，干時愧六奇。", "自嗟寒若此，誰閔病而衰。", "已辦窮秋去，寧餘幾日思。"]'),
('438bd702-b64f-413a-bc51-19915ca0f173','冬日雜興  其一','趙蕃','宋','宋诗','song-poetry','','[]','日出山門曉，日入山徑陰。',48,'全唐诗/poet.song.165000.json','["日出山門曉，日入山徑陰。", "區區昏復旦，役役古猶今。", "竹瘦人群玉，菊荒文碎金。", "泛觀難究理，默識自明心。"]'),
('99fa769c-a8d6-4da7-8505-a63c801c444f','冬日雜興  其二','趙蕃','宋','宋诗','song-poetry','','[]','節物他鄉晚，風聲大壑俱。',48,'全唐诗/poet.song.165000.json','["節物他鄉晚，風聲大壑俱。", "深愁木斯拔，寧慮蔓難圖。", "杜老衣何短，顔公米已無。", "可憐雞瑟縮，幸免鼠睢盱。"]'),
('538b6420-f556-4c2a-ab64-f846975f6c6f','冬日雜興  其三','趙蕃','宋','宋诗','song-poetry','','[]','暑雨報禾熟，霜晴憂菜空。',48,'全唐诗/poet.song.165000.json','["暑雨報禾熟，霜晴憂菜空。", "藜羹聊自誑，肉食念何功。", "歲晚貧兼病，年來西復東。", "詩成資遣悶，文就返招窮。"]'),
('97d05a9e-5d76-41ec-bb6c-8b3cdf5770fe','冬日雜興  其四','趙蕃','宋','宋诗','song-poetry','','[]','憒憒若有失，岑岑殊未佳。',48,'全唐诗/poet.song.165000.json','["憒憒若有失，岑岑殊未佳。", "枯藜茅屋靜，高枕竹窗斜。", "冬日誰云短，吾生幸有涯。", "薰爐微結篆，茗盌細浮花。"]'),
('da430912-6dfe-4f1f-876d-19f899f91df1','冬日雜興  其五','趙蕃','宋','宋诗','song-poetry','','[]','鷺舉虞卿璧，山開京兆眉。',48,'全唐诗/poet.song.165000.json','["鷺舉虞卿璧，山開京兆眉。", "窮愁雖付酒，閒意更關詩。", "地瘠黄楊燥，旱深蕎麥遲。", "冬溫要非正，冰霰汝爲期。"]'),
('b41b9ae6-1e11-48ef-b7c1-34e64de22b14','冬日雜興  其六','趙蕃','宋','宋诗','song-poetry','','[]','要識豐年象，閑觀別墅詩。',48,'全唐诗/poet.song.165000.json','["要識豐年象，閑觀別墅詩。", "雞聲一閒暇，人語兩娛嬉。", "北闕非無怒，東臯且自怡。", "物華從晼晚，吾意亦差池。"]'),
('9b9787b2-5932-4a10-a9a0-9cf8b5450044','冬日雜興  其七','趙蕃','宋','宋诗','song-poetry','','[]','久矣勞生厭，欣然野趣俱。',48,'全唐诗/poet.song.165000.json','["久矣勞生厭，欣然野趣俱。", "蒼姿松砥節，外飾橘紆朱。", "翰墨真吾好，功名已後圖。", "一椽今粗有，二頃莫憂無。"]'),
('18319292-b130-4011-82af-23fa566565fd','冬日雜興  其八','趙蕃','宋','宋诗','song-poetry','','[]','楊柳迎霜敗，枇杷隔歲花。',48,'全唐诗/poet.song.165000.json','["楊柳迎霜敗，枇杷隔歲花。", "柴桑今學隠，杜曲舊爲家。", "北訊時聞鴈，南烹久厭蛙。", "歸津隔吳越，隨地且桑麻。"]'),
('bd21ba4a-28d1-4dec-8852-962b7045c9c1','留題竹隠','趙蕃','宋','宋诗','song-poetry','','[]','逐日身頻役，來歸歲兩徂。',48,'全唐诗/poet.song.165000.json','["逐日身頻役，來歸歲兩徂。", "已悲松老大，更覺徑荒蕪。", "築室期終隠，干時恥異圖。", "因聲里中老，爲護竹邊雛。"]'),
('b36cc053-5fd7-47b3-bae7-6080b5b321d7','雨中懷竹隠','趙蕃','宋','宋诗','song-poetry','','[]','還因今夜雨，憶著故山凉。',48,'全唐诗/poet.song.165000.json','["還因今夜雨，憶著故山凉。", "野水循除急，脩筠出屋長。", "螢光侵蕙帳，鼠迹亂書囊。", "豈不念歸去，懷哉方絕糧。"]'),
('9d0c9713-89c3-4305-99e5-8335daa424a3','得山中訊','趙蕃','宋','宋诗','song-poetry','','[]','忽枉山中訊，新篁長舊竿。',48,'全唐诗/poet.song.165000.json','["忽枉山中訊，新篁長舊竿。", "風神渴瀟灑，消息報平安。", "昔已開三徑，歸何病一簞。", "借居寧自逸，理橐不應難。"]'),
('b7aab255-f804-4747-ac26-89e405eab558','次韻斯遠見寄','趙蕃','宋','宋诗','song-poetry','','[]','近市嫌紛擾，山居取靜深。',48,'全唐诗/poet.song.165000.json','["近市嫌紛擾，山居取靜深。", "俗塵雖遠隔，住處闕同臨。", "孰愈思君瘦，頻來可老吟。", "便應如對面，何止伴孤斟。"]'),
('ebf63b7f-0864-49a2-84f0-b3e945e8a903','沖谷過予晏齋','趙蕃','宋','宋诗','song-poetry','','[]','夢裏春歸去，榴花晚欲然。',48,'全唐诗/poet.song.165000.json','["夢裏春歸去，榴花晚欲然。", "窗晴書味熟，竹密鳥聲圓。", "多病妨搜句，逢人懶問禪。", "澹然無可語，危坐了鑪烟。"]'),
('9b3314f8-8dfc-4854-834c-8ee309170fa1','夜憶逸','趙蕃','宋','宋诗','song-poetry','','[]','雨聽止復作，灘聞抑更揚。',48,'全唐诗/poet.song.165000.json','["雨聽止復作，灘聞抑更揚。", "貪程謂日短，無寐識更長。", "兒歎父官遠，父憂兒學荒。", "渠能志游夏，我可吊沅湘。"]'),
('b628799a-2918-4b3c-9efd-631c9810a835','寄內及兒女二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','誰令未得歸，不解忍長饑。',48,'全唐诗/poet.song.165000.json','["誰令未得歸，不解忍長饑。", "歲晏得無感，書來何况遲。", "鴈聞傷北客，梅動是南枝。", "悵望山菴竹，青青獨守墀。"]'),
('0dfd9f69-0873-48ba-af73-8ac80cc874f8','寄內及兒女二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','幼子未識面，吾兒無用英。',48,'全唐诗/poet.song.165000.json','["幼子未識面，吾兒無用英。", "家雖以儒奮，身欲事農耕。", "水竹爲居處，布荆令女行。", "超然老夫婦，脫粟配藜羹。"]'),
('10734ff7-948b-4a50-ae38-b249894906e7','曝日二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','勿謂吾居陋，能來曉日多。',48,'全唐诗/poet.song.165000.json','["勿謂吾居陋，能來曉日多。", "屈伸忘病體，淪浹見天和。", "孰愈萬全藥，賢於五袴歌。", "食芹真有味，獻語欲同科。"]'),
('a7c292bc-1c7e-4166-8d7c-652d68f650a4','曝日二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','肅肅初停照，熙熙頓得春。',48,'全唐诗/poet.song.165000.json','["肅肅初停照，熙熙頓得春。", "人知受天賜，爲我樂堯民。", "體垢便搔抑，坐多忘欠伸。", "階除失餘潤，窗戶走遊塵。"]'),
('ada50d39-76de-4da9-a17d-8189b5dd14a0','早作','趙蕃','宋','宋诗','song-poetry','','[]','雞送山窗月，鐘殘欹枕眠。',48,'全唐诗/poet.song.165000.json','["雞送山窗月，鐘殘欹枕眠。", "櫛疏知鬢禿，肘見覺裘穿。", "覓句無新意，繙書有舊緣。", "縱違幽事喜，差免俗塵煎。"]'),
('a1bd5d71-5b5e-4985-9538-982312deb2fa','元日病中','趙蕃','宋','宋诗','song-poetry','','[]','故國歸無路，深居懶問津。',48,'全唐诗/poet.song.165000.json','["故國歸無路，深居懶問津。", "莫嗟今歲病，還守去年貧。", "禦冷休嫌絮，開懷但飲醇。", "東風到梅柳，枯木自逢春。"]'),
('acc78352-b54b-4004-ae97-56c9c6e8a25b','病中即事','趙蕃','宋','宋诗','song-poetry','','[]','病態與時關，炎凉僅覆翻。',48,'全唐诗/poet.song.165000.json','["病態與時關，炎凉僅覆翻。", "秋風已吹鬢，沴氣尚留根。", "比屋均如此，吾生敢自論。", "苦嗟詩總廢，斗水汲深渾。"]'),
('659a04e7-0fed-4507-890a-f8d666739efa','病中即事十五首  其一','趙蕃','宋','宋诗','song-poetry','','[]','半百還過半，平安殊未平。',48,'全唐诗/poet.song.165000.json','["半百還過半，平安殊未平。", "饑寒兼抱病，造物此何情。", "詎敢懷尤怨，那能問否亨。", "獨憐無以養，深愧下簾生。"]'),
('c434edc5-99b2-463b-bddc-24c67434d24c','病中即事十五首  其二','趙蕃','宋','宋诗','song-poetry','','[]','汀袍猶擁綠，林幄尚遮青。',48,'全唐诗/poet.song.165000.json','["汀袍猶擁綠，林幄尚遮青。", "霖雨秋冬接，商飈早晚經。", "枯荄明野燒，槁葉暗深坰。", "榮謝何終極，衰遲孰所令。"]'),
('7d6aca0d-b1df-4074-b607-c288e04f142d','病中即事十五首  其三','趙蕃','宋','宋诗','song-poetry','','[]','炎凉自時態，何乃戰胸中。',48,'全唐诗/poet.song.165000.json','["炎凉自時態，何乃戰胸中。", "譴句追韓子，辟碑摹魯公。", "聞塵非爲蟻，是境不因工。", "要使神明復，毋辭瞑眩攻。"]'),
('bad12233-12d2-45ec-9ac1-60635b814cc0','病中即事十五首  其四','趙蕃','宋','宋诗','song-poetry','','[]','宵晴朝復雨，夜雨曉還晴。',48,'全唐诗/poet.song.165000.json','["宵晴朝復雨，夜雨曉還晴。", "未識冬天爾，渾疑春令行。", "人人憂瘧癘，物物敗生成。", "襘法繇來古，官居孰用情。"]'),
('e44b8fb4-2742-48de-ac9b-af314555fb36','病中即事十五首  其五','趙蕃','宋','宋诗','song-poetry','','[]','端居念朋友，多病懶書題。',48,'全唐诗/poet.song.165000.json','["端居念朋友，多病懶書題。", "懷舊頻搔首，看雲獨杖藜。", "魚沉秋水闊，鴻遠暮天低。", "直恐乖離久，相逢老少迷。"]'),
('c5d7c8a7-2b42-4f68-ba74-8d4da4c58fb2','病中即事十五首  其六','趙蕃','宋','宋诗','song-poetry','','[]','莽莽前山隔，冥冥獨樹遮。',48,'全唐诗/poet.song.165000.json','["莽莽前山隔，冥冥獨樹遮。", "斷行迷白鷺，垂翅濕歸鴉。", "暝色看仍合，羈愁望愈賒。", "不應緣一病，全失醉生涯。"]'),
('1cfb7aad-8107-4551-ad0a-2ff971a24ec0','病中即事十五首  其七','趙蕃','宋','宋诗','song-poetry','','[]','晚食以當肉，人言蠋巧貧。',48,'全唐诗/poet.song.165000.json','["晚食以當肉，人言蠋巧貧。", "茹蔬何不可，設說未爲真。", "既屏豬肝累，何須鮭菜珍。", "夜煨牛糞芋，朝罨破鐺塵。"]'),
('0970f08e-72cf-4e57-99a8-ebfca9773462','病中即事十五首  其八','趙蕃','宋','宋诗','song-poetry','','[]','蒲柳望秋衰，風霜况此時。',48,'全唐诗/poet.song.165000.json','["蒲柳望秋衰，風霜况此時。", "人今非少壯，病祇益清羸。", "幾誦立名語，頻哦看鏡詩。", "浮生那足恃，迅景不容追。"]'),
('97932d98-6b94-4eab-bf2f-b5622d4c5c7c','病中即事十五首  其九','趙蕃','宋','宋诗','song-poetry','','[]','叢菊雖云薄，秋花獨此芳。',48,'全唐诗/poet.song.165000.json','["叢菊雖云薄，秋花獨此芳。", "祇愁霜後槁，寧慮雨前荒。", "蝶冷飛無迹，恐哀咽更長。", "嗟予自失所，對汝益增傷。"]'),
('4e9fbcf6-7db0-4af2-a629-fa1f5626f749','病中即事十五首  其一○','趙蕃','宋','宋诗','song-poetry','','[]','嬾命雞栖駕，分安龍具寒。',48,'全唐诗/poet.song.165000.json','["嬾命雞栖駕，分安龍具寒。", "枕肱朝日美，擁鼻北風酸。", "僞異公孫被，甘同陋巷簞。", "啼號從强聒，憂樂聽旁觀。"]'),
('ea93a8ba-1db3-407d-a1d0-23ae86d4913c','病中即事十五首  其一一','趙蕃','宋','宋诗','song-poetry','','[]','精廬名負郭，古路別通村。',48,'全唐诗/poet.song.165000.json','["精廬名負郭，古路別通村。", "落葉多新積，蒼苔半宿根。", "杖藜溪見影，步屐雨流痕。", "更羨兒童輩，騎牛不駕轅。"]'),
('e7632073-57fa-46d3-b5a3-0633526a219c','病中即事十五首  其一二','趙蕃','宋','宋诗','song-poetry','','[]','暮與牛羊夕，朝隨鴉鵲興。',48,'全唐诗/poet.song.165000.json','["暮與牛羊夕，朝隨鴉鵲興。", "山林真可樂，軒冕夢何曾。", "供給欠升斗，往還無友朋。", "粗成酬二事，老此詎難能。"]'),
('ab81c59d-8a20-4d04-9b2f-cf7b36ca903c','病中即事十五首  其一三','趙蕃','宋','宋诗','song-poetry','','[]','雨合湍流急，風高松韻寒。',48,'全唐诗/poet.song.165000.json','["雨合湍流急，風高松韻寒。", "中宵空耿耿，長夜苦漫漫。", "夢去無多地，愁來匪一端。", "明朝對清鏡，政恐覺凋殘。"]'),
('31fce224-7db0-4a50-a868-df7582448653','病中即事十五首  其一四','趙蕃','宋','宋诗','song-poetry','','[]','雨濕雲衣歛，風沉月鏡昏。',48,'全唐诗/poet.song.165000.json','["雨濕雲衣歛，風沉月鏡昏。", "誰家宵急杵，何處苦啼猿。", "睡思渾無思，吟魂欲斷魂。", "鍾聲纔近寺，雞叫已遥村。"]'),
('bf78fefb-35f9-4da4-9a3a-79b27efff06b','病中即事十五首  其一五','趙蕃','宋','宋诗','song-poetry','','[]','風雨雖如晦，雞鳴不廢晨。',48,'全唐诗/poet.song.165000.json','["風雨雖如晦，雞鳴不廢晨。", "窗明驚次第，吾卧特逡巡。", "泣豆因煮豆，柏人何迫人。", "爲家疑宿業，舊學似前身。"]'),
('5773f614-f5c7-4075-b296-38c11812812d','人日立春','趙蕃','宋','宋诗','song-poetry','','[]','陰已至人日，雨仍當立春。',48,'全唐诗/poet.song.165000.json','["陰已至人日，雨仍當立春。", "梅花一開謝，草色半陳新。", "節物變風物，病身成老身。", "微吟終楚調，高興屬詞人。"]'),
('63469c01-89e8-4036-9fe5-0acf6f5b6135','十四夜用立春韻','趙蕃','宋','宋诗','song-poetry','','[]','舊雪猶連雪，新春未得春。',48,'全唐诗/poet.song.165000.json','["舊雪猶連雪，新春未得春。", "燒燈當變節，圓月與俱新。", "邂逅成朋飲，飄流愴客身。", "還家重蕭索，山鬼闖厨人。"]'),
('c02e72f9-ca5f-4c1d-bdd7-cd7e0bd5cb33','立春日邂逅周文顯于子暢兄許飲酒論文歡有餘也成二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','文字追秦漢，簞瓢保賤貧。',48,'全唐诗/poet.song.165000.json','["文字追秦漢，簞瓢保賤貧。", "延英空側席，下里老斯人。", "傾蓋寧嗟晚，推門莫厭頻。", "罷談芻狗用，且看土牛春。"]'),
('3e38cf00-943b-4139-8d48-3ced78e61208','立春日邂逅周文顯于子暢兄許飲酒論文歡有餘也成二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','吾友南昌尉，典刑諸父風。',48,'全唐诗/poet.song.165000.json','["吾友南昌尉，典刑諸父風。", "元龍豪氣在，東野古心同。", "置酒能招我，論文更許公。", "相從真益者，那復嘆途窮。"]'),
('819893ca-8a0c-4ec4-bed9-bcc6095fc8fb','俗有社日不飲酒變爲豬之說作詩示兒曹','趙蕃','宋','宋诗','song-poetry','','[]','雨勢來相續，陰霾鬰不舒。',48,'全唐诗/poet.song.165000.json','["雨勢來相續，陰霾鬰不舒。", "舉觴隨楚俗，酌醴從枯魚。", "宰肉非吾事，祈田顧歲儲。", "龍豬自有分，社飲不關渠。"]'),
('695dce1c-85c2-47f2-be3b-fb6b19a4ab00','徐丈大雅有詩贈子暢尉曹用韻呈子暢兼柬徐丈','趙蕃','宋','宋诗','song-poetry','','[]','謝子姿野鶴，聳然常自昂。',48,'全唐诗/poet.song.165000.json','["謝子姿野鶴，聳然常自昂。", "貪留故人飯，忘踏板橋霜。", "舉世謬爲敬，從吾醒亦狂。", "交遊有徐庶，頭白尚東牆。"]'),
('0f98a66e-6947-41e9-b6e5-04eb748027b5','二月初二日二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','去歲不作瘧，今年乃病溫。',48,'全唐诗/poet.song.165000.json','["去歲不作瘧，今年乃病溫。", "初無一牀卧，但有小舟蹲。", "未怕黄州鬼，唯憂楚國魂。", "明朝强撐拄，摇兀到吳門。"]'),
('fec0fede-ce03-4610-85a7-68330d1e4678','二月初二日二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','所見與所聞，豪華同賤貧。',48,'全唐诗/poet.song.165000.json','["所見與所聞，豪華同賤貧。", "寒時端有獨，溫處乃能均。", "幸止葯餌費，深知天地仁。", "流行代斯有，不必嫁諸鄰。"]'),
('6591ab93-ab39-4307-b155-da49d43269e3','二月十二日雨寒','趙蕃','宋','宋诗','song-poetry','','[]','重設匡爐火，還披故絮裘。',48,'全唐诗/poet.song.165000.json','["重設匡爐火，還披故絮裘。", "春風今已半，地域况南頭。", "次第農耕動，侵尋花事休。", "浮生有過鳥，歸計欠沉牛。"]'),
('1115e01a-48c2-4de1-a690-5da3a667c466','伏日','趙蕃','宋','宋诗','song-poetry','','[]','熱苦應伏至，風清非雨祥。',48,'全唐诗/poet.song.165000.json','["熱苦應伏至，風清非雨祥。", "那知潦未退，遽與旱相望。", "荷損無裳被，菊枯愆糗芳。", "農夫還噍我，汝事異吾忙。"]'),
('4de9d0e2-9938-4858-9e5f-9f7f5c367e2f','六月十七夜出寺門驟有所聞疑水與風即而觀之雨也對面而橫騖焉已而傾注中夕復作明日猶未已賦詩三首與欽止斯遠同之  其一','趙蕃','宋','宋诗','song-poetry','','[]','驟得疑傾峽，徐行若泛潮。',48,'全唐诗/poet.song.165000.json','["驟得疑傾峽，徐行若泛潮。", "胡爲隔田畝，而不度林椒。", "爽氣雖能及，餘波不可招。", "不眠如有待，衝口漫成謠。"]'),
('d9bc592a-be03-47dc-a9b4-eaa858beda75','六月十七夜出寺門驟有所聞疑水與風即而觀之雨也對面而橫騖焉已而傾注中夕復作明日猶未已賦詩三首與欽止斯遠同之  其二','趙蕃','宋','宋诗','song-poetry','','[]','昨日真聊爾，今宵頗快哉。',48,'全唐诗/poet.song.165000.json','["昨日真聊爾，今宵頗快哉。", "無嫌雨脚短，故喜旱頭開。", "一飽歸天賜，群凶勿幸災。", "誰驅霹靂駕，更起阿香雷。"]'),
('8fb6069e-9708-4ec8-9210-77d50945a190','六月十七夜出寺門驟有所聞疑水與風即而觀之雨也對面而橫騖焉已而傾注中夕復作明日猶未已賦詩三首與欽止斯遠同之  其三','趙蕃','宋','宋诗','song-poetry','','[]','中宵還瀏瀏，乞曉更蕭蕭。',48,'全唐诗/poet.song.165000.json','["中宵還瀏瀏，乞曉更蕭蕭。", "亟作溪頭看，猶霑樹杪飄。", "田家比屋喜，沴氣十分消。", "我得扁舟去，江湖興久摇。"]'),
('05037aa8-1c3a-4ccc-978b-d6ccf09cb35c','過水南甚早','趙蕃','宋','宋诗','song-poetry','','[]','夜雨曉僅止，前山雲未收。',48,'全唐诗/poet.song.165000.json','["夜雨曉僅止，前山雲未收。", "陂田飛宿鷺，社木喚晴鳩。", "雲裏浮圖級，灘邊賈客舟。", "故知山可住，不覺利能謀。"]'),
('4da54228-4a41-4a99-91bd-d2b42dd746d8','早題','趙蕃','宋','宋诗','song-poetry','','[]','夜雨曉猶濕，曉天晴未分。',48,'全唐诗/poet.song.165000.json','["夜雨曉猶濕，曉天晴未分。", "澄波靜如練，秀野綠於雲。", "禽語無殊聽，鄉音有異聞。", "要知皆可隠，鳥獸詎同羣。"]'),
('65369bf9-fa6c-4e05-b7bc-071796feb15f','早作','趙蕃','宋','宋诗','song-poetry','','[]','蕭蕭初對雨，灧灧急看晴。',48,'全唐诗/poet.song.165000.json','["蕭蕭初對雨，灧灧急看晴。", "遠樹孤煙出，曠陂春水生。", "不關形役累，自作野田行。", "獨愧龍鍾者，猶敺觳觫耕。"]'),
('240a4ea2-a4f8-4574-8638-072ad842ba8c','早出','趙蕃','宋','宋诗','song-poetry','','[]','平明策蹇出，遇雨且歸休。',48,'全唐诗/poet.song.165000.json','["平明策蹇出，遇雨且歸休。", "樹樹花藏霧，田田水漫流。", "徙居還客寓，敗意阻春遊。", "頼有題詩興，聊當一以酬。"]'),
('b11bc280-96be-4dd6-bda5-fcc051cb7a0d','示逸二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','縱欲必富貴，成身多賤貧。',48,'全唐诗/poet.song.165000.json','["縱欲必富貴，成身多賤貧。", "寸陰寧重璧，江水本觴岷。", "勿但愈流俗，要當論古人。", "殘冬不十日，又說待來春。"]'),
('5d1a4b49-0d28-4142-8557-04d05a4c3b3a','示逸二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','菊種初猶落，及今當梢滋。',48,'全唐诗/poet.song.165000.json','["菊種初猶落，及今當梢滋。", "晴多須灌溉，草蔓合耘治。", "夏欲助茗椀，秋當浮酒巵。", "落英如可拾，更得慰長饑。"]'),
('15bddbe6-8087-458b-944d-6e014e519b6f','次韻斯遠晚步見懷','趙蕃','宋','宋诗','song-poetry','','[]','友遠弟仍出，柴扃誰復過。',48,'全唐诗/poet.song.165000.json','["友遠弟仍出，柴扃誰復過。", "卷終方獨坐，詩至得長哦。", "我乏王楊體，君寧崔蔡多。", "相思欲相覓，馬瘦怯陂陀。"]'),
('a61b8730-0f17-49be-99a2-5707139fe5e9','晚步溪旁示周次顔','趙蕃','宋','宋诗','song-poetry','','[]','村醉不能醒，徐行得蹔停。',48,'全唐诗/poet.song.165000.json','["村醉不能醒，徐行得蹔停。", "路收泥活活，田擁麥青青。", "放意知予獨，哦詩頼子聽。", "要觀溪潦暴，却畏晚風泠。"]'),
('5b06e6dc-1be7-4e28-976d-d883ad69f22a','中夜復書','趙蕃','宋','宋诗','song-poetry','','[]','凉生愁輾轉，月上照鬅鬙。',48,'全唐诗/poet.song.165000.json','["凉生愁輾轉，月上照鬅鬙。", "林壑故對此，溪山逢未曾。", "吟哀蛩伴苦，書絕鴈無憑。", "更欲留危坐，枝梧殆不勝。"]'),
('ac78be07-c039-4a02-accb-e373b1390f3f','懷明叔晚題','趙蕃','宋','宋诗','song-poetry','','[]','室暗莫遽寢，庭空成漫行。',48,'全唐诗/poet.song.165000.json','["室暗莫遽寢，庭空成漫行。", "蚊喧方夏聚，蟲咽已秋鳴。", "月淡星能著，雲疏電或明。", "可人非故乏，幽處莫能并。"]'),
('8831d401-6b02-4118-8169-16b0f960e740','晚作','趙蕃','宋','宋诗','song-poetry','','[]','午暑如許酷，晚凉能爾清。',48,'全唐诗/poet.song.165000.json','["午暑如許酷，晚凉能爾清。", "山陰雙鷺落，林杪幾蟬鳴。", "懶對自閒坐，閑穿不借行。", "追風更撐月，安得小舟橫。"]'),
('8707bc16-7478-4fa2-9204-f283d7b38e93','郊居書事','趙蕃','宋','宋诗','song-poetry','','[]','物意因人喜，人情與物和。',48,'全唐诗/poet.song.165000.json','["物意因人喜，人情與物和。", "家家繰繭火，處處插秧歌。", "麥熟黄疑委，桑餘路尚多。", "我居雖偪仄，度日亦婆娑。"]'),
('05e824d5-440d-4337-aa03-c4346af029fc','課詩','趙蕃','宋','宋诗','song-poetry','','[]','灘長有餘逸，灘迥不勝遲。',48,'全唐诗/poet.song.165000.json','["灘長有餘逸，灘迥不勝遲。", "山帽堆雲絮，水紋飛雨絲。", "鷗鳴如避弋，鳥倦盍投枝。", "無計繁憂整，聊因課小詩。"]'),
('adcb64b5-8471-4d8d-86fb-d8805c11577a','信題','趙蕃','宋','宋诗','song-poetry','','[]','假日成愒日，朝酲還暮酲。',48,'全唐诗/poet.song.165000.json','["假日成愒日，朝酲還暮酲。", "餘寒猶未去，破褐尚留情。", "野樹梅花落，空庭春草生。", "得閑聊信筆，不復强爲名。"]'),
('894ae248-02c3-4ab7-b47d-eabe3e5b6342','不寐','趙蕃','宋','宋诗','song-poetry','','[]','近夢續遠夢，長更和短更。',48,'全唐诗/poet.song.165000.json','["近夢續遠夢，長更和短更。", "月窗疑雪積，風柁苦宵行。", "天外獨身在，暗中華髮生。", "歸田莫遲暮，底是物窮亨。"]'),
('94956072-9547-4eae-a13d-e336f2576f2a','病卧聞益卿未行不能晤語成四十字','趙蕃','宋','宋诗','song-poetry','','[]','卧聽晚來雨，懸知明日行。',48,'全唐诗/poet.song.165000.json','["卧聽晚來雨，懸知明日行。", "破床空輾轉，高論阻崢嶸。", "文選君精理，江西我濫名。", "官曹敢論契，翰墨且尋盟。"]'),
('f6c0e7fe-c446-49a8-9c23-2a296bb2003a','晨起聞雞','趙蕃','宋','宋诗','song-poetry','','[]','宿雨收茅屋，群雞叫遠村。',48,'全唐诗/poet.song.165000.json','["宿雨收茅屋，群雞叫遠村。", "病羸深擁褐，厨罄晚開門。", "流落何年已，荒凉莫自存。", "束書徒負載，饑至不堪論。"]'),
('f17e5944-7a3f-43e0-938d-441f9017a9be','次韻和答斯遠入城見迎詩  其一','趙蕃','宋','宋诗','song-poetry','','[]','往辱携詩送，今勞入郭迎。',48,'全唐诗/poet.song.165000.json','["往辱携詩送，今勞入郭迎。", "交情如許厚，俗眼亦增明。", "冬仲溪宜涸，灘長路失平。", "要歸歸已近，物物繫吾情。"]'),
('cb6b91e7-b414-4344-a947-6bc21baad1c1','次韻和答斯遠入城見迎詩  其二','趙蕃','宋','宋诗','song-poetry','','[]','四海豈不廣，一身何所歸。',48,'全唐诗/poet.song.165000.json','["四海豈不廣，一身何所歸。", "倦遊成白首，知已固黄扉。", "媿我尚斗食，如君猶褐衣。", "長年恨相遠，晚歲得相依。"]'),
('2ef33a34-9d6c-403d-b86c-ecb10ad51ba2','晨興次季承韻','趙蕃','宋','宋诗','song-poetry','','[]','薄霧收殘雨，疎雲漏曉暾。',48,'全唐诗/poet.song.165000.json','["薄霧收殘雨，疎雲漏曉暾。", "泥行從上下，歸近得欣犇。", "近作要重錄，舊書仍再溫。", "平生屏居趣，畢世願衡門。"]'),
('ae624ff8-108d-465c-ba2b-f020fea938d7','飯後獨立寺門頗見摇落之境欲收以詩大費彈壓僅得二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','作詩無遠到，佇立有深思。',48,'全唐诗/poet.song.165000.json','["作詩無遠到，佇立有深思。", "集此溪山趣，充吾耳目資。", "唐虞紫微論，蘇李少陵詩。", "落落心雖在，茫茫力已疲。"]'),
('eb37c64c-b574-4fea-88dd-9c50677dfca3','飯後獨立寺門頗見摇落之境欲收以詩大費彈壓僅得二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','起望若有得，欲言殊費辭。',48,'全唐诗/poet.song.165000.json','["起望若有得，欲言殊費辭。", "冥搜累肝腎，凝想見鬚眉。", "此樂誰能愈，雖貧自勿疑。", "是身寧大謬，無事及諸兒。"]'),
('27c97c0b-e6e8-43a3-96a9-b46bfe636d69','待成父不至','趙蕃','宋','宋诗','song-poetry','','[]','晚日下前村，呼兒候蓽門。',48,'全唐诗/poet.song.165000.json','["晚日下前村，呼兒候蓽門。", "屢驚鄰犬吠，頻問路人言。", "準擬繙詩卷，經營置酒尊。", "此懷無與共，愁坐虱空捫。"]'),
('8fe3e9ea-d632-4d58-bfb4-9e0a4c9b6c17','石田渡口待潘文叔去歲亦嘗於此待端叔','趙蕃','宋','宋诗','song-poetry','','[]','野店當溪靜，荒園得日寬。',48,'全唐诗/poet.song.165000.json','["野店當溪靜，荒園得日寬。", "頻因候客至，併此把詩看。", "肯寄山中信，如今世上難。", "却忘相見後，勞苦雜悲酸。"]'),
('e2e6e0a1-e165-4af9-97bb-a17233790a63','書事寄呈斯遠','趙蕃','宋','宋诗','song-poetry','','[]','路熟疑爲短，馬遲翻更長。',48,'全唐诗/poet.song.165000.json','["路熟疑爲短，馬遲翻更長。", "野田吹欲合，林日凍無光。", "未暇親書案，頻成喚酒觴。", "短檠今夕念，我友正相望。"]'),
('fdfaba33-3d20-467d-bad9-bd80f541629b','晴晚立田間二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','落日明深塢，微流咽斷橋。',48,'全唐诗/poet.song.165000.json','["落日明深塢，微流咽斷橋。", "牛童肩滯穗，汲婦抱遺樵。", "誰謂居田賤，殊勝處富驕。", "歸哉各其所，吾亦飫吾瓢。"]'),
('0a27baa2-6ecd-4c4a-ae6a-f5929be4d9e4','晴晚立田間二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','負稻赬肩已，腰鐮裹飯歸。',48,'全唐诗/poet.song.165000.json','["負稻赬肩已，腰鐮裹飯歸。", "犬能迎別徑，兒亦候幽扉。", "共說去年熟，却愁今歲饑。", "及閒還治圃，促婦更鳴機。"]'),
('1f958193-3d78-4ec6-b915-e3cd6f208797','觀田者有感而作','趙蕃','宋','宋诗','song-poetry','','[]','白水田田滿，青秧處處高。',48,'全唐诗/poet.song.165000.json','["白水田田滿，青秧處處高。", "雨滋無復旱，人喜不知勞。", "顧我方羈旅，徒能慕汝曹。", "豐年如可望，賤糴亦多遭。"]'),
('c7887c3f-8ec9-47d1-aa76-0a974a871fe2','已晴復陰','趙蕃','宋','宋诗','song-poetry','','[]','雲去疑收雨，雲來復作陰。',48,'全唐诗/poet.song.165000.json','["雲去疑收雨，雲來復作陰。", "已聞崩澗壑，何止暗園林。", "蛙鬭怒何事，鳩鳴非好音。", "農心殊閔閔，病體更岑岑。"]'),
('c262f07d-0f56-4b00-9f88-888214d70d6f','晚坐欲過在伯而不能','趙蕃','宋','宋诗','song-poetry','','[]','暑威驗伏始，月遲知望過。',48,'全唐诗/poet.song.165000.json','["暑威驗伏始，月遲知望過。", "無風能濯熱，有句可蠲疴。", "竟拙空頻點，求工復屢哦。", "思尋戴安道，寧待雪舟何。"]'),
('27a0ef32-6ae9-4f1b-ad46-d1f920171f66','書事','趙蕃','宋','宋诗','song-poetry','','[]','當暑暑何在，以風風爲生。',48,'全唐诗/poet.song.165000.json','["當暑暑何在，以風風爲生。", "輿夫忘倦色，客子慰歸情。", "往者千年隔，人焉幾日程。", "同行得老伴，餘事率詩鳴。"]'),
('5f36ce64-879d-4ebc-ad17-2dca29c05762','寄題宋舜卿家小閣兼屬李亦韓梁進父二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','湖北終連北，辰州是古州。',48,'全唐诗/poet.song.165000.json','["湖北終連北，辰州是古州。", "故家唯宋氏，舊物有書不。", "幾踏緣江路，頻登小閣幽。", "雖微少陵句，不減浣花頭。"]'),
('9c51adeb-38c6-4b03-9d04-74670748f96d','寄題宋舜卿家小閣兼屬李亦韓梁進父二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','憶我辰州友，英英李宋梁。',48,'全唐诗/poet.song.165000.json','["憶我辰州友，英英李宋梁。", "參差由百拽，悵望到三湘。", "邂逅書能寄，追隨辱未忘。", "南山如訪舊，下有老耕桑。"]'),
('07245b27-38bd-4afd-850a-7ed605fcb3ea','獨步寺前待斯遠不至','趙蕃','宋','宋诗','song-poetry','','[]','隔墅雞啼午，經檐鳥喚春。',48,'全唐诗/poet.song.165000.json','["隔墅雞啼午，經檐鳥喚春。", "靜中成野步，老去得閒身。", "咫尺頻相覓，追隨定幾晨。", "村中應倍憶，海內復誰親。"]'),
('ff4ec58d-46d4-45f4-9fae-29958170eea5','中秋夜作去年今夕僕自北關過吳興','趙蕃','宋','宋诗','song-poetry','','[]','明月同千里，寒鄉又一秋。',48,'全唐诗/poet.song.165000.json','["明月同千里，寒鄉又一秋。", "牀隨檜陰側，巾與桂香浮。", "此夕山中趣，它年霅上遊。", "諸兒皆楚語，老子自商謳。"]'),
('3e020885-0bcf-44bd-ad97-9197ed72da1c','十六日夜邀二劉饒錢同成父飲','趙蕃','宋','宋诗','song-poetry','','[]','籍甚中秋月，飄然四海兄。',48,'全唐诗/poet.song.165000.json','["籍甚中秋月，飄然四海兄。", "詩兼淡仍泊，酒任濁還清。", "柳映蕭蕭影，灘聞活活聲。", "明年當此夕，擊柝政重城。"]'),
('7356f331-6ad4-48b1-8475-40422b9c044a','邢兄大聲以重九日置酒約梁丈仁伯段兄元衡蕃亦與焉賦詩二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','解印何其勇，五噫誰謂狂。',48,'全唐诗/poet.song.165000.json','["解印何其勇，五噫誰謂狂。", "雲仍有人物，家世未荒凉。", "學造淵騫寢，文推翰墨場。", "論交有如此，敢恨落殊方。"]'),
('61ddf091-5547-4cd2-8ed5-7272e556aa7c','邢兄大聲以重九日置酒約梁丈仁伯段兄元衡蕃亦與焉賦詩二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','栗里當年節，柯山七字詩。',48,'全唐诗/poet.song.165000.json','["栗里當年節，柯山七字詩。", "舉觴非徇俗，懷往要銷悲。", "暑絡膚侵凜，風巾鬢颯衰。", "多君能醉我，有客更同之。"]'),
('388e4a82-d98f-4ddd-8a28-f7c7025fb26c','九日欲行宜之兄見留賦詩一首','趙蕃','宋','宋诗','song-poetry','','[]','節裏留覉客，愁邊識此心。',48,'全唐诗/poet.song.165000.json','["節裏留覉客，愁邊識此心。", "臺高午時暖，齋靜晚來陰。", "白髮有衰盛，黄花無古今。", "君其賜茱會，我乃見山吟。"]'),
('91109eea-1ba5-4f77-ae01-41b835a0e1f2','九日','趙蕃','宋','宋诗','song-poetry','','[]','今年重九日，舟檝次蘭谿。',48,'全唐诗/poet.song.165000.json','["今年重九日，舟檝次蘭谿。", "懷古心雖壯，登高思却迷。", "山空分向背，木落盡高低。", "多少覉栖恨，寒猿斷續啼。"]'),
('4006ecb4-2990-4cb0-9aed-a3745282ff21','十九日招老謝丈','趙蕃','宋','宋诗','song-poetry','','[]','再失重陽集，才能一笑期。',48,'全唐诗/poet.song.165000.json','["再失重陽集，才能一笑期。", "兒童闖車馬，鳥雀避茅茨。", "雨後橙初熟，霜前菊未衰。", "招邀幸臨顧，傾飲莫相疑。"]'),
('8c3b1835-9859-4478-b066-49cd45236a61','十一月二十三日','趙蕃','宋','宋诗','song-poetry','','[]','正爾元無事，胡然不自聊。',48,'全唐诗/poet.song.165000.json','["正爾元無事，胡然不自聊。", "髯衰紛若雪，梅早綴如椒。", "太白傾殘榼，方爐𬋖柿樵。", "宦才成此味，隠莫待渠招。"]'),
('82b96dc6-6336-421c-b52a-4c0d4324e2d7','歲除日立春','趙蕃','宋','宋诗','song-poetry','','[]','舊歲此夕盡，新春今日回。',48,'全唐诗/poet.song.165000.json','["舊歲此夕盡，新春今日回。", "天公貪省事，嘉節併相催。", "謾有詩堪寫，初無尊可開。", "去年湖上寺，尚可寄尋梅。"]'),
('2d1aaac1-01d9-4081-b100-0949c32716ce','還章泉山居','趙蕃','宋','宋诗','song-poetry','','[]','林園柿栗日，郊野秔稻風。',48,'全唐诗/poet.song.165000.json','["林園柿栗日，郊野秔稻風。", "居皆有餘適，歲久無此豐。", "台背敬父老，裹頭問兒童。", "作客勿浪苦，此地吾當終。"]'),
('3804df4c-a589-477a-8800-1439d8f828e8','同文顯過山居','趙蕃','宋','宋诗','song-poetry','','[]','不惜露侵衣，俱行草徑微。',48,'全唐诗/poet.song.165000.json','["不惜露侵衣，俱行草徑微。", "論文尊有酒，竟日坐忘歸。", "誰謂吾居陋，能來好客稀。", "林園故多暇，杖屨莫相違。"]'),
('ad083eba-2a8f-4f5d-9f60-53b2821cb4d6','初夏山居有懷長沙從游四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','日者因回使，人纔致一書。',48,'全唐诗/poet.song.165000.json','["日者因回使，人纔致一書。", "有懷那再寫，爲况又何如。", "賈傅長沙國，陶公五柳廬。", "文章且難進，可向友朋疏。"]'),
('6dae0ea9-5570-485f-9c66-ff11ae546934','初夏山居有懷長沙從游四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','我愛長沙國，全如洛與伊。',48,'全唐诗/poet.song.165000.json','["我愛長沙國，全如洛與伊。", "諸公早聞道，老我謾耽詩。", "憶昨相追逐，何知有別離。", "湘西一回首，莽莽便天涯。"]'),
('0dee80c1-96e4-4e0f-88b0-a957384a0600','初夏山居有懷長沙從游四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','府谷我先契，諸公吾輩流。',48,'全唐诗/poet.song.165000.json','["府谷我先契，諸公吾輩流。", "懸知盍簪際，頗解憶人不。", "蕙逐光風轉，鸎啼出谷幽。", "因聲煩爲我，傳寫寄荆州。"]'),
('b4a3016f-3081-4209-81ec-2a5e67465691','初夏山居有懷長沙從游四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','想見湘西路，扶疏夏木長。',48,'全唐诗/poet.song.165000.json','["想見湘西路，扶疏夏木長。", "佛龕鐘磬寂，書屋簡編香。", "破霧穿晨屨，衝風喚晚航。", "向居嫌是客，今夢却同鄉。"]'),
('70f4c4b0-f002-4458-9a22-8fd20c6c50db','子進子儀過予山居子進有詩次韻呈子進兄弟二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','蓬蔴成蔽蔚，鄰曲斷經過。',48,'全唐诗/poet.song.165000.json','["蓬蔴成蔽蔚，鄰曲斷經過。", "茶供同桑苧，香聞共補陀。", "寒蒲空有節，古井久無波。", "尚病留餘習，詩成索細哦。"]'),
('de6d8765-6cf1-4b6a-be84-a519dc8c0bd4','子進子儀過予山居子進有詩次韻呈子進兄弟二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','荆谿有三士，求識自初年。',48,'全唐诗/poet.song.165000.json','["荆谿有三士，求識自初年。", "才大俱詩伯，公惟媿飲僊。", "結交期耐久，過我地忘偏。", "慚愧衡門下，今成頓有邊。"]'),
('91327695-9054-4aa3-8570-178a5c64127a','挽汪養源舍人二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','要識公兄弟，當年蜀兩蘇。',48,'全唐诗/poet.song.165000.json','["要識公兄弟，當年蜀兩蘇。", "文章到宗匠，人物見規模。", "謾有詞垣用，終遲政府須。", "世緣殊未了，忽復返清都。"]'),
('4e0feb7f-c9ea-407a-9547-82e9a6bd04d7','挽汪養源舍人二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','公作廬陵掾，先君官贛州。',48,'全唐诗/poet.song.165000.json','["公作廬陵掾，先君官贛州。", "書郵時問訊，江驛幾淹留。", "撫事今安在，臨風涕莫收。", "誰爲耆舊傳，好寄竹林遊。"]'),
('eaf308f1-fcce-4a5f-897c-93e333b8371c','挽施文叔三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','豈但吾州少，端如四海稀。',48,'全唐诗/poet.song.165000.json','["豈但吾州少，端如四海稀。", "儒林據根柢，玉德著光輝。", "不遇寧渠戚，傳亡始謂非。", "及今何所語，徒有淚霑衣。"]'),
('b1a926a3-2d9b-490a-ad15-d94d3ee9b7c2','挽施文叔三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','小作王官試，還爲幕府留。',48,'全唐诗/poet.song.165000.json','["小作王官試，還爲幕府留。", "綺歌偶意改，散號覓歸休。", "屈賈當重作，瀟湘漫一遊。", "胡爲車未發，已報病難瘳。"]'),
('4e5a1b04-94c2-4be9-ad65-c27623b872fe','挽施文叔三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','資福我跨蹇，智門分命車。',48,'全唐诗/poet.song.165000.json','["資福我跨蹇，智門分命車。", "那知畢世隔，但惜數年疏。", "此士豈復有，餘生誰與居。", "遺文好收拾，驥子記憐渠。"]'),
('768acc4a-903e-4272-907a-39b79fd5d149','挽謝景英丈二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','尚友固十載，過江真一時。',48,'全唐诗/poet.song.165000.json','["尚友固十載，過江真一時。", "信曾前輩及，寧後古人爲。", "竟作東山卧，漫傳康樂詩。", "荆州人物論，夫豈惜吾私。"]'),
('a0f386b7-c19f-4629-963e-0c845bf63aae','挽謝景英丈二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','不見遂歷載，寄書寧寫心。',48,'全唐诗/poet.song.165000.json','["不見遂歷載，寄書寧寫心。", "凄凉歎垂白，索寞遠知音。", "只道成乖隔，那知遂古今。", "赤城何許日，雲物渺難尋。"]'),
('6397d8dd-7759-4a8a-bcbd-c25694f706eb','挽余正叔','趙蕃','宋','宋诗','song-poetry','','[]','半生初未識，一見驟相親。',48,'全唐诗/poet.song.165000.json','["半生初未識，一見驟相親。", "九曲泛舟日，紫溪沽酒晨。", "我曹俱蹇薄，吾子固真醇。", "竟爾縈何疾，胡爲遽沒身。"]'),
('a1334574-2b7d-4b64-8deb-926d2ae58af4','挽周畏知二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','鄉里雖諸彥，情親不數人。',48,'全唐诗/poet.song.165000.json','["鄉里雖諸彥，情親不數人。", "比年成屢哭，將老愴吾身。", "問學文辭外，追隨寂寞濱。", "有懷終不遂，回首倍傷神。"]'),
('4742470b-9a97-4d20-bb9d-5e95933f5bac','挽周畏知二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','目疾初傳劇，猶思礙讀書。',48,'全唐诗/poet.song.165000.json','["目疾初傳劇，猶思礙讀書。", "那知遽至是，此恨合何如。", "我已鬢俱白，寧能世久居。", "吾人門戶責，驥子總憐渠。"]'),
('9ec25875-af9f-479a-902b-4568e456ff0f','挽周畏知母俞夫人二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','夫人不佞佛，平日事何如。',48,'全唐诗/poet.song.165000.json','["夫人不佞佛，平日事何如。", "臨死無貧苦，與常同起居。", "巫醫空睥睨，孝敬謾勤渠。", "性識真明達，油然悟本初。"]'),
('e69126b6-70ce-4740-bead-193064ac5de6','挽周畏知母俞夫人二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','卜兆雖自古，邇來聞見殊。',48,'全唐诗/poet.song.165000.json','["卜兆雖自古，邇來聞見殊。", "一言福後嗣，百計走愚巫。", "用意非流俗，惟賢畢此塗。", "徐看好兄弟，玉立騁天衢。"]'),
('3429a467-f8a1-469b-9919-e2527eae8efc','挽沈夫人','趙蕃','宋','宋诗','song-poetry','','[]','夫子家齊政，夫人實並賢。',48,'全唐诗/poet.song.165000.json','["夫子家齊政，夫人實並賢。", "女能堅素節，兒亦嗣青編。", "往日僧房寓，曾親壽酒邊。", "吁嗟難重拜，奠哭亦無緣。"]'),
('1840ac2a-e365-4c84-98ef-f47da52b1228','挽徐提舉夫人盧氏','趙蕃','宋','宋诗','song-poetry','','[]','進已後師說，中猶親母儀。',48,'全唐诗/poet.song.165000.json','["進已後師說，中猶親母儀。", "百年蘄未已，一病乃無醫。", "令子高交友，韓公直筆辭。", "是爲能不腐，雖死亦期頤。"]'),
('ac231f66-951b-4400-836d-e51dbbc5576b','挽楊茂原二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','玉美終懷璞，蘭香竟死林。',48,'全唐诗/poet.song.165000.json','["玉美終懷璞，蘭香竟死林。", "名期百世後，恨獨九原深。", "夜雨長形夢，秋風遂絕音。", "扁舟載孤旐，行路亦沾襟。"]'),
('daa42ce4-20bf-4a9c-befa-9cf4a79ce3d2','挽楊茂原二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','松老成哀吹，天高慘暮雲。',48,'全唐诗/poet.song.165000.json','["松老成哀吹，天高慘暮雲。", "如何歲時隔，便作死生分。", "經紀無家事，編藏有舊文。", "周侯誠義士，節概過非君。"]'),
('ddd7db2f-7bb6-443d-814e-26c266188480','挽俞克晦丈二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昨陳平相，鄉閭例薦延。',48,'全唐诗/poet.song.165000.json','["憶昨陳平相，鄉閭例薦延。", "蓬山渝奏墨，巖邑漫銓員。", "祠館歸求志，周行數選賢。", "那知終不偶，幕府遂終焉。"]'),
('18c83ee6-fa67-4b98-8f09-23a336887c25','挽俞克晦丈二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','好官堪底用，厚祿竟如何。',48,'全唐诗/poet.song.165000.json','["好官堪底用，厚祿竟如何。", "詩可傳家集，名能繼世科。", "流風親黨競，餘慶子孫多。", "挽送歸無策，凄凉謾擬歌。"]'),
('80d1cb9b-6c2b-47d6-8416-ffbf9360ea12','挽周德友','趙蕃','宋','宋诗','song-poetry','','[]','不作玉堂仙，猶宜入道山。',48,'全唐诗/poet.song.165000.json','["不作玉堂仙，猶宜入道山。", "予才無乃厚，賦命一何慳。", "此日騎鯨去，它年化鶴還。", "委疏仍嗣野，芳桂雜榛菅。"]'),
('2352a43d-c37b-4ad5-bc7e-ec00cf6540c1','挽趙路分善應三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','世俗紛爲僞，躬行率以誠。',48,'全唐诗/poet.song.165000.json','["世俗紛爲僞，躬行率以誠。", "拳拳將母念，侃侃友于情。", "濟物豈求報，得仁非近名。", "誰爲太史傳，獨行有宗英。"]'),
('893b2a08-8e7d-42b1-bbd9-afb0a5979c30','挽趙路分善應三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','公就專城養，我安陶令廬。',48,'全唐诗/poet.song.165000.json','["公就專城養，我安陶令廬。", "幾因州府入，得侍笑談餘。", "課誦列童稚，戚休詢里閭。", "高堂朝夕望，寧復象平居。"]'),
('4d4f12bf-34a8-4d83-a40d-db06980e3ab5','挽趙路分善應三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','惟我先君子，相於出自同。',48,'全唐诗/poet.song.165000.json','["惟我先君子，相於出自同。", "年推大父行，議篤古人風。", "薄宦曾憐我，經行阻見公。", "訃聞仍葬日，慟哭匪途窮。"]'),
('f9232539-09ae-4680-81ae-bfe9c0ca40b0','挽游迪功','趙蕃','宋','宋诗','song-poetry','','[]','通學元分族，淵源信有餘。',48,'全唐诗/poet.song.165000.json','["通學元分族，淵源信有餘。", "二龍名屢貢，一老慶懸車。", "義利過庭訓，興哀迂叟書。", "他時家國事，蘄不負幽墟。"]'),
('9cae6d8d-87ba-470f-8e59-f5a210e2a612','挽曾達臣二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','邱壑豈遺物，市朝寧汙塵。',48,'全唐诗/poet.song.165000.json','["邱壑豈遺物，市朝寧汙塵。", "士當明大節，天下棄斯民。", "玉笥遊仙夢，浮雲閲世身。", "襄陽獨耆舊，他國顧無人。"]'),
('a21cabc1-5df1-4a14-8f78-7a08451f39fa','挽曾達臣二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','江右曾爲氏，南豐與贛州。',48,'全唐诗/poet.song.165000.json','["江右曾爲氏，南豐與贛州。", "推其本儒素，夫豈異源流。", "邇日過遺宅，有逢皆好脩。", "公侯生積善，天道非悠悠。"]'),
('051aa5c8-9bef-439d-afe6-a5c6b8090950','謁趙文鼎墓','趙蕃','宋','宋诗','song-poetry','','[]','君卧青山久，余今白髮新。',48,'全唐诗/poet.song.165000.json','["君卧青山久，余今白髮新。", "秋風對摇落，舊事入悲辛。", "此世寧長世，吾身豈久身。", "蕭蕭聞鶴夜，耿耿待鷄晨。"]'),
('7c979391-ffa9-4235-9952-fc37ee0f04d3','同方景嚴謁介菴墓','趙蕃','宋','宋诗','song-poetry','','[]','又過餘干縣，來瞻馬鬣墳。',48,'全唐诗/poet.song.165000.json','["又過餘干縣，來瞻馬鬣墳。", "侯芭今白首，李漢舊多聞。", "采若溪頭屋，騎鯨海上雲。", "生存零落句，三復涕紛紛。"]'),
('d97d5f28-9606-435e-b821-16036d8f61bb','樂南金秀才求其先處士君挽詩追作','趙蕃','宋','宋诗','song-poetry','','[]','此邦來已晚，人物欠冰清。',48,'全唐诗/poet.song.165000.json','["此邦來已晚，人物欠冰清。", "要摭平生實，聊徵月旦評。", "有兒真不朽，求志得知名。", "更欲求吾語，吾言曷重輕。"]'),
('5c4ef9a9-e0d1-4684-8820-228450d1c669','聞鄭仲仁訃','趙蕃','宋','宋诗','song-poetry','','[]','未快沉冤雪，俄驚東逝波。',48,'全唐诗/poet.song.165000.json','["未快沉冤雪，俄驚東逝波。", "平生萬卷讀，遺句百篇多。", "盛德今如此，天心果若何。", "青山忍回首，南望鬰嵯峨。"]'),
('adca51b3-f72a-4d3b-9682-afc83e87b43e','挽李舒州二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','忽報舒州逝，深同海內傷。',48,'全唐诗/poet.song.165000.json','["忽報舒州逝，深同海內傷。", "平泉無草木，北海漫文章。", "要作人琴歎，空懷道路長。", "臨風爲之慟，髮色變蒼蒼。"]'),
('cc96236f-1bef-4532-8eb3-5b64c449b83f','挽李舒州二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','一跌竟不起，兩州空復更。',48,'全唐诗/poet.song.165000.json','["一跌竟不起，兩州空復更。", "臺綱元振舉，物論甚分明。", "遂絕朝天騎，空傳跨海鯨。", "遥知流涕者，豈但一門生。"]'),
('9b9b9958-e6f1-473c-88d4-bfa7edc8f029','挽曾仲躬侍郎三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','昔者嘉禾郡，曾容謁長公。',48,'全唐诗/poet.song.165000.json','["昔者嘉禾郡，曾容謁長公。", "已焉地官宅，還獲見今翁。", "識面雖先後，陳詩匪異同。", "如何一再慟，祇向十年中。"]'),
('d47c1f50-9dad-4b68-b209-0cfca6725419','挽曾仲躬侍郎三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','政報朱轓起，旋驚丹旐歸。',48,'全唐诗/poet.song.165000.json','["政報朱轓起，旋驚丹旐歸。", "死生何忽忽，聞見悉依依。", "獻納名元在，吟哦事已非。", "清風端可繼，黄髮獨成違。"]'),
('45861ab7-1af9-4a52-a3d0-e1efc2c39ab1','挽曾仲躬侍郎三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','好在茶青竹，青青十百竿。',48,'全唐诗/poet.song.165000.json','["好在茶青竹，青青十百竿。", "風煙飽持護，鳥雀靜嘲讙。", "父子當年趣，聲名後代看。", "興懷非一事，愁絕更思韓。"]'),
('135e3450-21c9-467f-8e84-91eb7331210e','挽南澗先生三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','唐室文公裔，國朝桐樹家。',48,'全唐诗/poet.song.165000.json','["唐室文公裔，國朝桐樹家。", "學探和靜藴，文嗣一門華。", "尚擬咨黄髮，居成後白麻。", "公身寧有憾，物論自興嗟。"]'),
('e5aff717-b74a-42be-a6a1-e12424496efc','挽南澗先生三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','曾呂兼晁鄭，吾州夙所尊。',48,'全唐诗/poet.song.165000.json','["曾呂兼晁鄭，吾州夙所尊。", "流風嗟日遠，耆舊頼公存。", "見必詢詩卷，聞仍置酒樽。", "從今入州府，寂寞向誰門。"]'),
('8f99b6c0-80b3-4502-a352-c7ff8607d1fe','挽南澗先生三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','寂寞溪南路，於今忍重經。',48,'全唐诗/poet.song.165000.json','["寂寞溪南路，於今忍重經。", "東來待樽俎，南去哭丹青。", "四裔傳碑版，誰人作誌銘。", "屏山空矗矗，澗水暗泠泠。"]'),
('a01b8ae2-1015-4ab0-9145-86e84feadd61','初五日呈潘提舉時禱雨應而未洽','趙蕃','宋','宋诗','song-poetry','','[]','潦退旱隨至，吏憂民足傷。',168,'全唐诗/poet.song.165000.json','["潦退旱隨至，吏憂民足傷。", "陂塘待天雨，饘粥仰官倉。", "事勢胡能久，收成亟所望。", "關心厪漢節，用意格穹蒼。", "忽已雲霓合，兼之雷電將。", "驟來能點點，快落遂浪浪。", "未復田疇綠，纔蘇菜隴黄。", "粗能寬閔閔，聊且慰皇皇。", "末世耽饕佛，前聞戒暴尫。", "于公明孝婦，卜式訟弘羊。", "是可資邦本，寧唯致歲穰。", "公行有餘力，我句漫斯狂。", "半載官離次，欲歸行絕糧。", "何當荷簑笠，及此濟江湘。"]'),
('3bffd7ac-71f3-4ae8-bab8-f26295ca55b6','季蕭兄三貺詩且辱出示陵陽墨帖敢次韻一首爲謝','趙蕃','宋','宋诗','song-poetry','','[]','中朝當極治，人物近臯夔。',96,'全唐诗/poet.song.165000.json','["中朝當極治，人物近臯夔。", "南渡更衰亂，諸賢困逸遺。", "舍人名最早，白首但論思。", "尚喜詩傳派，于今學有涯。", "居然老成獨，異彼俗書姿。", "明眼逢吾子，掀髯話昔時。", "端能繼蕪累，所見匪狐疑。", "愧我安能友，酬篇只韻隨。"]'),
('34e7bc00-ba39-42ab-a40a-54a31615f51a','寄王謙仲周子充丈','趙蕃','宋','宋诗','song-poetry','','[]','吳蜀三分地，沅湘合水流。',240,'全唐诗/poet.song.165000.json','["吳蜀三分地，沅湘合水流。", "魚鰕今島嶼，蘭茝舊汀洲。", "逾月雨連晝，莫春風送秋。", "濕桑蠶餓死，壞種穀漂浮。", "弊屋無乾處，吁嗟幾日休。", "事多徵放逐，文欲號窮愁。", "懼禍初求免，茲行重失謀。", "官曹待符檄，食事指衣裘。", "淹速空占服，行藏漫倚樓。", "生涯縱草草，行路勝悠悠。", "弟妹懷天末，夢魂栖浪頭。", "何當得散號，從此具歸舟。", "特達非無仗，迍邅自過憂。", "禁庭敦宿契，樞府記鄉州。", "幾遇長安使，頻蒙禮翰投。", "雖狐懸釜煮，且益破囊收。", "憂禹思由溺，阿衡任內溝。", "豈伊儕子弟，而俾墮拘囚。", "霄漢瞻歸雁，波濤羨沒鷗。", "懷哉上南斗，去矣事西疇。"]'),
('c04e64ad-e009-413a-aa1d-0b1a0c6e9420','雨後','趙蕃','宋','宋诗','song-poetry','','[]','畏暑常疑病，逢凉還作詩。',96,'全唐诗/poet.song.165000.json','["畏暑常疑病，逢凉還作詩。", "岸巾看鏡懶，步履過廊遲。", "草樹消陳意，江山發令姿。", "裴徊如自得，徙倚竟何爲。", "厚祿書多斷，長貧志未移。", "無官带難緩，有竹俗能醫。", "不遇徒成賦，歸來亦漫辭。", "行藏隨所遇，造物豈無欺。"]'),
('2cfac79f-39f4-45d4-bfb8-cc91a39b048b','呈莫大猷令','趙蕃','宋','宋诗','song-poetry','','[]','入境能知政，昔聞今信然。',120,'全唐诗/poet.song.165000.json','["入境能知政，昔聞今信然。", "吾行萬安道，頗識令君賢。", "阡陌東西隔，人家遠近連。", "鍼青秧出水，穗長麥摇煙。", "犬吠稀逢客，牛耕不廢鞭。", "幽啼催穀布，午霽起蠶眠。", "檄罷追呼擾，民爭賦入先。", "太平真有象，循吏可無前。", "徑欲捐五斗，從之受一廛。", "經行嗟阻免，少日待回船。"]'),
('8e589a36-6f1c-4459-9753-8bcf1ec83ed6','歸途','趙蕃','宋','宋诗','song-poetry','','[]','招要非故約，談笑偶然期。',84,'全唐诗/poet.song.165000.json','["招要非故約，談笑偶然期。", "假日寧憂夜，徐行不用馳。", "吾曹欣窈窕，童騎苦逶迤。", "罷酌餘樽酒，催成未了詩。", "事雖同栗里，宿乃異西枝。", "雨合泉如瀑，嵐昏石似螭。", "茲遊蘄可再，約友更携兒。"]'),
('aab04d44-70ba-48ae-a792-de53f9c3572b','贈嚴黎二師','趙蕃','宋','宋诗','song-poetry','','[]','往者聞三益，今焉欠一夔。',96,'全唐诗/poet.song.165000.json','["往者聞三益，今焉欠一夔。", "寄詩曾併達，得報乃相遺。", "自說斯人死，尤懷一見思。", "高樓雖物外，好句必天涯。", "渺渺煙霞趣，蕭蕭蔬筍姿。", "徧參真已悟，換骨久其時。", "以彼大成就，而余深惑疑。", "刀圭如乞與，瓶錫詎難隨。"]'),
('195f170f-7afa-481d-b7b1-ccaf57b7e60f','讀舊詩作','趙蕃','宋','宋诗','song-poetry','','[]','長日胡爲度，繙囊閲舊詩。',96,'全唐诗/poet.song.165000.json','["長日胡爲度，繙囊閲舊詩。", "渭南雖乃祖，脩水是吾師。", "論自唐虞遠，名繇屈宋垂。", "相傳均一體，所得亂他岐。", "智鑿空奇字，天成在達辭。", "江山真末助，學問本深基。", "性癖端渠似，窮工殆我欺。", "誰能釣時譽，聊以慰朝饑。"]'),
('cedb3c7c-3752-4c8f-a404-100501e2a3b1','使君以十月上休日燕通判教授縣令錄參沅陵貴溪兩尉曹蕃亦與焉坐間出示宋莒公草書劉賓客詩圖李西臺呂東萊朱希真趙忠簡詩帖蕃賦詩十二韻以紀其事','趙蕃','宋','宋诗','song-poetry','','[]','假日黄堂燕，窮冬白晝長。',144,'全唐诗/poet.song.165000.json','["假日黄堂燕，窮冬白晝長。", "風流話前哲，翰墨出珍藏。", "莒國龍蛇字，西臺錦繡章。", "東萊先理致，朱老繼顛狂。", "最後吾宗帖，深於往事傷。", "污泥躍鰍鱓，大藪暴豺狼。", "薄暮仍添火，終筵更益觴。", "時雖當歲廩，氣乃返春陽。", "此固公爲德，寧云勢所當。", "廣文忘獨冷，半刺喜翱翔。", "四士俱才茂，一夫惟鬢霜。", "驂鸞看霄漢，買犢自耕桑。"]'),
('3e4eda46-f490-4205-b634-727b2751b3d6','謝張帥','趙蕃','宋','宋诗','song-poetry','','[]','試仰元戎貴，還瞻簿領卑。',192,'全唐诗/poet.song.165000.json','["試仰元戎貴，還瞻簿領卑。", "居間凡幾級，其勢可懸知。", "屢進黄堂拜，夙蒙青眼期。", "筵華紛饜飫，飲劇聽淋漓。", "既納違離謁，并頒道路資。", "間令叩齋閣，禮謝歷階墀。", "披豁忘名位，高深詎測窺。", "憂人多語政，餘事亦論詩。", "似欲徵凡作，何勝枉譽辭。", "更成湖上集，仍厠幕中奇。", "七字昔靈鷲，吾言今總持。", "流傳久已困，收收尚無遺。", "自省才惟薄，難堪德過儀。", "受之增踧踖，見者亦驚疑。", "暫爾休行役，於焉紀謝私。", "釣竿如可把，懸榻定除絲。"]'),
('2867f092-3ba6-4627-bcd5-eafec710dc2b','呈王侍郎昆仲二首  其一','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','先契今餘幾，交情不易論。',96,'全唐诗/poet.song.165000.json','["先契今餘幾，交情不易論。", "疇能逾薄俗，未肯棄衰門。", "慨念我伯仲，仰懷公弟昆。", "自知真瓦礫，那得並璵璠。", "誰謂長江遠，茲來匹馬奔。", "匪因窮附達，政以曲能敦。", "遺愛凄其久，高風凜若存。", "青雲看星聚，白髮對鴒原。"]'),
('96dfdcc2-f7d4-4064-98a5-b86662332a61','呈王侍郎昆仲二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','往未瞻烏府，先曾涉杏壇。',96,'全唐诗/poet.song.165000.json','["往未瞻烏府，先曾涉杏壇。", "予詩厪和答，貽教異暄寒。", "名位元相絕，知聞共駭觀。", "干霄峙松柏，流水會波瀾。", "應念登門舊，幾嗟行路難。", "蒸湘方渺渺，淮楚忘曼曼。", "既見得良慰，語離還浩歎。", "深思盡心曲，直覺欠豪端。"]'),
('1fe982b4-1866-4103-ae44-b44ffb36e66c','沈沅陵生日','趙蕃','宋','宋诗','song-poetry','','[]','十載郊居賦，當年蠟屐遊。',72,'全唐诗/poet.song.165000.json','["十載郊居賦，當年蠟屐遊。", "江山元好在，人物繼風流。", "奏牘頻能上，絃歌特暫留。", "白雲寬志養，黄紙拜天休。", "先契仍僚契，賡酬復獻酬。", "懸弧頌初度，橫鶚看清流。"]'),
('d15bab29-f06f-4380-ab3b-ec9f3a2e32d7','寄成父','趙蕃','宋','宋诗','song-poetry','','[]','屢約過茅舍，終成覓順舟。',120,'全唐诗/poet.song.165000.json','["屢約過茅舍，終成覓順舟。", "書來勤問訊，病去苦淹留。", "邂逅行人往，丁寧葯物求。", "那知空悵望，直恐遂沈浮。", "籬菊猶青蕊，鬢毛非黑頭。", "平生愛此節，今歲祇空酬。", "度日渾無頼，期君得散憂。", "柴車夙須辦，草徑掃令幽。", "豈乏登臨處，堪爲耳目謀。", "躋攀無脚力，夢寐想神遊。"]'),
('44f5293a-dd47-455a-b02e-85c8d6023ded','寄贈曾裘父兼呈嚴黎二師','趙蕃','宋','宋诗','song-poetry','','[]','憶昨初南渡，吾家住信州。',192,'全唐诗/poet.song.165000.json','["憶昨初南渡，吾家住信州。", "樞庭嘗牧守，詞掖舊淹留。", "生世夫何晚，斯人不易求。", "風流付篇翰，零落卧山邱。", "尚友當論世，如公實並遊。", "近功稱共學，爲僞說橫流。", "白首無愆素，清名所得優。", "百年安甕牖，萬里罷浮遊。", "太守尊徐孺，鄉人慕少游。", "成蹊自桃李，有臭別薰蕕。", "久矣聞風義，因茲速置郵。", "碧雲增悵望，石鼎怕冥搜。", "王謝池臺古，嚴黎鐘磬幽。", "林園小摇落，巖壑細雕鎪。", "豈曰忘徵逐，懷哉困阻脩。", "駏蛩終有合，鍼石詎難收。"]'),
('958c2b3c-f82f-4bd9-a9dc-a59d230ac657','用韓文公送鄭尚書韻寄雷朝宗兼屬歐陽全真','趙蕃','宋','宋诗','song-poetry','','[]','莽莽湖中客，悠悠月下杯。',72,'全唐诗/poet.song.165000.json','["莽莽湖中客，悠悠月下杯。", "飛騰南海士，斷絕尺書開。", "三命今爲牧，傳聞祝以來。", "貪泉姑著詠，驛使且催迴。", "賓客有文士，登臨仍古臺。", "唱酬須寫寄，屬和恐非才。"]'),
('cac8af06-1cfd-4bf7-828b-d3cd53ff9fd2','寄黄子耕','趙蕃','宋','宋诗','song-poetry','','[]','野寺已黄昏，高軒辱過門。',120,'全唐诗/poet.song.165000.json','["野寺已黄昏，高軒辱過門。", "交遊夫豈乏，情義獨能敦。", "我已家聲愧，君今風氣存。", "一官何未試，多雞亦成屯。", "詩本吾家事，經從達者論。", "明知有傳受，未易測淵源。", "近訪湖邊宅，猶餘漲水痕。", "如聞江上郡，欲覓隠居園。", "邂逅空題句，飄零難具言。", "折梅無以贈，三嗅鬢霜繁。"]'),
('68714860-8693-4797-9370-725afd973808','寄程可久丈','趙蕃','宋','宋诗','song-poetry','','[]','聞道沙隨老，遂爲安國居。',96,'全唐诗/poet.song.165000.json','["聞道沙隨老，遂爲安國居。", "逢人難問似，近况復何如。", "此士猶松徑，何人在石渠。", "儒林有韓孟，待詔自嚴徐。", "別去常勞夢，新來更欠書。", "久知腰倦折，懸想病都除。", "番國吾州近，冰溪一水餘。", "秋風期命駕，春雨政携鋤。"]'),
('f6259a91-14f2-4e3c-8ff7-1e7767ea602d','送藍吉州','趙蕃','宋','宋诗','song-poetry','','[]','前歲公開府，鄰疆我適移。',168,'全唐诗/poet.song.165000.json','["前歲公開府，鄰疆我適移。", "山坳深遣戍，齋閣遠投詩。", "去國哀王粲，逢人說項斯。", "春秋其我罪，觀過可仁知。", "流轉今初定，保持端自誰。", "筆難窮記牘，禮欲簉賓墀。", "累日方求棹，傳聞遽解龜。", "只云那有是，及此信無疑。", "春事崢嶸際，農工勸相時。", "吾曹一身計，父母百年思。", "鴈渚新浮綠，楊堤亦褭絲。", "茲時繫船地，異日寄書期。", "學道安時順，餘寒近酒宜。", "臨分意無盡，公爾豈其私。"]'),
('eae02da3-c907-4519-ae4a-f27acc7c4544','寄李處州','趙蕃','宋','宋诗','song-poetry','','[]','自入湖南路，驅車得屢停。',96,'全唐诗/poet.song.165000.json','["自入湖南路，驅車得屢停。", "流傳雖有句，次舍或無亭。", "嶮絕猶云未，艱危不易聽。", "真宜太白醉，未信屈原醒。", "我去方蠻府，公歸合漢庭。", "願言均沛雨，尚想獨當霆。", "白雪故寡和，黄麻須六經。", "詔除期不晚，得以慰飄零。"]'),
('b41786f0-65fa-4856-8d9d-5ecec380b95a','送江憲移京西漕','趙蕃','宋','宋诗','song-poetry','','[]','流轉江湖後，飄零歲月餘。',96,'全唐诗/poet.song.165000.json','["流轉江湖後，飄零歲月餘。", "僅能瞻玉節，忽已報除書。", "借寇情雖切，依劉計已疎。", "二天元不遠，大厦豈殊居。", "使者澄清事，明廷獻納攄。", "循行聊偃薄，朝覲勿躊躇。", "處士獨苦節，清江空舊魚。", "昔聞曾誦此，今日定何如。"]'),
('3138b5d4-31a9-44cf-bdca-ab4223154b9e','呈李和卿法曹','趙蕃','宋','宋诗','song-poetry','','[]','使者趨朝後，參軍捧檄初。',120,'全唐诗/poet.song.165000.json','["使者趨朝後，參軍捧檄初。", "重湖來至險，兩月聽閑居。", "豈是拘形役，真成畏簡書。", "祠官請已再，郵傳報何疏。", "風雨工欺我，江山頼起予。", "芻薪頻益檟，幼稚苦無儲。", "鑿枘寧防此，冠緌信有諸。", "何心事刀筆，但覺愧樵漁。", "觀水知除滿，看雲見卷舒。", "故人方幕府，見謂合何如。"]'),
('ba9e4b71-4494-4f9b-85ed-9c39e80e5e7c','問候周子充丈','趙蕃','宋','宋诗','song-poetry','','[]','抗疏有歷載，宣麻茲一朝。',96,'全唐诗/poet.song.165000.json','["抗疏有歷載，宣麻茲一朝。", "漕河讙啟閘，江水待乘潮。", "豈有夔龍輩，而從鷗鷺招。", "定應聊偃薄，寧事久逍遥。", "世既仍才美，居還絕吝驕。", "齗齗自讒慝，曈曈本光昭。", "往者資先覺，今焉倚後彫。", "公如再廊廟，我亦遂簞瓢。"]'),
('2b565628-9517-4a63-8a4d-844ec3de618a','寄誠齋先生','趙蕃','宋','宋诗','song-poetry','','[]','邇日使嶺表，歷論無此賢。',120,'全唐诗/poet.song.165000.json','["邇日使嶺表，歷論無此賢。", "誰歟記南海，久矣賦貪泉。", "已上蓬山直，還居吏部銓。", "省郎遲豈恨，宣室夜重前。", "掌制宜鴻筆，談經合細旃。", "茲爲重儒術，何止用詩仙。", "四海推鳴鳳，孤生悵跕鳶。", "長安近抵日，蜀道遠如天。", "裋褐春風倚，歸心夜雨懸。", "十年期撰屨，斗食政窮邊。"]'),
('d8bebead-fbee-46b5-8b57-1c9aae716bb2','寄劉子澄先生','趙蕃','宋','宋诗','song-poetry','','[]','春雨寒猶積，春園木又榮。',96,'全唐诗/poet.song.165000.json','["春雨寒猶積，春園木又榮。", "武昌聞別駕，生米見題名。", "安否逢人問，書題闕便行。", "周圍懷細履，陶酒憶徐傾。", "會合知何日，羈棲尚此生。", "向來猶楚越，今日遂蠻荆。", "妻子饑寒累，交朋時勢情。", "未應終薄祿，當復事深耕。"]'),
('2f1fc119-d1ba-444d-ab03-0c0286447d80','魏辰州生日','趙蕃','宋','宋诗','song-poetry','','[]','昔在思文獻，今焉見典刑。',120,'全唐诗/poet.song.165000.json','["昔在思文獻，今焉見典刑。", "玉良中有韞，陂廣外無形。", "毓秀舒淮水，飛聲出漢廷。", "恩雖予符左，官來繼氈青。", "諭俗書陰德，傳家刻孝經。", "庶幾相感格，于以稱丁寧。", "萬象皆春氣，斯人乃德星。", "否臧斯列上，耳目豈途聽。", "松茂寒仍秀，蘭幽遠更馨。", "不惟歸盛美，併用祝脩齡。"]'),
('4123ff05-3c28-489c-9522-151a8bd76245','何叔信生日','趙蕃','宋','宋诗','song-poetry','','[]','既自科名就，方勤問學爲。',72,'全唐诗/poet.song.165000.json','["既自科名就，方勤問學爲。", "一官寧恨晚，萬里此其基。", "晁魏通家舊，沅湘識面遲。", "高懷每傾倒，勝日共追隨。", "要擬維熊什，慚無黄絹辭。", "迺翁松柏茂，驥子渥洼姿。"]'),
('d56372df-2b77-40ef-9d4d-69cb772f0cb6','賀吳仲權召試館職','趙蕃','宋','宋诗','song-poetry','','[]','重爲湖外別，難寄日邊書。',96,'全唐诗/poet.song.165000.json','["重爲湖外別，難寄日邊書。", "詎敢疏風義，欣聞有詔除。", "圖書天祿閣，文陳玉堂廬。", "祕記資讐校，人材務養儲。", "端如策晁董，不比召嚴徐。", "惟我高曾世，曾仍位序居。", "永懷元祐始，絕歎建炎初。", "衰謝今如此，淒涼實在予。"]'),
('de6c69d7-26a2-49fa-9d18-7f1433b22d0f','蕃欲爲辰陽之行適寺簿先生以使事來武陵既獲再侍又蒙俯用近者寄上鄙韻賜之輒復次韻敘別併呈子實百六丈','趙蕃','宋','宋诗','song-poetry','','[]','歲事有豐儉，民情關悴榮。',96,'全唐诗/poet.song.165000.json','["歲事有豐儉，民情關悴榮。", "蓄儲雖具數，郡邑頗空名。", "爲國深存慮，勞公作是行。", "違離頻領引，邂逅復心傾。", "有志空前躅，無成愧此生。", "匆匆還進棹，草草僅班荆。", "對雨塤箎句，看雲手足情。", "千林喚歸去，一雨勸催耕。"]'),
('07e9e6dc-3293-4268-849c-47965ce984a4','張次律見招欲同一詩人飲既見乃新定遠令劉旦元贊也詰朝與之別別後寄之併寄次律','趙蕃','宋','宋诗','song-poetry','','[]','張侯呼我飲，云欲醉詩人。',120,'全唐诗/poet.song.165000.json','["張侯呼我飲，云欲醉詩人。", "我媿野無格，君能高出塵。", "句中真有畫，筆下信如神。", "不待平生識，由來一語親。", "衆皆嫌坦率，意獨取天真。", "頗恨匆匆別，殊乖款款陳。", "王官欣舊轍，蠻語昧初詢。", "起此窮途哭，端非傾蓋新。", "度江風吼夕，發軔雪飛晨。", "行路嗟離闊，題詩報苦辛。"]'),
('52720514-46e0-49e5-a7ab-c1877dc45a34','詠筍用昌黎韻','趙蕃','宋','宋诗','song-poetry','','[]','山居何所用，種竹並楹軒。',288,'全唐诗/poet.song.165000.json','["山居何所用，種竹並楹軒。", "聽雨宵忘寐，摇風日破煩。", "春來仍引蔓，雨後競添孫。", "迸砌思移石，妨池欲廢盆。", "隄防虞採掘，檢束費晨昏。", "自是林深茂，非因地獨溫。", "有朋如角立，布陣似爭騫。", "戢戢株雖短，駸駸勢已存。", "却行纔避碍，逆曳遂難垠。", "婢喜頻留步，兒欣屢發言。", "縱橫從可目，散漫孰尋根。", "蟻敗須攻穴，羊侵要補藩。", "驟驚疑瓦合，還訝若車奔。", "豈害偏藏徑，何妨便滿園。", "擁培規我力，振拔果誰恩。", "坐見身長塹，行看籜蔽垣。", "苔俱滋濕暈，蘭與王芳蓀。", "未肯低前輩，終當及次番。", "萬杉真浪說，千橘更何論。", "蹇傲冬方見，陰森夏乃繁。", "務令收晚節，忍把助朝餐。", "此日聊成隠，它年定改門。", "韓公留句偉，侯喜漫名掀。", "韻險言無麗，搜窮筆殆髠。"]'),
('2cf39be4-f0f4-48fa-aa32-891d47e95cff','謝知縣丈相率汎舟且訪寓舍併呈子暢兄','趙蕃','宋','宋诗','song-poetry','','[]','父老延見後，詔書宣布餘。',120,'全唐诗/poet.song.165000.json','["父老延見後，詔書宣布餘。", "臨流具舟檝，散步輟車輿。", "天氣清而朗，物情和且舒。", "聊爲曲江飲，報此暮春初。", "人物玉相倚，山川畫不如。", "要窮詩律細，寧遣酒行疏。", "既益園官菜，亦留溪友魚。", "風期須我輩，樂事見群居。", "欲去鷺前導，重來犬入裾。", "還迂長者轍，薄憇野人廬。"]'),
('7f252f12-1266-49b5-9b66-4e047b5d4e5f','既別文顯兄弟晚宿日光寺書懷寄之','趙蕃','宋','宋诗','song-poetry','','[]','別君當以詩，此物不充饑。',108,'全唐诗/poet.song.165000.json','["別君當以詩，此物不充饑。", "二事交爲病，吾曹均坐茲。", "欲談殊爛熳，趣去苦凄悲。", "晚宿投幽寺，翻思赴野期。", "風燈半明滅，雨葉亂紛披。", "安石畏作別，淵明當語離。", "萍蓬居靡定，燥濕志難移。", "問隠俱携弟，躬耕皆有兒。", "懷哉衡泌樂，可以共棲遲。"]'),
('41ac7dc8-b769-416e-b7ad-33b93b9ccaa3','口占','趙蕃','宋','宋诗','song-poetry','','[]','稍不作山行，山行眼界生。',60,'全唐诗/poet.song.165000.json','["稍不作山行，山行眼界生。", "晚禾場已築，宿麥地初耕。", "丱角收牛策，青裙負水甖。", "自安如有道，所樂是無營。", "我亦懷茲願，胡爲計莫成。"]'),
('c142af0c-ab13-4fe2-b744-6b98be668639','挽向參議','趙蕃','宋','宋诗','song-poetry','','[]','丞相遺家法，雲仍多耐官。',72,'全唐诗/poet.song.165000.json','["丞相遺家法，雲仍多耐官。", "著鞭期一躍，失路困千盤。", "竟死諸侯客，保留神武冠。", "梟鸞終異志，松柏遂孤蟠。", "前輩今無幾，臨風特屢歎。", "臧孫宜有後，龐老遺之安。"]'),
('86f787a3-87ea-45f0-a208-776a635fcb98','立春日呈彥博并帖審知','趙蕃','宋','宋诗','song-poetry','','[]','憶昔少陵身在蜀，遇春曾憶兩京梅。',64,'全唐诗/poet.song.165000.json','["憶昔少陵身在蜀，遇春曾憶兩京梅。", "我今久隔鄉關念，病後徒驚節物催。", "不見過門長者轍，可憐到手故人杯。", "長亭與想東征路，柳色青青拂面來。"]'),
('04983dc7-1f9f-4e47-be1c-4eae8c265060','晚春呈全真','趙蕃','宋','宋诗','song-poetry','','[]','九十日春餘十日，庭陰已作夏扶疎。',64,'全唐诗/poet.song.165000.json','["九十日春餘十日，庭陰已作夏扶疎。", "桃花浪暖且振擑，燕子日長空廢書。", "故人行行重作別，倦雲悠悠思定居。", "及此莫孤朝與暮，易勝書禮問何如。"]'),
('7fbf45db-6917-4037-bf70-1c34283c4036','周愚卿出示楊謹仲墨帖','趙蕃','宋','宋诗','song-poetry','','[]','成都舊日揚雄宅，今在清江鷗鷺洲。',64,'全唐诗/poet.song.165000.json','["成都舊日揚雄宅，今在清江鷗鷺洲。", "頗念書題成間闊，忽逢翰墨見風流。", "薌林草木年仍故，此老詩篇晚更遒。", "官事安能久覊我，何時載子以扁舟。"]'),
('d20dc59d-1a66-4d60-85f8-8341b07af572','建康回使寄范帥從求詩帖許而未至','趙蕃','宋','宋诗','song-poetry','','[]','作意投公好賦詩，無鹽竟自突西施。',64,'全唐诗/poet.song.165000.json','["作意投公好賦詩，無鹽竟自突西施。", "生憎逼仄饑寒態，不盡從容質問時。", "已辦過江還敗興，要期重謁愧無辭。", "夜光明月雖防暗，白日青天不碍知。"]'),
('5928b10f-366d-489c-8ec4-8bc817b57dcc','聞子耕司戶兄非一日昨見墨帖於中州又誦五言長篇於劉子澄許今茲乃遂識面輒題鄙句以敘區區','趙蕃','宋','宋诗','song-poetry','','[]','墨妙初看眼自明，誦詩還見五言城。',64,'全唐诗/poet.song.165000.json','["墨妙初看眼自明，誦詩還見五言城。", "不惟喜獲吾黨士，要是未忘山谷盟。", "我亦可憐耽句癖，君其勉力振家聲。", "祗今此道寒如水，莫以微官取重輕。"]'),
('d7213349-c42e-4ded-870b-0c29e80871a0','馬上讀子肅詩集并懷子進子儀','趙蕃','宋','宋诗','song-poetry','','[]','一雨初收更有凉，我時驅馬度危梁。',64,'全唐诗/poet.song.165000.json','["一雨初收更有凉，我時驅馬度危梁。", "溪山慣見少新意，詩句熟窺多舊行。", "不使高飛向台省，忍教微祿滯柴桑。", "難兄難弟俱奇士，寧愧諸洪出豫章。"]'),
('3fcaef28-ddf5-4f4b-ac93-4a7585033967','夜坐讀書有感示兒曹','趙蕃','宋','宋诗','song-poetry','','[]','昨夜秋風入短檠，試繙編簡似前生。',64,'全唐诗/poet.song.165000.json','["昨夜秋風入短檠，試繙編簡似前生。", "不求甚解慕名語，足記姓名嗤老兵。", "但得作詩窮有味，曷憂從宦久無成。", "汝曹未可還翁學，當念無田事筆耕。"]'),
('956bff8e-8b48-4ea4-9dc9-d8f2bff87dfb','伏讀時中胡公墓誌輒用澹菴省齋銘詩之韻從仲威昆仲求本','趙蕃','宋','宋诗','song-poetry','','[]','千年廉藺凜猶寒，豈似乞人誇豆簞。',64,'全唐诗/poet.song.165000.json','["千年廉藺凜猶寒，豈似乞人誇豆簞。", "經病漢儒顓學癖，義求秦火未燒殘。", "名章可愧功言立，門戶在君兄弟難。", "至寶獨完元自貴，用輕寧事雀空彈。"]'),
('41a6dfe6-0221-48e4-8053-cd55945796c6','曾耆英錄先提舉著述及屠龍禾譜與先世誌文見貺副以長句次韻爲謝','趙蕃','宋','宋诗','song-poetry','','[]','試用初如江發源，斯人欠使百其年。',64,'全唐诗/poet.song.165000.json','["試用初如江發源，斯人欠使百其年。", "有孫解保書如束，過我不嫌寒乏氈。", "郡守舊聞曾奏疏，鄉人今日有經筵。", "縱云錄後有前例，循吏藝文應並編。"]'),
('2c053ee8-f69e-4dcb-97a6-d86e7425db9c','曾耆英自太和携所錄謝民師觀妙詩文副以長句見惠次韻酬答','趙蕃','宋','宋诗','song-poetry','','[]','別時黄落問山風，見日清霜鳴啞鐘。',64,'全唐诗/poet.song.165000.json','["別時黄落問山風，見日清霜鳴啞鐘。", "二謝有詩皆可誦，七言兼與見傳宗。", "舉幡故異司隸救，右袒徒聞呂氏從。", "君獨凄凉能過我，逢迎敢作謬爲恭。"]'),
('f48284b1-1ee6-4ce7-977f-9d61a3e00ccb','張因叔尉曹借示贛陳丞擇之文編以長句還之','趙蕃','宋','宋诗','song-poetry','','[]','子昂高蹈固家風，詩到後山仍更工。',64,'全唐诗/poet.song.165000.json','["子昂高蹈固家風，詩到後山仍更工。", "何事棲遲猶五斗，向來推許漫諸公。", "平生但記逢人說，一洗真成凡馬空。", "今日宦遊得此士，知君不類溧陽窮。"]'),
('8bf754dc-1376-41ee-8b62-a42bbe661a2c','讀山谷文','趙蕃','宋','宋诗','song-poetry','','[]','深居度日渾亡頼，小役踰旬抑又疲。',64,'全唐诗/poet.song.165000.json','["深居度日渾亡頼，小役踰旬抑又疲。", "到處青山恃青眼，隨行黄卷有黄詩。", "少陵授受後千載，此老風流彼一時。", "衆作沛然雖莫禦，要云萬折必東之。"]'),
('468d8bc3-76b1-4047-b2e7-3dcd5fed10cf','通問贛州留尚書并寄三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','去冬曾作送行詩，豈料重臨歲甫移。',64,'全唐诗/poet.song.165000.json','["去冬曾作送行詩，豈料重臨歲甫移。", "盍遣德星均四海，願令竹馬快并兒。", "使君不獨符仍剖，刺史還聞節再持。", "吏治久安民則化，九重於此有深思。"]'),
('bf6c7506-6804-4ea6-8b9d-3389bd9e0aeb','通問贛州留尚書并寄三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','疇昔王門耻曳裾，每懷端拜獻公書。',64,'全唐诗/poet.song.165000.json','["疇昔王門耻曳裾，每懷端拜獻公書。", "簡編訖補遺忘後，餽贐分霑憂患餘。", "只信此心無改事，詎知彼譖欲何如。", "屬聞盛府重開幕，適此故山歸駕車。"]'),
('36b159b2-bdf5-4180-912d-5c2281cedc8d','通問贛州留尚書并寄三首  其三','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','陛下胡爲先一州，是公豈合久諸侯。',64,'全唐诗/poet.song.165000.json','["陛下胡爲先一州，是公豈合久諸侯。", "東江西江水且漲，南山北山春正浮。", "促席久思宣室問，都人願覩翰林遊。", "我家懷玉山之下，亦擬探奇謁道周。"]'),
('e30b5c33-b89d-48f5-9bf1-35293fb27366','賀周待制兼直學士院','趙蕃','宋','宋诗','song-poetry','','[]','重聞陸贄掌絲綸，可念公朝道必伸。',64,'全唐诗/poet.song.165000.json','["重聞陸贄掌絲綸，可念公朝道必伸。", "暫向玉堂還舊直，亟從鳳沼據通津。", "招來贊普邊疆肅，詔感山東德意新。", "誰謂文章財小技，計功端合畫麒麟。"]'),
('3c2ac56b-d564-46d6-bcf2-6f1b983de591','呈曾侍郎逮','趙蕃','宋','宋诗','song-poetry','','[]','思人幾作訪茶山，竹密如雲不敢刪。',64,'全唐诗/poet.song.165000.json','["思人幾作訪茶山，竹密如雲不敢刪。", "未覺風流成歲遠，政繇伯仲力追還。", "長公舊日曾一識，末路後來遭百艱。", "邂逅探囊得行記，贈公試遣略承顔。"]'),
('789574aa-cc98-4024-b046-de069aa20f92','贈蕭參議德藻二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','諸侯賓客湖南盛，東海蕭生漢帝知。',64,'全唐诗/poet.song.165000.json','["諸侯賓客湖南盛，東海蕭生漢帝知。", "前後相望真一揆，流傳况復有新詩。", "鄉來識面嗟無地，今日登門可自遲。", "未信千巖趣歸去，近傳新把峽州麾。"]'),
('50fd77c8-d0e9-4bd9-ae13-c14e49d5da56','贈蕭參議德藻二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','平生苕霅幾扁舟，意在斯人豈漫遊。',64,'全唐诗/poet.song.165000.json','["平生苕霅幾扁舟，意在斯人豈漫遊。", "聞道千巖有高隠，甚思一見苦無由。", "雖云葯石稍親近，未害煙霞廑攬收。", "况是交承我伯父，援茲論契許前不。"]'),
('ed127ee8-9ea7-40b7-aac2-937696c2300b','寄鄭祕校','趙蕃','宋','宋诗','song-poetry','','[]','吾邦豪傑未多聞，義薄雲天獨數君。',64,'全唐诗/poet.song.165000.json','["吾邦豪傑未多聞，義薄雲天獨數君。", "遇歉登倉真甚惠，當郊置驛信徒勤。", "目前米價未爲貴，我自囊空先有云。", "食粥敢言今數月，更憂無粥但羹芹。"]'),
('9a617953-76ed-4706-8019-5ab0ab060c79','聞宋伯潜李和卿孟養直有審察之命','趙蕃','宋','宋诗','song-poetry','','[]','柴門一閉動經旬，何許書來事得新。',64,'全唐诗/poet.song.165000.json','["柴門一閉動經旬，何許書來事得新。", "駱驛詔追三縣令，崢嶸名聳漢廷臣。", "浩然豈憶南山舊，太白寧歌泗水春。", "賦就梅花如肯寄，長安不乏少年人。"]'),
('25c124f3-e2eb-4f1e-a200-d382a479c330','觀賈元放書迹寄其弟季承','趙蕃','宋','宋诗','song-poetry','','[]','古寺荒凉客寓居，閉門百事付乘除。',64,'全唐诗/poet.song.165000.json','["古寺荒凉客寓居，閉門百事付乘除。", "學知定力貧非病，詩見新功樂有餘。", "化鶴已空今已矣，騎鯨何處問何如。", "追懷存沒傷零落，底事秋來音訊疏。"]'),
('ee19dd02-5e8f-4fc9-a2d0-e6d15835f93d','寄贈湯司諫二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','御史曾追慶曆唐，有孫還是紹興湯。',64,'全唐诗/poet.song.165000.json','["御史曾追慶曆唐，有孫還是紹興湯。", "絕知驥騄難羈絆，故遣松筠試雪霜。", "如許人才豈終棄，要之日月本何傷。", "鬰孤臺上蘇仙句，多載寥寥無和章。"]'),
('9067bcfb-1406-4530-b819-8aa44661a279','寄贈湯司諫二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','自聞寬法離新州，日日江頭數過舟。',64,'全唐诗/poet.song.165000.json','["自聞寬法離新州，日日江頭數過舟。", "學子尚知稱述作，君王寧不念謀猷。", "五車頗困十年讀，一見蘄勝萬戶侯。", "我亦東歸苦無日，待公行矣勿遲留。"]'),
('ef8cdb0d-fbe3-421a-a63e-1078059da7cf','贈楊左司三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','白下初逢使廣軒，始披雲霧見青天。',64,'全唐诗/poet.song.165000.json','["白下初逢使廣軒，始披雲霧見青天。", "黄花紅葉蒙深賞，白髮青衫又十年。", "舉室尚爲湖外客，一身還上浙江船。", "蓴羹鱸鱠雖佳矣，不是東歸重惘然。"]'),
('fb32582b-8251-49dd-b742-fbc2fb54e0e7','贈楊左司三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','先生文力早騫騰，今代詞人盡服膺。',64,'全唐诗/poet.song.165000.json','["先生文力早騫騰，今代詞人盡服膺。", "已見陳詩歌上壽，更須作頌紀中興。", "敢如杜集高岑比，尚媿韓門籍湜朋。", "政爾周流不知屆，况于朝夕遂師承。"]'),
('3c885f48-0734-48a7-b1b6-95a3b8e7bac7','贈楊左司三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','有來聞說上封章，造膝言之外敢昌。',64,'全唐诗/poet.song.165000.json','["有來聞說上封章，造膝言之外敢昌。", "但見詔除頻寵渥，是知明聖識忠良。", "都司萬事無不理，一語九州當致康。", "况此十年門下士，反從勾漏弔沉湘。"]'),
('91d3a26a-cd73-474d-bc46-db312d6ccc22','寄林運使三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','番禺城下牂牁水，亦復分流過此州。',64,'全唐诗/poet.song.165000.json','["番禺城下牂牁水，亦復分流過此州。", "使節長瞻萬里外，尺書忽到五溪頭。", "酸寒應念卑堪說，奇勝聊云舊所遊。", "嶺海滯公猶未召，蠻荒著我更何尤。"]'),
('50cfdc0f-9f68-4d3e-b976-e1be81f111af','寄林運使三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','門第違離又一冬，素書寥闊便艱通。',64,'全唐诗/poet.song.165000.json','["門第違離又一冬，素書寥闊便艱通。", "身隨回鴈辭湘水，官許騎馿看華峰。", "人笑半生躭落拓，自欣三徑著疏慵。", "顧慚囊粟無功受，勤動終年是老農。"]'),
('f7841af1-faed-492a-a11c-3541ff0ec766','寄林運使三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','憶昨登門誤取知，再焉猶復似當時。',64,'全唐诗/poet.song.165000.json','["憶昨登門誤取知，再焉猶復似當時。", "已容盡醉尊中酒，更辱頻詢別後詩。", "落落有懷那得寫，悠悠重見果何期。", "南山幸邇朝天路，準擬追隨竹馬兒。"]'),
('afd23373-3d5d-45ab-abfb-4d36e81873e7','寄曾運使','趙蕃','宋','宋诗','song-poetry','','[]','携詩十載舊登門，一見長思闕細論。',64,'全唐诗/poet.song.165000.json','["携詩十載舊登門，一見長思闕細論。", "豈憶猶蒙記名姓，故情仍許奉罍尊。", "臨分更俾傳家集，請事于今行嫡孫。", "儻有新聞幸無棄，素書無只報寒溫。"]'),
('e1c6af8f-e2d7-4ed5-84eb-cd5325877e30','別曾運使','趙蕃','宋','宋诗','song-poetry','','[]','鍾陵寂寞幾何年，公自茶山又一傳。',64,'全唐诗/poet.song.165000.json','["鍾陵寂寞幾何年，公自茶山又一傳。", "萬里未能攀老鶴，晚風那復聽鳴蟬。", "乖離每覺如思古，流轉何知復拜前。", "賸欲相從還索去，候門稚子望歸韉。"]'),
('51aa3628-7b1e-4b9b-a7d0-a0c147abc107','投徐運使','趙蕃','宋','宋诗','song-poetry','','[]','白社多年井逕荒，有孫還復以詩昌。',64,'全唐诗/poet.song.165000.json','["白社多年井逕荒，有孫還復以詩昌。", "此懷願識亦已久，茲日能來豈所望。", "萸後菊前霜錯落，地長家遠客凄凉。", "平生知己晦菴老，爲我談公遣座旁。"]'),
('2768f997-1c8b-4064-bf9b-58868c96242c','別徐運使','趙蕃','宋','宋诗','song-poetry','','[]','風聲富貴每多偏，造物于公獨俾全。',64,'全唐诗/poet.song.165000.json','["風聲富貴每多偏，造物于公獨俾全。", "笑我效顰忘露醜，不知學步返難前。", "侏儒自合奉囊粟，衛尉何曾直一錢。", "我地有饑能任耻，熟聞高義薄雲天。"]'),
('30c101c1-5085-465d-a5cf-8ba489bb38eb','程閣學知建寧府入對二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','日邊飛下詔黄新，大府潜藩屬老成。',64,'全唐诗/poet.song.165000.json','["日邊飛下詔黄新，大府潜藩屬老成。", "一代儒宗還北闕，十年法從對延英。", "從容定有回天力，咫尺重聞曳履聲。", "便覺兒童語音好，謝公今起慰蒼生。"]'),
('9bda20aa-daa2-4540-810e-2e4f3cfa8395','程閣學知建寧府入對二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','湖山十里芰荷香，穩送朝天一夜航。',64,'全唐诗/poet.song.165000.json','["湖山十里芰荷香，穩送朝天一夜航。", "前席固應思見賈，留行政不待徵黄。", "懸知筆下三千字，小試囊中一二方。", "自笑侯芭今白首，彈冠何敢企王陽。"]'),
('245448a3-133e-44ba-bc88-b254a5e49eaf','送周禮侍赴召','趙蕃','宋','宋诗','song-poetry','','[]','昨奉書題歲且更，每逢人士說先生。',64,'全唐诗/poet.song.165000.json','["昨奉書題歲且更，每逢人士說先生。", "名高正倚斯文在，身屈不妨吾道行。", "天以蒼生付安石，孰能三徑老淵明。", "自憐留落端何幸，得向溪城一送迎。"]'),
('b705d952-f180-4cc8-9ac9-2a1bcfdaeb25','送韓建寧赴召二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','頻向清時課郡功，履聲長憶未央宮。',64,'全唐诗/poet.song.165000.json','["頻向清時課郡功，履聲長憶未央宮。", "祇言治行稱黄覇，果見朝廷徵弱翁。", "簡注豈惟陛下聖，讙謠還見庶民同。", "孰云故國非喬木，賜第行看又植桐。"]'),
('9b76617f-d13f-42c2-92b6-ec7b8bcc8420','送韓建寧赴召二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','憶公典選繼昌黎，是我學人行卷時。',64,'全唐诗/poet.song.165000.json','["憶公典選繼昌黎，是我學人行卷時。", "香火奉祠雖觖望，簿書棲邑尚淹期。", "長年敢有飄零恨，末路欣逢陶冶私。", "自度才能不堪舉，直思求地勉寒饑。"]'),
('98d7e259-f79c-4ddc-8137-234f03eca74d','送吳提刑赴召三首  其一','趙蕃','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','擁節西來歲未更，提封畧已遍循行。',64,'全唐诗/poet.song.165000.json','["擁節西來歲未更，提封畧已遍循行。", "洞庭青草絕餘寇，沅水武谿俱力耕。", "勿漫繡衣閒直指，正應天下急澄清。", "治平已召吳公去，材秀何人是賈生。"]'),
('7105d0af-666a-4b39-8b80-7b1994365682','送吳提刑赴召三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','連朝欲作送公詩，以頌懸知孰愈規。',64,'全唐诗/poet.song.165000.json','["連朝欲作送公詩，以頌懸知孰愈規。", "萬事要當明本末，一身切莫計安危。", "老農不過除荑稗，良葯安能棄朮芝。", "勿謂常談便輕鄙，獻言端自戒新奇。"]'),
('7a2d63cd-7bcb-4714-9ce0-011b5d6bbd95','送吳提刑赴召三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','只道邊城獄訟稀，那知亦有造空爲。',64,'全唐诗/poet.song.165000.json','["只道邊城獄訟稀，那知亦有造空爲。", "不惟寬大難容止，正畏精明莫可欺。", "已矣榜敲成俗吏，懷哉香火奉湘祠。", "儻蒙一紙聞天奏，便是吹噓送上時。"]'),
('10e0a8a3-1c82-4333-a759-38e77186f6d1','送王饒州赴召','趙蕃','宋','宋诗','song-poetry','','[]','吾君日旰坐延英，寤寐得人成太平。',64,'全唐诗/poet.song.165000.json','["吾君日旰坐延英，寤寐得人成太平。", "常恐珍才在空谷，豈容舊德久專城。", "潁州便合爲丞相，渤海無庸拜水衡。", "今代吳公祇公是，自慚名謝洛陽生。"]'),
('9baab27b-c2a7-4b41-a421-026609a7c88d','送京運使赴召二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','南浦維舟初拜公，五谿隨牒限趨風。',64,'全唐诗/poet.song.165000.json','["南浦維舟初拜公，五谿隨牒限趨風。", "問途欲假移官見，傾聽讙聞召節東。", "不但朝陽徯鳴鳳，正思御史昔乘驄。", "我曹意見非黎庶，大庇要令天下同。"]'),
('33c6530e-eb46-4ae2-8852-9814ec2c6ef8','送京運使赴召二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','一官不恨落羈縻，正謂邊頭獄訟稀。',64,'全唐诗/poet.song.165000.json','["一官不恨落羈縻，正謂邊頭獄訟稀。", "但有膠膠還擾擾，略無是是與非非。", "詩書舊學渾忘却，夢寐衡祠放得歸。", "邂逅兩臺俱趣召，蓴鱸於此合知幾。"]'),
('dc476567-b74f-4aaa-8272-52c8f75f6eb6','代成父送趙信州移知台州','趙蕃','宋','宋诗','song-poetry','','[]','邦人初喜兩橋成，詔旨還傳易鎮榮。',64,'全唐诗/poet.song.165000.json','["邦人初喜兩橋成，詔旨還傳易鎮榮。", "千里溪山如有恨，一川風雨似增情。", "未應重畀臨凋郡，看即歸來侍邇英。", "平日空哦海山賦，便思懷謁問經行。"]'),
('5e2c893b-6f05-4bc1-963c-fe7b4712c89a','呈趙蘄州善扛','趙蕃','宋','宋诗','song-poetry','','[]','雨合園林水滿池，黄鸝無語鷺頻窺。',64,'全唐诗/poet.song.165000.json','["雨合園林水滿池，黄鸝無語鷺頻窺。", "哦吟終日大自好，黜陟與時殊不知。", "北海定欣真識面，阿連還喜伴成詩。", "自從諸老凋零後，此事于今更屬誰。"]'),
('36e3b0d4-8482-4598-b793-ece52c33b5e7','送張真州大經','趙蕃','宋','宋诗','song-poetry','','[]','渺渺春江綠水波，客中送客倍愁多。',64,'全唐诗/poet.song.165000.json','["渺渺春江綠水波，客中送客倍愁多。", "一麾出守輸公去，三徑就荒如我何。", "暫爲淮人符剖竹，即歸漢殿橐持荷。", "異時治狀稱優最，十萬疲羸蒙拊摩。"]'),
('8c54936c-b726-4995-93f3-2f1d10d1f85c','寄林信州','趙蕃','宋','宋诗','song-poetry','','[]','嶺近梅花開已多，水南梅事又如何。',64,'全唐诗/poet.song.165000.json','["嶺近梅花開已多，水南梅事又如何。", "使君假日曾遊否，客子臨風空屢哦。", "好士何妨勤下榻，豐年那有拙催科。", "倦遊我亦懷三徑，何况傳聞政免苛。"]'),
('185136c4-69f9-48e5-ba4e-3631483dcce6','送莫贛州','趙蕃','宋','宋诗','song-poetry','','[]','赤縣權宜非昔時，近聞誰復古人爲。',64,'全唐诗/poet.song.165000.json','["赤縣權宜非昔時，近聞誰復古人爲。", "向來聲烈有如此，今日飛騰已似遲。", "鴈序相仍盡詞掖，虎城寧獨待瓜期。", "歸哉懷玉山邊路，準擬重看召節時。"]'),
('8eee7abd-5271-4fea-a3d8-1efff17dcae6','呈郭峽州二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','往者枉書并賜詩，藹然高義見乎詞。',64,'全唐诗/poet.song.165000.json','["往者枉書并賜詩，藹然高義見乎詞。", "襄陽耆舊今餘幾，海內風流更屬誰。", "早日有懷期見止，秋風於此得來思。", "顧雖願被林宗識，却恐人非詎辱知。"]'),
('0adc315e-f11e-4162-92c7-a6ed7262b817','呈郭峽州二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','鄉來識面苦無因，今日升堂敘所親。',64,'全唐诗/poet.song.165000.json','["鄉來識面苦無因，今日升堂敘所親。", "豈愛瀟湘爲隠地，故嗟伊洛涴風塵。", "周程授受源流遠，廣受聲名物望均。", "詔旨已聞班郡紱，徵書看即動蒲輪。"]'),
('a9aa2f0c-58da-40a9-84c4-bb95408c315d','呈陸嚴州二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','一代詩盟孰主張，試探源委見深長。',64,'全唐诗/poet.song.165000.json','["一代詩盟孰主張，試探源委見深長。", "家聲甫里歸嚴瀨，句法茶山出豫章。", "千里寸心長炯炯，十年兩鬢漫蒼蒼。", "扁舟縱欲乘風去，可不一登君子堂。"]'),
('c1800212-b4c8-4380-958d-99cb431eaee5','呈陸嚴州二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','去年犯雪到嚴州，呵筆題詩曳履投。',64,'全唐诗/poet.song.165000.json','["去年犯雪到嚴州，呵筆題詩曳履投。", "所恨决然成間闊，故茲復爾小遲留。", "精金美玉自有價，伯樂王良無即休。", "珠玉見褒猶美疢，葯須瞑眩疾方瘳。"]'),
('77105dc4-32ab-4fa1-8a12-5626fc3575b4','呈莫信州障二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','稍將書札報黄堂，僅得官亭繫野航。',64,'全唐诗/poet.song.165000.json','["稍將書札報黄堂，僅得官亭繫野航。", "文物願窺中秘直，風流曾識省曹郎。", "莫言長孺今閉閤，舊說葛豐能擊彊。", "未信吾州留得住，天書咫尺會徵黄。"]'),
('d40849d9-c069-4fb5-a257-0cdbc776138c','呈莫信州障二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','公爲州牧我州民，敢敘當年半面親。',64,'全唐诗/poet.song.165000.json','["公爲州牧我州民，敢敘當年半面親。", "故喜來歸逢稔歲，况於遊倦得閒身。", "無功良醖不可戀，仲叔豬肝猶累人。", "最是妻孥苦驚怪，奈何造請尚趨晨。"]'),
('13561a52-39af-4b53-8618-dd22563831f2','寄李舒州  其一','趙蕃','宋','宋诗','song-poetry','','[]','賸欲寄書兼寄詩，病餘殊覺不能支。',64,'全唐诗/poet.song.165000.json','["賸欲寄書兼寄詩，病餘殊覺不能支。", "西山南浦風前恨，皖水灊山天外思。", "四海舊知寧我識，百年深契舍公誰。", "自違門第秋重老，華髮蕭蕭異別時。"]'),
('7443295a-f215-4a0d-8b9c-c3e69a1c0d55','寄李舒州  其二','趙蕃','宋','宋诗','song-poetry','','[]','賸欲題詩詩不成，遣人空復附書行。',64,'全唐诗/poet.song.165000.json','["賸欲題詩詩不成，遣人空復附書行。", "言邊詎止寒溫事，紙上胡能底裏傾。", "以我向公深有託，知公于我未忘情。", "扶持未可言門戶，老大相看祇弟兄。"]'),
('5e46df0d-39ab-4767-9f66-8923642c1632','寄曾使君昭','趙蕃','宋','宋诗','song-poetry','','[]','溪山杖策過山林，萬竹千梅可慰心。',64,'全唐诗/poet.song.165000.json','["溪山杖策過山林，萬竹千梅可慰心。", "已悟濠魚真得計，未嫌郢曲謝知音。", "飛騰要路終無那，咫尺春風且細尋。", "詩自空青受山谷，到公探討益精深。"]'),
('70a2c683-e154-45e3-8d88-2efcc8f3d167','寄進賢令程可久','趙蕃','宋','宋诗','song-poetry','','[]','博士湖邊初拜公，後來超化信常通。',64,'全唐诗/poet.song.165000.json','["博士湖邊初拜公，後來超化信常通。", "一官何意偶同隸，千里長懷幾望風。", "墨綬于今天下半，絃歌誰復古人中。", "雙魚敬遣問無恙，目極春江鴻墮空。"]'),
('ecac85a2-0ce3-416b-9a2d-7096ae930f47','送周德望之參告太學','趙蕃','宋','宋诗','song-poetry','','[]','郢州清節著吾州，宜爾諸郎總好脩。',64,'全唐诗/poet.song.165000.json','["郢州清節著吾州，宜爾諸郎總好脩。", "過我山林忘僻陋，爲君雞黍乏淹留。", "結交群從非一日，欲話令人翻百憂。", "畫舸曾同李膺載，竹林仍並阮咸遊。"]'),
('c6c6f1e3-ed84-4c3b-b16b-2fbf79aa7ca3','呈何縣丞','趙蕃','宋','宋诗','song-poetry','','[]','古屋無多客掛包，占風政類鳥居巢。',64,'全唐诗/poet.song.165000.json','["古屋無多客掛包，占風政類鳥居巢。", "誰能故賦感不遇，亦莫空書廣絕交。", "開闔屢摇塵戶牡，戞磨時裊竹簷梢。", "南朝文物君家盛，聽我追隨學詠嘲。"]'),
('70bde6f0-c7ca-4781-b5dd-1dd6dd6f14ca','送向如愚赴廬陵丞','趙蕃','宋','宋诗','song-poetry','','[]','乃祖當年耐官職，遠孫今日振家聲。',64,'全唐诗/poet.song.165000.json','["乃祖當年耐官職，遠孫今日振家聲。", "閉門已盡五車讀，補吏反爲千里行。", "丞不負君休自厭，詩能窮我竟何成。", "春風儘可寬役役，不用迴頭數去程。"]'),
('b1fd35d9-44f8-4145-80ea-c06c5218d145','呈謝資深縣丞源','趙蕃','宋','宋诗','song-poetry','','[]','平生夢寐臨川郡，故在溪堂竹友齋。',64,'全唐诗/poet.song.165000.json','["平生夢寐臨川郡，故在溪堂竹友齋。", "句法已看行世集，風聲猶得起人懷。", "有孫住著園依水，薄宦舊來松儼槐。", "縱是塵埃政衝突，可無一語道離乖。"]'),
('0133fbdd-2e55-44e8-bc60-30c76aa1d96b','懷張丞用多字韻兼屬明叔','趙蕃','宋','宋诗','song-poetry','','[]','愁陰頗覺助煩疴，別日回頭已似多。',64,'全唐诗/poet.song.165000.json','["愁陰頗覺助煩疴，別日回頭已似多。", "聯詩古亦有韓孟，共和今豈無羊何。", "踏青未晚歸來約，舉白何妨醉後歌。", "顧憚禮容成簡慢，願君貰我勿加訶。"]'),
('4717d9b9-ba6e-465d-8ff0-9391d855ac6b','過玉光呈吳丞','趙蕃','宋','宋诗','song-poetry','','[]','又見秋風拉芰荷，也無官柳共婆娑。',64,'全唐诗/poet.song.165000.json','["又見秋風拉芰荷，也無官柳共婆娑。", "青山只作向來看，白髮自驚重到多。", "莫道予方有公事，須知地僻少經過。", "數公句刻雖無恙，題榜風流欠景坡。"]'),
('c0511324-fe25-458e-a690-643311c1e881','賀向伯元通判休致','趙蕃','宋','宋诗','song-poetry','','[]','薌林再世企疎堂，不但私榮國有光。',64,'全唐诗/poet.song.165000.json','["薌林再世企疎堂，不但私榮國有光。", "畢娶了知家法在，耐官爰自祖風長。", "眼明圖史猶年少，手種檜松今老蒼。", "父客同時亦同盛，成都卜宅匪它楊。"]'),
('24b522a6-9250-4213-b419-4b186a27e7e2','贈王教授基仲','趙蕃','宋','宋诗','song-poetry','','[]','先君昔作濡須令，閭里所知清德高。',64,'全唐诗/poet.song.165000.json','["先君昔作濡須令，閭里所知清德高。", "末路我今慚世業，一門君乃冠辰髦。", "長公已有朝陽譽，夫子寧淹獨冷曹。", "頗念相從問疇昔，不堪歲月去滔滔。"]'),
('bea0f835-03ed-4dba-a6aa-1a13d2f36a1d','贈袁州王教授時會','趙蕃','宋','宋诗','song-poetry','','[]','邂逅相逢索我詩，我詩何有鬢空絲。',64,'全唐诗/poet.song.165000.json','["邂逅相逢索我詩，我詩何有鬢空絲。", "能聲故爾媿侯喜，到處其誰說項斯。", "肯約山行頻滯雨，預懷別後費相思。", "一官獨冷休形歎，斯會簿書都不知。"]'),
('b8515d45-917c-424b-9be8-a648e31914bc','用韻寄孫推官二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','淚垢悲啼失母雛，可思營室共啣蕪。',64,'全唐诗/poet.song.165000.json','["淚垢悲啼失母雛，可思營室共啣蕪。", "未能因事賦歸去，尚此折腰成走趨。", "豈謂微官堪顧藉，不難征路指虛無。", "重輕得喪吾知矣，莫待孔賓聞夜呼。"]'),
('a036c12f-35c0-4928-82cd-77dcec14eeea','用韻寄孫推官二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','珍重章泉萬竹雛，護煩鄰里未應蕪。',64,'全唐诗/poet.song.165000.json','["珍重章泉萬竹雛，護煩鄰里未應蕪。", "浮生固覺浮雲似，逝者難堪逝水趨。", "尚喜論詩有新益，幸逃閲士若旁無。", "君平未可山林去，儻欲赴盟其見呼。"]'),
('db1b3992-8870-47c7-9e28-345b08cbeb8b','蕃近有干字韻屬教授兄而知縣尉曹皆嘗用是韻相酬贈亦成一首奉呈並屬錄事今年未見梅花故及之','趙蕃','宋','宋诗','song-poetry','','[]','回首江南千萬山，渺如霄漢邈難干。',64,'全唐诗/poet.song.165000.json','["回首江南千萬山，渺如霄漢邈難干。", "至前不見梅花朵，客裏何由老病寬。", "往日簿書如束濕，新來詩卷喜頻看。", "我衰才盡渾無奈，倚頼諸君爲發端。"]'),
('58792421-6190-4d8e-9d98-aa71ebcea790','八月二十六日雨後呈沅陵教授','趙蕃','宋','宋诗','song-poetry','','[]','秋風比已凉如水，秋日還能熱似焚。',64,'全唐诗/poet.song.165000.json','["秋風比已凉如水，秋日還能熱似焚。", "驟對碧雲成突兀，忽看快雨灑繽紛。", "梧應留響中宵聽，菊爲韜香九日聞。", "排遣羈愁消底物，要君詩律張吾軍。"]'),
('3209ba41-0544-410d-ab65-b5193bd75bca','挽黄參議','趙蕃','宋','宋诗','song-poetry','','[]','給事勳庸太史詩，凜然人物見家規。',64,'全唐诗/poet.song.165000.json','["給事勳庸太史詩，凜然人物見家規。", "霜鬚同老豈無種，孝友深根真得師。", "治行所居皆可紀，人亡於此歎吾衰。", "舊聞有道碑無媿，今見雲孫無媿詞。"]'),
('a882c248-fd71-4052-9c07-67f6e87ebb0f','挽朱通判','趙蕃','宋','宋诗','song-poetry','','[]','堆勝題詩尚可懷，異時吳楚渺何哉。',64,'全唐诗/poet.song.165000.json','["堆勝題詩尚可懷，異時吳楚渺何哉。", "傳聞屢作南州佐，政自不妨三逕開。", "準擬歸舟成再見，驚嗟玉樹有新摧。", "要知盛德亡窮處，連璧光輝看後來。"]'),
('34f65165-a014-4db7-81f3-906447c60e5b','題重脩堆勝樓','趙蕃','宋','宋诗','song-poetry','','[]','白鷺洲前堆勝樓，相望前後幾監州。',64,'全唐诗/poet.song.165000.json','["白鷺洲前堆勝樓，相望前後幾監州。", "枝梧合付陶謝手，嘯傲亦須嵇阮流。", "怪得江山還舊觀，只應欄檻有新脩。", "登臨媿我焉能賦，假日空成半日留。"]'),
('3dc29a94-6631-48f1-9a79-f145cd25284a','元衡過邢園同廣聲終日坐於習堂梅樹之下得長句','趙蕃','宋','宋诗','song-poetry','','[]','一間茅屋數株梅，三徑頻成爲我開。',64,'全唐诗/poet.song.165000.json','["一間茅屋數株梅，三徑頻成爲我開。", "賸有游蜂能掠蘂，寂無饑雀下行苔。", "長吟共惜頻驚落，久坐何妨晚始回。", "爲語清風莫輕掃，明朝更欲杖藜來。"]'),
('b4f7068e-465c-4f85-962a-ea4a2f443b70','用老謝丈立春韻贈周文顯蕃與文顯以癸巳歲是日相識始有倡酬故及之','趙蕃','宋','宋诗','song-poetry','','[]','時序飛騰不貸人，相從還此賦迎春。',64,'全唐诗/poet.song.165000.json','["時序飛騰不貸人，相從還此賦迎春。", "祇言世態有凉燠，須信吾曹無故新。", "長句能同李白好，爲儒未許賈山醇。", "兩郎玉立仍難弟，誰道先生解久貧。"]'),
('cdfc4410-39ef-413c-a6a9-126be934f9c0','次韻簽判丈立春日長句','趙蕃','宋','宋诗','song-poetry','','[]','未說麥黄如病人，可堪梅落似殘春。',64,'全唐诗/poet.song.165000.json','["未說麥黄如病人，可堪梅落似殘春。", "休論北客驚相嘆，試問南公見一新。", "謂恐齊民罹癘疫，又言漢詔發深淳。", "從茲度日能無事，頻與傳詩慰此貧。"]'),
('31076818-b548-4caf-9090-661532f4c1c9','是日招明叔飲明叔有詩次韻','趙蕃','宋','宋诗','song-poetry','','[]','客罷蕭然欲閉關，竹陰梅影兩爛斑。',64,'全唐诗/poet.song.165000.json','["客罷蕭然欲閉關，竹陰梅影兩爛斑。", "溫風不捄詩寒相，老色聊須酒借顔。", "此味何妨君與共，流年莫待水西還。", "破春行樂胡爲始，快閣之餘有觀山。"]'),
('482cd740-34ad-4cae-a5bd-55364b50699f','兩日不見在伯風雨中有懷因以簡之','趙蕃','宋','宋诗','song-poetry','','[]','卧聞急雨響林柯，想見江頭聲更多。',64,'全唐诗/poet.song.165000.json','["卧聞急雨響林柯，想見江頭聲更多。", "兩日不來百憂集，一杯猶憶醉時歌。", "已孤柿栗霜天熟，其柰衣裘卒歲何。", "掾奉酸寒古云歎，治時還重力田科。"]'),
('c2554f24-a0b9-45f6-943a-f68f503cd79f','初二日復雨偶成','趙蕃','宋','宋诗','song-poetry','','[]','秋旱連冬勢未平，何期小雨趁元正。',64,'全唐诗/poet.song.165000.json','["秋旱連冬勢未平，何期小雨趁元正。", "休論忽忽生爲樂，且對欣欣木向榮。", "已分終身樂貧賤，自無岐路覓功名。", "獨於詩律存餘習，三日不談荆棘生。"]'),
('ac94ce7c-bf48-47e5-9d3d-0536cabd659f','十九日雨中','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','帆來鳥去蘇州句，落木長江老杜詩。',64,'全唐诗/poet.song.165000.json','["帆來鳥去蘇州句，落木長江老杜詩。", "得意寫圖那辦此，驚人吐句或能之。", "長年役役愁肝腎，老態駸駸入鬢髭。", "寄謝樵夫與漁子，可憐日用不能知。"]'),
('8f38b79f-5dc5-4f66-8800-447351d4202a','二月六日雨中簡諸君','趙蕃','宋','宋诗','song-poetry','','[]','人言好雨知時節，紅白紛紛柰若何。',64,'全唐诗/poet.song.165000.json','["人言好雨知時節，紅白紛紛柰若何。", "田父相呼稻當種，園官語我菜添科。", "日長燕子自無事，渚漲桃花思汎波。", "寄謝同參二三老，未妨乘間數經過。"]'),
('48666d1b-d0c2-4f4f-9520-1eebfdd4ffae','雨陰未解成長句','趙蕃','宋','宋诗','song-poetry','','[]','一日舒晴十日陰，春來時節更蕭森。',64,'全唐诗/poet.song.165000.json','["一日舒晴十日陰，春來時節更蕭森。", "徐行索句茅簷靜，孤坐焚香書屋深。", "少日饑寒真累己，莫年勳業已無心。", "先賢遺傳時披讀，頗怪山王在竹林。"]'),
('24362a1b-d84d-4e08-9545-0d218fd12fa8','初十日早立寺門作','趙蕃','宋','宋诗','song-poetry','','[]','春天陰晴無定姿，陰雲未卷晴風吹。',64,'全唐诗/poet.song.165000.json','["春天陰晴無定姿，陰雲未卷晴風吹。", "青山表見花顔色，綠竹增添鷺羽儀。", "郭外不知誰是主，眼中今日我題詩。", "人生何物非郵傳，敢謂吾廬不在茲。"]'),
('d830e798-5137-4b7d-8dc3-8af7aaf6b6a7','季春十有三日作','趙蕃','宋','宋诗','song-poetry','','[]','晨起風寒又覺加，不知信復到何花。',64,'全唐诗/poet.song.165000.json','["晨起風寒又覺加，不知信復到何花。", "晴多且欲雨知節，雨久更思晴亦佳。", "寂寂蕙蘭菲賸馥，紛紛姚魏掃殘葩。", "故山政好不歸去，筍蕨登盤僧餽茶。"]'),
('eb1e64b1-5d6a-409b-9559-30e350f761a6','三月三十日','趙蕃','宋','宋诗','song-poetry','','[]','正是春時病不聊，未嫌風雨送今朝。',64,'全唐诗/poet.song.165000.json','["正是春時病不聊，未嫌風雨送今朝。", "今年紅蘂明年在，此日繁陰後日凋。", "詩癖不除終作祟，鬢霜無種自能饒。", "平生吟友俱安在，寥落天涯不可招。"]'),
('5646e601-1d29-47f7-93e5-dbfe87348e84','暑甚有懷山居','趙蕃','宋','宋诗','song-poetry','','[]','風不能清友病人，睡常忘起更疲神。',64,'全唐诗/poet.song.165000.json','["風不能清友病人，睡常忘起更疲神。", "世間自有寬凉處，胸次休懷偪仄嗔。", "腕倦不勝持羽扇，頭童端欲墊綸巾。", "歸歟舊隠連脩竹，幽鳥窺簷席有塵。"]'),
('b92de71b-6f48-436a-be62-43e7dcf757de','呈歐陽伯威','趙蕃','宋','宋诗','song-poetry','','[]','傳得新詩字字驚，佛廊驟識病身輕。',64,'全唐诗/poet.song.165000.json','["傳得新詩字字驚，佛廊驟識病身輕。", "李邕昔已求工部，文舉今宜薦禰衡。", "祇道迷邦尚藍縷，試令吐氣即崢嶸。", "一官不作來南限，取友得交齊魯生。"]'),
('5bd2a6ba-457c-4cb5-bef8-9f10ff4c9200','呈壽岡','趙蕃','宋','宋诗','song-poetry','','[]','夏雨凄凄曾過公，祇今端復是秋風。',64,'全唐诗/poet.song.165000.json','["夏雨凄凄曾過公，祇今端復是秋風。", "青青但保庭前竹，渺渺不悲江上楓。", "每憶誦詩頭且白，可期頻見頰猶紅。", "陶家九日明朝事，問訊菊籬開幾叢。"]'),
('e03890aa-6d4b-41f2-8b75-cdb30e143ed5','九日','趙蕃','宋','宋诗','song-poetry','','[]','澗落峯寒似往時，重陽面目許誰知。',64,'全唐诗/poet.song.165000.json','["澗落峯寒似往時，重陽面目許誰知。", "摇摇楓葉未全赤，草草菊花成後期。", "酒量稍增愁渴肺，詩材頓減費衰髭。", "一年節物財如此，太息空形老大悲。"]'),
('65074843-6b59-4c0e-8d1b-3d1287df0f59','九日遊馬祖巖','趙蕃','宋','宋诗','song-poetry','','[]','環城往往盡高峯，更欲登高底可同。',64,'全唐诗/poet.song.165000.json','["環城往往盡高峯，更欲登高底可同。", "馬祖自今成故實，龍山翻覺墮虛空。", "當公迭唱青霄上，政我孤吟返照中。", "要是不孤吹帽節，孰云真隔馬牛風。"]'),
('641306ed-3737-4121-881d-350e8576f86b','重陽後一日作','趙蕃','宋','宋诗','song-poetry','','[]','昨日重陽故作晴，今晨陰慘倍愁生。',64,'全唐诗/poet.song.165000.json','["昨日重陽故作晴，今晨陰慘倍愁生。", "憑高已負登臨約，展卷空餘賦詠情。", "籬下菊香殊寂寞，瓶中桂影謾凄清。", "感今懷古無窮意，祇取村醪細細傾。"]'),
('7df2b18f-7123-40a9-9a0b-895359913d8f','至日','趙蕃','宋','宋诗','song-poetry','','[]','今年至日還爲客，墮我侵尋老境中。',64,'全唐诗/poet.song.165000.json','["今年至日還爲客，墮我侵尋老境中。", "照影不堪詩鬢禿，向人無復酒顔紅。", "石田茅屋鄉關異，官柳野梅時序同。", "試問一廛何所直，苦令飄泊困西東。"]'),
('02cfa3c7-8752-40c3-b96b-09f909a821ed','閏十一月十一日病酒不能扶頭忽得成父弟書繼又得叔異季承和詩偶成長句會有便先寄叔異季承','趙蕃','宋','宋诗','song-poetry','','[]','北風將雪晝成陰，冷屋閒窗偃卧深。',64,'全唐诗/poet.song.165000.json','["北風將雪晝成陰，冷屋閒窗偃卧深。", "百慮欲醒還皎皎，白頭高擁更岑岑。", "詩從嶺外來雙璧，書自江東得萬金。", "得友似斯真足慰，有兄如我竟何任。"]'),
('e6d0918a-3b40-4cf1-afa7-477b0ed52bd7','酬在伯再用書事之韻','趙蕃','宋','宋诗','song-poetry','','[]','西行險絕類中巴，東望悲凉底是家。',64,'全唐诗/poet.song.165000.json','["西行險絕類中巴，東望悲凉底是家。", "渺渺春風限啼鴂，悠悠落日送歸鴉。", "室盈幼稚爲腰折，腹有詩書宜氣華。", "兩日不親顔色好，出門還恐滯泥沙。"]'),
('28e14de9-7e6c-4edf-8eeb-a119192ab841','酬湯莘夫用懷孫溫叟韻見貽','趙蕃','宋','宋诗','song-poetry','','[]','長夜漫漫起飯牛，飛鳶跕跕墮炎州。',64,'全唐诗/poet.song.165000.json','["長夜漫漫起飯牛，飛鳶跕跕墮炎州。", "是皆有命無悲感，孰若委心安去留。", "駿足豈嫌鑾輅苦，散才當逭斧斤搜。", "吾人故有交期在，出處何須終並遊。"]'),
('ac97a400-6aa5-499e-8a27-952bdf9d2280','子暢尉曹用贈沅陵韻作詩見示亦用韻奉酬','趙蕃','宋','宋诗','song-poetry','','[]','元祐于今幾故家，要尋遺事渺難涯。',64,'全唐诗/poet.song.165000.json','["元祐于今幾故家，要尋遺事渺難涯。", "虛名可媿鐵爐冒，實美當知丙穴嘉。", "柱後惠文余故窘，伍符尺籍子無嗟。", "神仙也說多官府，何物蜂房亦趁衙。"]'),
('ac3d1455-5af4-45c5-ac01-cfe595a1a1b3','王原慶有詩寄謝丈簽判子暢尉曹具以見及次韻酬之','趙蕃','宋','宋诗','song-poetry','','[]','相望千里舊聞風，何意論交邂逅中。',64,'全唐诗/poet.song.165000.json','["相望千里舊聞風，何意論交邂逅中。", "別去傷心念風雨，詩來滿眼眩青紅。", "通家契好君能記，末路飄零我亦同。", "江左名流數王謝，一時況有小安豐。"]'),
('604de76e-7ccc-4793-9782-d04fe5eebe34','昨見子暢尉曹與靈鷲長老年公用蕃船字韻唱酬佳什用韻呈年老','趙蕃','宋','宋诗','song-poetry','','[]','幾思杖策禮金仙，聞道客來如貫船。',64,'全唐诗/poet.song.165000.json','["幾思杖策禮金仙，聞道客來如貫船。", "政恐方成過溪送，不能容此對牀眠。", "愛公詩律真餘習，憐我宗門乏厚緣。", "願以伽佗示深旨，莫將麗藻鬭多篇。"]'),
('93dd7081-f874-4bbc-84d3-e83e2e014eda','莘夫再用前韻作詩謝余過其居復用韻答之  其一','趙蕃','宋','宋诗','song-poetry','','[]','漫道平生風馬牛，也能歷歷記吾州。',64,'全唐诗/poet.song.165000.json','["漫道平生風馬牛，也能歷歷記吾州。", "相從大勝十年讀，肯過輕爲一飯留。", "氣合未知投分晚，腹虛終苦和詩搜。", "我方羈旅君當去，契闊何時重與遊。"]'),
('2d2c1427-e1f4-4a38-902a-78dd115c98f6','莘夫再用前韻作詩謝余過其居復用韻答之  其二','趙蕃','宋','宋诗','song-poetry','','[]','鹽車驥服駕罷牛，政使斯人此佐州。',64,'全唐诗/poet.song.165000.json','["鹽車驥服駕罷牛，政使斯人此佐州。", "大策本收經濟用，三年何有課程留。", "愛其義重雲天薄，憐我詩窮肺腑搜。", "子見懸知問何似，爲言歸决夢成遊。"]'),
('37fc31ec-6da8-4204-9885-e14c019531dc','寄答曾無己見貽詩卷','趙蕃','宋','宋诗','song-poetry','','[]','吾舅風流名海內，霜清月淡有梅詩。',64,'全唐诗/poet.song.165000.json','["吾舅風流名海內，霜清月淡有梅詩。", "君曾一向蒸湘識，句裏懸應摸索知。", "邂逅已能成屢見，殷勤還辱問歸期。", "談間併爲諸兄謝，從此論交更不疑。"]'),
('0075f5ff-376e-4a00-9182-bd4fcf3e90e9','沅陵用在伯林字作詩見屬次韻答之','趙蕃','宋','宋诗','song-poetry','','[]','畏寒終日卧窗陰，衰颯政如霜後林。',64,'全唐诗/poet.song.165000.json','["畏寒終日卧窗陰，衰颯政如霜後林。", "勿謂官閒得廳冷，幾因詩至啟門深。", "酒才飲濕寧崇味，琴且無弦豈嗜音。", "政爾欲閒閒不得，和詩頻改又頻吟。"]'),
('8ed0a6bf-bb24-45d6-8b33-fe66cfdb8729','季奕見蕃與審知唱酬近詩過辱枉贈用韻奉答','趙蕃','宋','宋诗','song-poetry','','[]','故里歸來跡轉浮，是身投老計何由。',64,'全唐诗/poet.song.165000.json','["故里歸來跡轉浮，是身投老計何由。", "山中閲世松筠老，江上隨波雁鶩流。", "攬鬢不堪供潦倒，誦詩猶及問朋遊。", "西鄰徐孺今文伯，我爾俱當讓一頭。"]'),
('d700cc1a-aa8f-4a5a-859b-abf326883c22','湯莘夫用孫溫叟韻見寄次韻答之','趙蕃','宋','宋诗','song-poetry','','[]','生氣千年藺與頗，生前杯酒事如何。',64,'全唐诗/poet.song.165000.json','["生氣千年藺與頗，生前杯酒事如何。", "誰令誤舍清江釣，政爾甘持絕徼戈。", "有句忽成能見憶，感君知我未加訶。", "晚風苦雜蟬鳴樹，不謂林鶑尚有歌。"]'),
('ad3aaaed-acb4-411a-a04f-c3954fdf14e5','再答曾元之','趙蕃','宋','宋诗','song-poetry','','[]','春風吹雨雨還晴，晚日才昏昏復明。',64,'全唐诗/poet.song.165000.json','["春風吹雨雨還晴，晚日才昏昏復明。", "屋角乍聞烏鵲喜，林間又聽勃姑鳴。", "鷄豚已負鄰翁社，詩酒尚欣吾輩盟。", "笑我難忘澹生活，因君重憶舊風情。"]'),
('bb06c615-7a17-4107-8541-d765d304f4ae','迂齋往葛水道中蚤起有詩見寄次韻答之','趙蕃','宋','宋诗','song-poetry','','[]','桑柘陰中數畝村，病多終日厭昏昏。',64,'全唐诗/poet.song.165000.json','["桑柘陰中數畝村，病多終日厭昏昏。", "忽傳寄我道間作，徑欲過君竹下門。", "坐看諸公上臺省，誰知陶令在田園。", "文章勳業元難並，未易輕爲得失論。"]'),
('76405e54-9a77-4ab1-9d78-d4c1dd46a903','和答李季蓬因觀鄙語見贈','趙蕃','宋','宋诗','song-poetry','','[]','沅有茝兮澧有蘭，到今風物尚班班。',64,'全唐诗/poet.song.165000.json','["沅有茝兮澧有蘭，到今風物尚班班。", "有懷未覺千年遠，無力能追一字還。", "贈我詩何富風月，知君助不待江山。", "況聞方奏凌雲賦，寧復留繻待出關。"]'),
('6efbf665-0790-43fd-acae-d582370fe87a','贈韋德卿秀才','趙蕃','宋','宋诗','song-poetry','','[]','蚌繇珠剖孰爲冤，鶴豈鳴臯且唳天。',64,'全唐诗/poet.song.165000.json','["蚌繇珠剖孰爲冤，鶴豈鳴臯且唳天。", "對策未居金馬上，夜書猶即短檠邊。", "子誠異嗜如昌歜，我媿沉痾非藕船。", "永好固知當有報，思眢才索不能篇。"]'),
('a894b6f7-9b85-415d-bf31-7e838c9726c2','次韻酬答陳席慶伯見貽二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','詩成每輒肺肝愁，那與人充耳目謀。',64,'全唐诗/poet.song.165000.json','["詩成每輒肺肝愁，那與人充耳目謀。", "敢謂老懷千里志，故憐饑作四方遊。", "若人尚隠南山霧，老我合從春水鷗。", "舊契百年談未易，且言家共古揚州。"]'),
('20de9a3f-c2b4-4fc0-b703-1e34ca1a55a6','次韻酬答陳席慶伯見貽二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','問君有賦敵相如，誰爲君王誦子虛。',64,'全唐诗/poet.song.165000.json','["問君有賦敵相如，誰爲君王誦子虛。", "去歲別家今未返，有親須養得安居。", "附名願見先友記，宣布曾傳太史書。", "清燕倘思詢舊事，莫辭待詔久公車。"]'),
('37cfd48f-4b78-4b39-8f24-7e596054e030','次韻元衡憶上饒見示七言','趙蕃','宋','宋诗','song-poetry','','[]','避兵俱落信州溪，爲客豈知湖外期。',64,'全唐诗/poet.song.165000.json','["避兵俱落信州溪，爲客豈知湖外期。", "遠役不應因米屈，秋風政爾悵鱸時。", "故人已寄招魂作，吾子重歌隠士詩。", "回首天寒又霜雪，可教猿鶴苦凄悲。"]'),
('7c01c7e2-7d5f-4303-b596-42e88d9af294','玉汝行頗遽以詩留之','趙蕃','宋','宋诗','song-poetry','','[]','雲物荒荒苦未晴，客程慘慘易成驚。',64,'全唐诗/poet.song.165000.json','["雲物荒荒苦未晴，客程慘慘易成驚。", "家貧縱乏淹留具，意合能忘賦咏情。", "底用飄然輕此去，未妨聊爾聽流行。", "年來已是乖離數，況復相逢俱老生。"]'),
('bf157af4-822b-454a-bd5e-3a994187f9b9','寄太和舊遊','趙蕃','宋','宋诗','song-poetry','','[]','李暗桃春未是晚，可憐孤負海棠天。',64,'全唐诗/poet.song.165000.json','["李暗桃春未是晚，可憐孤負海棠天。", "故應陶寫皆詩內，安得淋漓到酒邊。", "已辦經營求散吏，便思瀟灑泛江船。", "相思異日題詩句，遶屋扶疎陶令篇。"]'),
('95b65688-0ccd-4dd8-a189-7585fd489746','秉文同成父問屋普圓過予而歸','趙蕃','宋','宋诗','song-poetry','','[]','朝響疎疎不晻光，暮簷瀏瀏亦無長。',64,'全唐诗/poet.song.165000.json','["朝響疎疎不晻光，暮簷瀏瀏亦無長。", "胡然可救焦枯厄，政爾能成湔祓方。", "堆案文書小盤礴，並溪草樹一徜徉。", "君方問隠我思去，異日相望何有鄉。"]'),
('ce434e9e-8e11-4bbd-8e04-6ac71d580e3b','過陳莘叔尹因以贈之','趙蕃','宋','宋诗','song-poetry','','[]','幾從邢子問先友，相與談公口不空。',64,'全唐诗/poet.song.165000.json','["幾從邢子問先友，相與談公口不空。", "治獄盡心無詭論，掛冠猶健有高風。", "崢嶸正爾尚豪氣，矍鑠未應閑是翁。", "兩月淹留見何晚，竹林松徑暫時同。"]'),
('7d2598c5-9876-43b6-af73-6ee0a2e8451c','晚待明叔不至','趙蕃','宋','宋诗','song-poetry','','[]','爲霜未就覺風繁，撥火成灰思晤言。',64,'全唐诗/poet.song.165000.json','["爲霜未就覺風繁，撥火成灰思晤言。", "立壁舊諳寧怲怲，孤燈垂上只昏昏。", "讖言已過一陽復，歸去可忘三徑存。", "趙孟孰云能貴賤，萬年端以勢依溫。"]'),
('2c536f51-a583-4456-9499-72f62abb40d0','王彥博徐審知頻來問疾口占示之','趙蕃','宋','宋诗','song-poetry','','[]','秋來瘧鬼不銷亡，令我兼旬病在牀。',64,'全唐诗/poet.song.165000.json','["秋來瘧鬼不銷亡，令我兼旬病在牀。", "治藥頻成問良苦，易衣終日屢炎凉。", "但添物色增悲壯，那有功名憶慨慷。", "多謝故人來問疾，幾回宵度石爲梁。"]'),
('d89eefeb-529c-46d1-a310-ce08e3a47e48','邂逅徐應卿於都下要之同歸不可索詩因作','趙蕃','宋','宋诗','song-poetry','','[]','鉛山假尉懷初識，祖印依僧憶屢過。',64,'全唐诗/poet.song.165000.json','["鉛山假尉懷初識，祖印依僧憶屢過。", "看鏡余今歎斑白，束書君亦尚犇波。", "肯因艇子俱歸否，捫此空囊奈若何。", "好並千巖學詩去，侯門彈鋏爲悲歌。"]'),
('da5cacb5-48c5-4f47-9dab-14c1f9515880','偶書','趙蕃','宋','宋诗','song-poetry','','[]','陰雲不肯放朝陽，霧雨真成作早霜。',64,'全唐诗/poet.song.165000.json','["陰雲不肯放朝陽，霧雨真成作早霜。", "窗靜網絲縈棐几，壁疎蟲語撼藜牀。", "故人秦越自肥瘠，世事鶴鳬隨短長。", "病不銜觴惟覓句，不須吟詠轉凄凉。"]'),
('e974c556-7997-4adf-8e52-1c0914767aa8','贈徐處士','趙蕃','宋','宋诗','song-poetry','','[]','南朝文士數徐陵，騎省流風篆法存。',64,'全唐诗/poet.song.165000.json','["南朝文士數徐陵，騎省流風篆法存。", "翰墨了知無異道，丹青今復見諸孫。", "規模要自胸中具，繩尺嫌於筆下論。", "太息藝成頭已白，誰能持使獻金門。"]'),
('d908fe7b-adbd-4d9a-aba1-f373f974fcca','蕃有詩謝蕭伯和見訪伯和和之節推丈見而同作謹用韻併呈教授丈宋衡兄','趙蕃','宋','宋诗','song-poetry','','[]','忽聞獨奏鳳將雛，三歎遺音特未蕪。',64,'全唐诗/poet.song.165000.json','["忽聞獨奏鳳將雛，三歎遺音特未蕪。", "禁裏端宜奉朝事，幕中那得尚平趨。", "臨流置酒高人意，叩戶求詩俗士無。", "迨此何妨屢還往，可人況不費招呼。"]'),
('98b91707-26e8-4416-90ba-1722e106ab9e','夜憶欽止斯遠','趙蕃','宋','宋诗','song-poetry','','[]','木葉騷然雨到時，共眠僧榻各哦詩。',64,'全唐诗/poet.song.165000.json','["木葉騷然雨到時，共眠僧榻各哦詩。", "推移忽已年時事，悵望相看天一涯。", "別後屢書渾未報，風前小立重相思。", "人生知復幾寒暑，一別長爲數載期。"]'),
('c5e70e76-386d-4380-bf29-46430d3b9add','訪韋丈叔能於嚴州西溪門外','趙蕃','宋','宋诗','song-poetry','','[]','春王正月附人書，踵報祠官賦遂初。',64,'全唐诗/poet.song.165000.json','["春王正月附人書，踵報祠官賦遂初。", "到處頻成詢所寓，忽能爲說已謀居。", "蘇州舊日詩無敵，嚴瀨從來畫不如。", "東館輕舟雖若駛，可辭躡履到階除。"]'),
('e966e6b8-c8ad-43e0-800d-afa6e9b3443d','示詹深父','趙蕃','宋','宋诗','song-poetry','','[]','濁涇清渭本源分，寂寞安能亂糾紛。',64,'全唐诗/poet.song.165000.json','["濁涇清渭本源分，寂寞安能亂糾紛。", "世黠只知錢使鬼，我癡但識穎呼君。", "乘時大駔千金射，望歲良農赤地耘。", "富貴要知定何物，五車何必爲渠勤。"]'),
('2aaeb8b2-2368-4cc1-879b-2c909647d669','經旬不作詩示明叔','趙蕃','宋','宋诗','song-poetry','','[]','春風著物已熙熙，枯木無心亦自知。',64,'全唐诗/poet.song.165000.json','["春風著物已熙熙，枯木無心亦自知。", "徑欲殷勤辭故絮，却憐窘束欠新詩。", "老來政怯花經眼，遊倦翻成鳥遶枝。", "同病同憂有如子，更堪相對兩霜髭。"]'),
('4f07c0e7-0183-4c00-ac00-04449c410847','入夜應潭對岸作示成父','趙蕃','宋','宋诗','song-poetry','','[]','溪山風月兩相當，痼疾真成得祕方。',64,'全唐诗/poet.song.165000.json','["溪山風月兩相當，痼疾真成得祕方。", "往日同舟但饒信，祇今去路落湖湘。", "貧離親戚古所歎，歸去田園老未忘。", "試遣溪頭問酒價，掃沙聊得踞胡牀。"]'),
('a1955bc1-a37a-4461-b35e-769417b2de69','別約之舅','趙蕃','宋','宋诗','song-poetry','','[]','歎息無錢歸買山，駕言渺渺不知還。',64,'全唐诗/poet.song.165000.json','["歎息無錢歸買山，駕言渺渺不知還。", "爲家百畝未爲泰，何事一生長苦慳。", "我漫參軍作蠻語，公能詩賦動江關。", "固窮似舅詩難敵，不待牀分上下間。"]'),
('8488f9fa-87cb-482d-b05e-66a6a7f37ca9','送成父弟赴補試兼屬同行親友','趙蕃','宋','宋诗','song-poetry','','[]','南省新陞弟子員，詔來郡國亦詳延。',64,'全唐诗/poet.song.165000.json','["南省新陞弟子員，詔來郡國亦詳延。", "百年涵養期爲用，一日選掄非所先。", "珍重好營當暑服，丁寧休覓候潮船。", "故知同役皆親友，莫忘書來慰目前。"]'),
('38491eec-270c-4f88-97ec-ccc38ce5b753','用送成父弟韻送周明甫赴補','趙蕃','宋','宋诗','song-poetry','','[]','詔取咸知有定員，朋來爭欲副招延。',64,'全唐诗/poet.song.165000.json','["詔取咸知有定員，朋來爭欲副招延。", "揚眉欲競將誰與，見敵能輕孰子先。", "養志鄉時惟負米，薄遊今日蹔求船。", "男兒富貴須勤苦，笑我區區但眼前。"]'),
('7e04bac5-1984-44cd-8ccf-ef514ef2fe53','送孝顯彥博昆仲赴補仍用前韻','趙蕃','宋','宋诗','song-poetry','','[]','清時擇士豈充員，大闢賢關務遠延。',64,'全唐诗/poet.song.165000.json','["清時擇士豈充員，大闢賢關務遠延。", "一日擅場稱舉子，百年匡國是儒先。", "爲言行役加餐飯，仍祝濤江穩放船。", "意愜歸來期不晚，秋風觴酒大人前。"]'),
('a21bbbd1-9af9-437e-b1b3-f493e4ca8327','送張剛中赴省','趙蕃','宋','宋诗','song-poetry','','[]','王都觀闕兩巍巍，遠道觀光亦已稀。',64,'全唐诗/poet.song.165000.json','["王都觀闕兩巍巍，遠道觀光亦已稀。", "當念功名方發軔，可辭塵土蹔侵衣。", "春風咫尺君得意，晚歲伶仃我欲歸。", "儻過南山語吾弟，尺書因冷倦重揮。"]'),
('85d32a37-e384-4005-a7a8-b791dd952c87','又成父弟往餘干謁趙叔遂至池陽廬陵謁二周先生長句送行','趙蕃','宋','宋诗','song-poetry','','[]','歸我山中未一年，兩回題子送行篇。',64,'全唐诗/poet.song.165000.json','["歸我山中未一年，兩回題子送行篇。", "況今客路飛紅葉，不比春風啼杜鵑。", "東閣翹材嗟久闊，長沙夜席已喧傳。", "子行歷聘應兄問，併謝江東有二天。"]'),
('2cdc4bbf-b7db-485e-b9f8-c9b164a601f2','過吳江訪尉曹李仲純不值代簡寄之','趙蕃','宋','宋诗','song-poetry','','[]','曉尋仙尉向吳江，聞道乘舟警吠厖。',64,'全唐诗/poet.song.165000.json','["曉尋仙尉向吳江，聞道乘舟警吠厖。", "漁具畫圖賒面覿，松陵酬倡阻心降。", "因人尚擬它時寄，共看無因絕境雙。", "二季一翁新作別，望君須遣候船窗。"]'),
('b237da91-5e73-4aca-843a-295e19a6c97a','因送王亢宗便寄','趙蕃','宋','宋诗','song-poetry','','[]','經年不遇辰州使，忽喜黔陽信使通。',64,'全唐诗/poet.song.165000.json','["經年不遇辰州使，忽喜黔陽信使通。", "縣尉已聞辭令尹，校官仍說困治中。", "可堪契闊漂流處，長憶追隨寂寞同。", "已是湖南更湖北，欲言風物怕愁公。"]'),
('234c8d47-fcf4-4894-b4df-be1ecff8024c','贈王進之','趙蕃','宋','宋诗','song-poetry','','[]','走遍東南數十州，皇皇長媿食爲謀。',64,'全唐诗/poet.song.165000.json','["走遍東南數十州，皇皇長媿食爲謀。", "閲人政爾亦多矣，有客可能如此不。", "歎我漫知耽句僻，如君真復是詩流。", "相逢頗恨夫何晚，華髮蕭蕭今滿頭。"]'),
('46582321-600e-4459-a530-4842355dacba','贈別游子明','趙蕃','宋','宋诗','song-poetry','','[]','頻年此地幾維舟，愧費主人雞黍留。',64,'全唐诗/poet.song.165000.json','["頻年此地幾維舟，愧費主人雞黍留。", "祇道雙鳬已朝帝，那知一鶚尚遲秋。", "小能過我談不惡，重復別君空作憂。", "問訊東歸所經歷，但云巖石過丫頭。"]'),
('9c1e4fb0-efa5-43b5-84e9-70b27570b534','奉贈子冉議郎老兄','趙蕃','宋','宋诗','song-poetry','','[]','大阮談詩數起予，爲言小阮最憐渠。',64,'全唐诗/poet.song.165000.json','["大阮談詩數起予，爲言小阮最憐渠。", "客中邂逅能君識，天外飄零孰我如。", "家世要談京洛舊，古碑共閲漢唐餘。", "所期共剪西窗燭，却值移家方借車。"]'),
('8ad947e4-cef9-4410-a47e-e9d10d7ea4a7','贈別謝茂直','趙蕃','宋','宋诗','song-poetry','','[]','江東何許上饒郡，置吏能淹謝法曹。',64,'全唐诗/poet.song.165000.json','["江東何許上饒郡，置吏能淹謝法曹。", "與世相逢腰漫折，對山吟詠首頻搔。", "誰憐老去斗升祿，未博平生燈火勞。", "我自都城與君別，一官於此始青袍。"]'),
('de41ae9d-fd09-4e5b-9d2b-e1288bfd6c85','贈沈沅陵','趙蕃','宋','宋诗','song-poetry','','[]','紹聖同年今幾家，汎然遊宦偶天涯。',64,'全唐诗/poet.song.165000.json','["紹聖同年今幾家，汎然遊宦偶天涯。", "先因避賊來江左，身欠看山到永嘉。", "世祿相期會騰踏，束書寧復漫咨嗟。", "我今山色催歸意，君政黄紬穩聽衙。"]'),
('a1d3fdd8-a562-4700-9233-890aae920297','贈李子永泳','趙蕃','宋','宋诗','song-poetry','','[]','漫刺平生不妄投，不知我者謂何求。',64,'全唐诗/poet.song.165000.json','["漫刺平生不妄投，不知我者謂何求。", "平生願作李君御，問事況聞他秩抽。", "驛舍夜凉陪麈尾，野田風晚從遨頭。", "可嗟鞅掌催成去，未盡登臨山水幽。"]'),
('44dee886-fa78-4a40-a0a2-2a4404fc1bf9','贈馬奉先二首值其已病竟不相識  其一','趙蕃','宋','宋诗','song-poetry','','[]','使君何苦向宜州，應爲涪翁句法留。',64,'全唐诗/poet.song.165000.json','["使君何苦向宜州，應爲涪翁句法留。", "銅柱寧興跕鳶嘆，金華要遂牧羊求。", "壯時根本先培固，老去波瀾重卷收。", "我亦學詩窮未達，是中得處可聞否。"]'),
('21c27317-0d04-43ba-a68a-336c63bda489','贈馬奉先二首值其已病竟不相識  其二','趙蕃','宋','宋诗','song-poetry','','[]','湘山湘水久經懷，近歲扁舟始一來。',64,'全唐诗/poet.song.165000.json','["湘山湘水久經懷，近歲扁舟始一來。", "頗見留傳詩句寫，故勝摸索畫圖開。", "城南雖鬰平生志，冀北未空千里才。", "壯節曾聞趣除詔，辭官何乃尚徘徊。"]'),
('0a86834e-fa7d-4b0d-9cea-5bef6cc2d778','溧陽別成父弟兼寄遠父秉文','趙蕃','宋','宋诗','song-poetry','','[]','策蹇同來秋始高，肅霜於此背征袍。',64,'全唐诗/poet.song.165000.json','["策蹇同來秋始高，肅霜於此背征袍。", "別離摇落誰入句，險阻艱難卒歲勞。", "好在梅花千雪樹，因思我友兩文豪。", "莫道凶年政艱食，徑須一醉辦糜醪。"]'),
('b13132a6-9d5f-4819-91c9-52b5d711ea6e','溧陽邂逅胡安豐赴官送以二詩  其一','趙蕃','宋','宋诗','song-poetry','','[]','清江江上順風船，大軸持來得縱觀。',64,'全唐诗/poet.song.165000.json','["清江江上順風船，大軸持來得縱觀。", "幾對江山憶談笑，故懷書札欠平安。", "傳聞召節趣歸對，不信淮州勞跨鞍。", "我欲渡江因病返，豈期於此刺探漫。"]'),
('4bc40c69-7f5e-49cc-8261-c9363d80c2b0','溧陽邂逅胡安豐赴官送以二詩  其二','趙蕃','宋','宋诗','song-poetry','','[]','丈人筆力老波瀾，平處猶能敵建安。',64,'全唐诗/poet.song.165000.json','["丈人筆力老波瀾，平處猶能敵建安。", "蹔爲時清掌邊鑰，却來夜直上金鑾。", "悵儂三徑歸來引，翻作五溪行路難。", "邂逅一欣還別去，雪泥連日未全乾。"]'),
('f9e3f68f-ec87-4dab-8517-4e372a937068','鄧師契縣尉以沅陵韻作詩見貽次韻','趙蕃','宋','宋诗','song-poetry','','[]','歎息師門久不傳，葦間幾欲聽延緣。',64,'全唐诗/poet.song.165000.json','["歎息師門久不傳，葦間幾欲聽延緣。", "多君有意工文字，老我空能歷歲年。", "鵬鷃故知難一辨，夔蚿空復妄相憐。", "雖然亦可凄凉慰，祇恐賡篇別是篇。"]'),
('3f9baddd-0538-4262-8b72-f80658fce371','十二月二十六日','趙蕃','宋','宋诗','song-poetry','','[]','水有縈紆何自來，竹能森爽爲誰栽。',64,'全唐诗/poet.song.165000.json','["水有縈紆何自來，竹能森爽爲誰栽。", "山僧乞飯朝一出，幽子題詩日幾迴。", "故鶴未妨頻有客，騎馿正爾獨尋梅。", "得閒且盡幽居趣，顧我初無當世才。"]'),
('af41dacd-c0c7-4772-96b3-e2912158cdc9','人日','趙蕃','宋','宋诗','song-poetry','','[]','元日雖晴人日陰，梅花如積杏花深。',64,'全唐诗/poet.song.165000.json','["元日雖晴人日陰，梅花如積杏花深。", "未憂盈室無儲粟，且恃春風洗破衾。", "莫怪物華常草草，定緣老態日駸駸。", "不須憤泣卞和玉，何有矜誇季子金。"]'),
('031bbbf1-120a-4f36-b711-c15d8c8f0465','人日懷成父弟','趙蕃','宋','宋诗','song-poetry','','[]','人日雨連元日陰，杜陵時節已如今。',64,'全唐诗/poet.song.165000.json','["人日雨連元日陰，杜陵時節已如今。", "苔迷草色閑多思，竹倚梅花瘦不禁。", "徵事還愆退之集，題詩漫有蜀州心。", "溪南有弟遥成隔，目斷蒼然暮色侵。"]'),
('4d200f69-9367-4421-b039-b566db6d3109','同邢希聲遊化成巖','趙蕃','宋','宋诗','song-poetry','','[]','客授袁州且二三，勝遊茲日始輿籃。',64,'全唐诗/poet.song.165000.json','["客授袁州且二三，勝遊茲日始輿籃。", "僧殘尚保高低寺，跡古猶呼上下巖。", "不省眼中如昔否，可慙筆底欠窮探。", "平泉草木今金瀨，免郡還家未趁參。"]'),
('f47cfca2-6b8d-43e4-91aa-6ba3c0bdd88e','寒食前一日伯永相約過陳氏茅軒蕃亦載酒共往與者常寧尉曹明叔伯和蕃賦詩','趙蕃','宋','宋诗','song-poetry','','[]','茅軒臨水自誰開，况有荼䕷玉作堆。',64,'全唐诗/poet.song.165000.json','["茅軒臨水自誰開，况有荼䕷玉作堆。", "佳節愁孤一百五，可人共約兩三杯。", "輕雷淡雨林間過，落日清風座上催。", "更喜經行遠城市，不妨杖屨晚方回。"]'),
('cd1bc47d-ee32-4b38-bbdd-e3f1378a06a3','袁州北崇勝寺二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','病中曾覓扊扅炊，別後東西無自知。',64,'全唐诗/poet.song.165000.json','["病中曾覓扊扅炊，別後東西無自知。", "似說諸侯枉行卷，却從羣彥赴明時。", "相如定辱君王問，鄭老寧容爾汝期。", "幾欲寄書愁不達，偶因閒暇一酬詩。"]'),
('f50f3626-b7f9-4e5a-b595-064906efe4a3','袁州北崇勝寺二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','故人貽我壁間詩，何處飄零負此期。',64,'全唐诗/poet.song.165000.json','["故人貽我壁間詩，何處飄零負此期。", "蹭蹬我今慙薄宦，飛騰君合趁明時。", "雖然不用逢人說，老矣何庸覓世知。", "借問還家底爲計，兒能樵木婦能炊。"]'),
('08dcf19e-ad95-466c-8783-a1643954d46d','呈明叔且約詰朝過買江天閣','趙蕃','宋','宋诗','song-poetry','','[]','老屋支風政覺疎，況堪急雪墮空虛。',64,'全唐诗/poet.song.165000.json','["老屋支風政覺疎，況堪急雪墮空虛。", "黑甜頗念華胥去，白戰仍牽故事餘。", "雀噪還喑家立壁，鼠窺欲下粟無儲。", "江天快閣相縈带，曳履明朝不命車。"]'),
('32c397d3-d033-471e-91c3-a170fc8d92b4','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其一','趙蕃','宋','宋诗','song-poetry','','[]','參軍出郭匪幽尋，使者移文播德音。',64,'全唐诗/poet.song.165000.json','["參軍出郭匪幽尋，使者移文播德音。", "石蒜榆皮那得飽，刀耕火種豈能任。", "義倉政爾因饑發，賑歷茲焉遣吏臨。", "比屋故知難戶曉，分行聊得盡吾心。"]'),
('87f2191e-f279-427d-8831-82ec4aa05b84','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其二','趙蕃','宋','宋诗','song-poetry','','[]','聞道高原尚苦乾，未妨平陸欲生湍。',64,'全唐诗/poet.song.165000.json','["聞道高原尚苦乾，未妨平陸欲生湍。", "眼中乍見扶藜出，耳畔未嗟啼鳥讙。", "漢詔當知本寬大，豳詩政復著艱難。", "爾能粗得饑腸實，我亦安辭脚力酸。"]'),
('b1fbd162-c3d3-4024-8224-0a403d4eacbf','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其三','趙蕃','宋','宋诗','song-poetry','','[]','馬騣嶺下源初發，鵞口山前漸可舟。',64,'全唐诗/poet.song.165000.json','["馬騣嶺下源初發，鵞口山前漸可舟。", "一百八盤誰謂險，二十四溪何自遊。", "深厲淺揭故數數，車煩馬殆真悠悠。", "惜哉當此方倥傯，不然亦足供夷猶。"]'),
('da5789bf-e823-4a53-b6b4-54c2b56c1fae','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其四','趙蕃','宋','宋诗','song-poetry','','[]','大麥初齊積漸黄，青青小麥更連岡。',64,'全唐诗/poet.song.165000.json','["大麥初齊積漸黄，青青小麥更連岡。", "去冬屢雪有如此，今歲一豐端可望。", "負籠不須嗟甚苦，腰鎌行且看爭忙。", "太倉紅腐憎泥土，亦復遥思餠餌香。"]'),
('c77317ed-99e5-47c4-a8a9-7e21e7dd29ee','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其五','趙蕃','宋','宋诗','song-poetry','','[]','既雨得晴晴亦佳，筍輿終日度咿啞。',64,'全唐诗/poet.song.165000.json','["既雨得晴晴亦佳，筍輿終日度咿啞。", "蒙籠篁竹四三里，髣髴茅茨三五家。", "鄰舍相聞亦雞犬，田疇隨事有桑麻。", "居夷何陋慚君子，不爾辭官學種畬。"]'),
('d1913f89-9b2a-44b7-9b73-d56e2dda8aac','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其六','趙蕃','宋','宋诗','song-poetry','','[]','乾溪溪側彈子洞，薄暮過之聊且休。',64,'全唐诗/poet.song.165000.json','["乾溪溪側彈子洞，薄暮過之聊且休。", "志欲山林成獨往，媿無名姓繼三遊。", "奇奇怪怪乏畫手，鑿鑿磷磷宜枕流。", "巖岫水泉真兩得，未容石井獨吾州。"]'),
('2b937673-ab74-4862-be4f-4ee4f1bbe363','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其七','趙蕃','宋','宋诗','song-poetry','','[]','春今回首便天涯，留得芳英在物華。',64,'全唐诗/poet.song.165000.json','["春今回首便天涯，留得芳英在物華。", "野色似雲閒放犢，樹陰如幄暗巢鴉。", "金錢滿地空心草，紫綺漫郊苦菜花。", "試考方言助多識，欲傳名字入詩家。"]'),
('3a0d72c6-6dcc-4535-aa0d-ad62accdd0e9','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其八','趙蕃','宋','宋诗','song-poetry','','[]','浦口江頭艇子呼，有懷逸興恐成孤。',64,'全唐诗/poet.song.165000.json','["浦口江頭艇子呼，有懷逸興恐成孤。", "非鬭郵傳憎塵土，自愛江山入畫圖。", "峯勢宛如神峻拔，瀑痕渾似筆濃枯。", "顧憐文力孱非敵，賸欲追摹忽已逋。"]'),
('5dfad92c-acc8-42f5-bc5e-2c07a2ba18ce','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其九','趙蕃','宋','宋诗','song-poetry','','[]','晚日微風墜鏡平，中流直下縠紋生。',64,'全唐诗/poet.song.165000.json','["晚日微風墜鏡平，中流直下縠紋生。", "煙雲點綴多新態，鷗鳥逢迎殆宿盟。", "聚落近於邊境接，村墟亦有戍樓橫。", "雖然王化初無外，接畛農桑畔不爭。"]'),
('62519d2f-c56a-4cb6-8830-c649aee8830f','三月十七日以檄出行賑貸旬日而復反自州門至老竹自老竹至鵞口復回老竹由乾溪上入浦口汎舟以歸得詩十首  其一○','趙蕃','宋','宋诗','song-poetry','','[]','世奇粵水與湘山，此地元居楚粵間。',64,'全唐诗/poet.song.165000.json','["世奇粵水與湘山，此地元居楚粵間。", "盡日覓詩終莫就，有時遊目不能還。", "驟來遥點雨初過，忽爾數峯雲自閒。", "遠碧近蒼元互映，淺青深綠更相關。"]'),
('1871ee05-019a-4d14-ac43-5de2ce865330','九日宜春道中','趙蕃','宋','宋诗','song-poetry','','[]','勿云秋意漫生悲，可欠重陽一首詩。',64,'全唐诗/poet.song.165000.json','["勿云秋意漫生悲，可欠重陽一首詩。", "瘦馬嘶風紅葉樹，村帘沽酒菊花枝。", "壺觴徵逐紛皆是，人物風流眇莫追。", "獨立斜陽屢搔首，未妨烏帢鬢絲垂。"]'),
('7bb4b409-f46b-47a8-a8b4-8406a17bbd71','十二月一日因出小憩快閣而歸','趙蕃','宋','宋诗','song-poetry','','[]','昨宵已辨雪中燈，今日晴來聊記曾。',64,'全唐诗/poet.song.165000.json','["昨宵已辨雪中燈，今日晴來聊記曾。", "病骨可堪風似刮，衰眸自喜句如冰。", "鴈因就暖長爲客，魚爲逃寒返墜罾。", "北去南來勿渠嘆，身今淹泊歲還仍。"]'),
('663b6b66-a5e5-4637-82bb-41fa6a5fbfda','賦辰州東園水鄉','趙蕃','宋','宋诗','song-poetry','','[]','往日蒼苔滿廢牆，祇今新綠漲芳塘。',64,'全唐诗/poet.song.165000.json','["往日蒼苔滿廢牆，祇今新綠漲芳塘。", "不唯新種荷成柄，更復添栽柳作行。", "墨客休題洛神賦，主人政念水仙王。", "倦遊拓落渾無此，伹擬攀搴學製裳。"]'),
('9748d82e-a4e9-4f0e-9f82-dd2f16fe5540','早到超果寺示成父且約歸日携家來遊','趙蕃','宋','宋诗','song-poetry','','[]','霧裏看花喜未昏，竹園啼鳥愛頻言。',64,'全唐诗/poet.song.165000.json','["霧裏看花喜未昏，竹園啼鳥愛頻言。", "土膏穉麥如爭長，水脉清流却變渾。", "負郭無如此山寺，携家更擬泛溪村。", "卜居苦欲規佳處，佳處都歸祇樹園。"]'),
('43c5ff4e-d2f1-475a-b984-44cbb63bc5d9','歸途','趙蕃','宋','宋诗','song-poetry','','[]','籃輿伊軋又前村，何許風來洗睡昏。',64,'全唐诗/poet.song.165000.json','["籃輿伊軋又前村，何許風來洗睡昏。", "木落盡還山面目，旱深窮見水根源。", "相逢負擔皆征利，難覓隠居躬灌園。", "歸路苦長行易倦，斷鴉殘月記松門。"]'),
('e865cc18-88a4-4f14-9503-bb59e5ac6deb','桃源道中用邢子中丈舊韻','趙蕃','宋','宋诗','song-poetry','','[]','山川曾是避秦餘，何得真成畫不如。',64,'全唐诗/poet.song.165000.json','["山川曾是避秦餘，何得真成畫不如。", "想象曾聞昔所賦，經行爲記我今初。", "欲知賦役無逃遁，看取耕桑映密疎。", "雨笠煙簑春正好，盍拋手板便從渠。"]'),
('3772c6de-fcd6-4132-9269-63f484b4dbc9','昨日絕湖頗危追賦二詩  其一','趙蕃','宋','宋诗','song-poetry','','[]','平生謾說江湖樂，小遇風濤意不任。',64,'全唐诗/poet.song.165000.json','["平生謾說江湖樂，小遇風濤意不任。", "頗眩雲山相俯仰，却憐水鳥恣浮沈。", "神遊險向冤魂語，笑傲强爲洛下吟。", "頼是初謀壯維楫，不然何地覓壺金。"]'),
('8e710a7c-2ab1-4352-a927-9fe076530bca','昨日絕湖頗危追賦二詩  其二','趙蕃','宋','宋诗','song-poetry','','[]','鄱之爲險舊知名，盜奪漁侵恃以成。',64,'全唐诗/poet.song.165000.json','["鄱之爲險舊知名，盜奪漁侵恃以成。", "波靜宴安猶几席，風來洶湧甚戈兵。", "欲知舟楫洄沿趣，都在溪山表裏清。", "明日餘干又維纜，誦詩還是憶長城。"]'),
('64c99b05-a3b3-47ea-b54d-eb58a6a531be','既絕湖得順風頃刻已見弁山二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','五日陰霾鬭不開，步行湖觜看帆來。',64,'全唐诗/poet.song.165000.json','["五日陰霾鬭不開，步行湖觜看帆來。", "祇言命有窮年厄，豈料風能今日回。", "自是人心分順逆，枉於造物示嫌猜。", "篷窗縱雨無深掩，要見前山翠作堆。"]'),
('707bd764-3651-4676-957b-672fbcfcc048','既絕湖得順風頃刻已見弁山二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','幾向詩中覓弁峯，倦遊何意道茲從。',64,'全唐诗/poet.song.165000.json','["幾向詩中覓弁峯，倦遊何意道茲從。", "欲搜短句五七字，却值浮雲千萬重。", "頗覺嘯歌隨趣得，不同應接向人慵。", "連朝苦厭浮家惡，今日翻思此地容。"]'),
('1464c84b-b2d0-4d6f-9a06-19aa3f3e3c62','二十三日使風','趙蕃','宋','宋诗','song-poetry','','[]','江行已屬北風權，此去寧憂上水船。',64,'全唐诗/poet.song.165000.json','["江行已屬北風權，此去寧憂上水船。", "卧聽招呼帆轉脚，起看飛濺水平舷。", "鷗乘逸氣沿仍泝，鴈怯驚吹斷復連。", "玄妙未窮天籟說，雄豪詩讀快哉篇。"]'),
('db409ff4-b6a6-4b3a-9d03-5b033788f7cd','比與成父別謂先行矣及再至溧陽則猶未也留數日與之同歸用雪中懷家之韻','趙蕃','宋','宋诗','song-poetry','','[]','分携决意歸先我，邂逅尚留翻挽渠。',64,'全唐诗/poet.song.165000.json','["分携决意歸先我，邂逅尚留翻挽渠。", "已是常饑思稚子，更逾三月欠家書。", "歲云莫矣嗟何及，歸去來兮計莫如。", "壯志渡江思擊檝，老懷尋壑願巾車。"]'),
('b514afa3-d9c5-4585-b312-44e8d713ba8f','過南昌以病不入城縱望偶題','趙蕃','宋','宋诗','song-poetry','','["\u6ed5\u738b\u9601"]','滕王閣上退之碑，徐孺祠中魯直詩。',64,'全唐诗/poet.song.165000.json','["滕王閣上退之碑，徐孺祠中魯直詩。", "往客欠遊常繫夢，今行緣病復愆期。", "霜彫南浦短長柳，雲掩西山濃澹姿。", "落照有情增我恨，晚風無力度帆遲。"]'),
('a1fbe097-523f-4fc8-a138-dee5b69161c0','峽江舟中懷徐審知','趙蕃','宋','宋诗','song-poetry','','[]','峽江江上曉乘風，人語雞聲宿霧中。',64,'全唐诗/poet.song.165000.json','["峽江江上曉乘風，人語雞聲宿霧中。", "自入江西此差勝，有如吾子乃無同。", "未憐終歲數行役，可料此生長困窮。", "獨是嗜詩餘習在，聳肩搔髮願求工。"]'),
('94921140-5aec-4277-ae29-fb108c19154d','寄題周氏園亭','趙蕃','宋','宋诗','song-poetry','','[]','紅紫矜春一夢空，綠陰青子竟匆匆。',64,'全唐诗/poet.song.165000.json','["紅紫矜春一夢空，綠陰青子竟匆匆。", "那知黛色二千尺，況說蒼髯十八翁。", "萬卷讀書餘舊習，百年種德待成功。", "吾家相望牛鳴地，來往懸知亦許同。"]'),
('19db9d11-313b-4a98-9532-8824396b324a','蒙齋','趙蕃','宋','宋诗','song-poetry','','[]','嶄巖鬰鬰勢參天，下有幽幽百尺泉。',64,'全唐诗/poet.song.165000.json','["嶄巖鬰鬰勢參天，下有幽幽百尺泉。", "淺汲寧容長蛙鮒，旱年端可洗蚳蝝。", "若人懷寶故如此，笑彼發蒙真易然。", "不但作詩能換骨，更知讀易已忘筌。"]'),
('76f2d7af-a904-4062-b2b6-6fa7f2338c3d','題堪隠','趙蕃','宋','宋诗','song-poetry','','[]','考槃何必澗之阿，喧寂由來無異科。',64,'全唐诗/poet.song.165000.json','["考槃何必澗之阿，喧寂由來無異科。", "筆下煙雲供點綴，胸中邱壑寄婆娑。", "清譚不負玉麈尾，白酒未孤金叵羅。", "試數王春才幾日，落梅將盡鳥聞歌。"]'),
('30e1dd2f-d022-4b92-9f40-fdb8890d102d','蕃歸自浙之十日斯還赴處州之約入城自此遂將從處州入關迤邐往謁朱晦菴先生興懷契闊乃成長句','趙蕃','宋','宋诗','song-poetry','','[]','展卷才披別後詩，倡余和汝媿猶遲。',64,'全唐诗/poet.song.165000.json','["展卷才披別後詩，倡余和汝媿猶遲。", "書來喚去有前約，力挽莫留聊後期。", "徵逐里閭平日事，飄零山水異時思。", "從師千里多君志，餬口四方憐我饑。"]'),
('3aaeca02-c432-4763-844d-97a436734c30','寄題周霍丘寓齋','趙蕃','宋','宋诗','song-poetry','','[]','君住瀟湘作寓齋，賦歸仍與是齋偕。',64,'全唐诗/poet.song.165000.json','["君住瀟湘作寓齋，賦歸仍與是齋偕。", "已知身世非真著，肯向功名怨寡諧。", "雨後更無雲在嶺，曉來那有月當階。", "幾思談妙從人去，人事胡爲苦好乖。"]'),
('99b5a3fd-b742-4b58-b7e3-bf05f2d783d3','同張伯永出郊迓客倦歎之餘因以成詠','趙蕃','宋','宋诗','song-poetry','','[]','度日無悰得養痾，不知春事已云多。',64,'全唐诗/poet.song.165000.json','["度日無悰得養痾，不知春事已云多。", "桃花灼灼爲誰好，楊柳依依如恨何。", "曲折東西山展畫，抑揚高下鳥聞歌。", "是間有句彊能管，古淡如君莫我訶。"]'),
('03b58584-1031-4809-a043-f1012897c6f4','周允升見臨已而步過其書堂二詩贈之  其一','趙蕃','宋','宋诗','song-poetry','','[]','漣川川上一書堂，岸缺籬崩徑亦荒。',64,'全唐诗/poet.song.165000.json','["漣川川上一書堂，岸缺籬崩徑亦荒。", "問訊主人空日日，自憐求友亦皇皇。", "豈期雪後能相過，不憚風前往送將。", "隴菜半蕪梅摘索，未妨小立更尋香。"]'),
('cbd7db28-4b44-44f0-9091-2f9acdc77e07','周允升見臨已而步過其書堂二詩贈之  其二','趙蕃','宋','宋诗','song-poetry','','[]','問學知君有所從，未聞論事劇談鋒。',64,'全唐诗/poet.song.165000.json','["問學知君有所從，未聞論事劇談鋒。", "滔滔元自濫觴水，凜凜定期寒歲松。", "不負師承經子厚，共於人物惜元龍。", "漣川川上書堂路，寧復斯人舊履蹤。"]'),
('8cbe6c40-1fdb-4f04-a467-5fbdb4464ef1','訪孫子進子肅於黄堰','趙蕃','宋','宋诗','song-poetry','','[]','茅屋啼雞日過中，小舟隨問曲能通。',64,'全唐诗/poet.song.165000.json','["茅屋啼雞日過中，小舟隨問曲能通。", "遥遥黄堰忽重到，落落白頭今一翁。", "別後每懷音問闊，見時還許笑言同。", "倡予和汝平生事，惆悵春風又起鴻。"]'),
('13014b03-edf2-4f85-89cf-538259d60c97','劉伯山書來云有施主爲造一亭劉子澄名曰竹溪索詩爲賦二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','竹外青原久不看，書來賸喜報平安。',64,'全唐诗/poet.song.165000.json','["竹外青原久不看，書來賸喜報平安。", "脩筠流水故亦有，高士韻人良獨難。", "杜老不應棲錦里，謫仙終合見金鑾。", "茲亭便與圖經載，何況製名繇孟韓。"]'),
('540a0642-9671-4928-8f54-3fba30e28346','劉伯山書來云有施主爲造一亭劉子澄名曰竹溪索詩爲賦二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','今人那有郗嘉賓，爲子經營茅棟新。',64,'全唐诗/poet.song.165000.json','["今人那有郗嘉賓，爲子經營茅棟新。", "可待絃歌資廼具，詎須出郭始離塵。", "舊詩頗願窮岡割，後約要容王翰鄰。", "更喚能詩子歐子，不因對月自三人。"]'),
('e72fa261-0037-404c-8905-c1db7a56e386','遊石壁寺懷禪月','趙蕃','宋','宋诗','song-poetry','','[]','一棹夷猶石壁來，寺門雜樹向溪開。',64,'全唐诗/poet.song.165000.json','["一棹夷猶石壁來，寺門雜樹向溪開。", "七言粗可供詩本，十幅誰能致襪材。", "想見高情澹雲水，未嗟陳迹掩莓苔。", "倦遊到處渾如昔，欲住還成破雨回。"]'),
('5a3b6294-9875-4a81-b63e-7d7d49647e40','登愚卿無盡藏再用韻呈愚卿','趙蕃','宋','宋诗','song-poetry','','[]','白雲故遶青原寺，青竹深藏白鷺洲。',64,'全唐诗/poet.song.165000.json','["白雲故遶青原寺，青竹深藏白鷺洲。", "物外未能窮往迹，眼中欣復對詩流。", "功名邂逅何嗟晚，歲月侵尋直漫遒。", "擬盡崎嶇仍窈窕，幾時扶策更挐舟。"]'),
('6200eba2-3b36-4cc9-a80e-095f42d48d88','宜春縣齋寒食日作','趙蕃','宋','宋诗','song-poetry','','[]','故知寒食住爲佳，可奈携家更憶家。',64,'全唐诗/poet.song.165000.json','["故知寒食住爲佳，可奈携家更憶家。", "憂樂相尋定何種，死生如夢本無涯。", "節中天色少來舊，詩裏風光別去嗟。", "李逕桃蹊事雖退，柳行因雨未拋花。"]'),
('2bfee958-2df9-43b9-be54-9d5fc36f047f','三月初二日雨人以爲風止之祥','趙蕃','宋','宋诗','song-poetry','','[]','讖言雨作風當正，得雨喜如遭旱時。',64,'全唐诗/poet.song.165000.json','["讖言雨作風當正，得雨喜如遭旱時。", "枕藉無嗔雜簑笠，跧藏不異庇茅茨。", "近看楊柳大垂手，遠對雲山圖入眉。", "日暮橫流難共濟，明當安穩遂東之。"]'),
('2b526bdc-9a98-4b23-b2fd-a693c0891cba','三月十六日郊行','趙蕃','宋','宋诗','song-poetry','','[]','乍驚風色掃羣陰，旋見朝光上遠林。',64,'全唐诗/poet.song.165000.json','["乍驚風色掃羣陰，旋見朝光上遠林。", "李徑桃蹊愁欲寂，麥畦桑畝秀何深。", "未云晨出因迎客，自喜山行不廢吟。", "春晚得晴如此少，寄聲鳩輩且停音。"]'),
('b16579bf-6992-403e-833e-88e9a710a35f','宿柞樹下見趙行之所題詩','趙蕃','宋','宋诗','song-poetry','','[]','人道朝霞不出門，今朝失喜見晴暾。',64,'全唐诗/poet.song.165000.json','["人道朝霞不出門，今朝失喜見晴暾。", "長林未減霜前翠，疊巘全收雨後昏。", "兀兀不知爲底日，悠悠又復度前村。", "眼明見此壁間句，回憶東江數過村。"]'),
('7a3afe23-376a-4c82-9560-7fdbf890301c','寄克齋舅氏','趙蕃','宋','宋诗','song-poetry','','[]','不奉書題遂一年，書猶斷絕况詩傳。',64,'全唐诗/poet.song.165000.json','["不奉書題遂一年，書猶斷絕况詩傳。", "興來亦復吟哦否，讀罷何當疾痼痊。", "慷慨初無伏波志，憂愁枉類屈原遷。", "使來覓我當何處，水出牂牁若箇邊。"]'),
('3c6dfbc7-d911-47b8-8d18-0e51bcfbf31f','次韻晁大舅祖子應','趙蕃','宋','宋诗','song-poetry','','[]','離騷皎皎在湖湘，冀北茫茫失乘黄。',64,'全唐诗/poet.song.165000.json','["離騷皎皎在湖湘，冀北茫茫失乘黄。", "徒手豈能探虎穴，敝車安得繞羊腸。", "外家文律况吾祖，有作歲時常一囊。", "天遣南來端有意，要須健筆寫秋光。"]'),
('952ab382-64c8-4a0a-a2f2-768aeb8755ad','久不領衡州舅氏書以長句問動靜','趙蕃','宋','宋诗','song-poetry','','[]','寥闊書題久不聞，可憐魚鴈動成羣。',64,'全唐诗/poet.song.166000.json','["寥闊書題久不聞，可憐魚鴈動成羣。", "未傳春興衡陽紙，長憶江東日暮雲。", "見說風帆京口泊，又云山色敬亭分。", "莫言翰墨繞遊戲，看取毛錐解致君。"]'),
('149347de-7a53-41de-9f4f-b92a5d2e7540','次韻遠齋春雨有感','趙蕃','宋','宋诗','song-poetry','','[]','春今著物幾陳新，未抵新詩得許榮。',64,'全唐诗/poet.song.166000.json','["春今著物幾陳新，未抵新詩得許榮。", "韓子雖云譽東野，侯生終竟愧彌明。", "已知林下棲遲計，何處人間寵辱驚。", "更欲從公問歸宿，夜深風雨四山傾。"]'),
('6b63d82d-520a-401f-9fc3-ac04e1ec506b','沖谷和詩惠書且有訪予之意','趙蕃','宋','宋诗','song-poetry','','[]','門外秋來草長科，寂然何止雀堪羅。',64,'全唐诗/poet.song.166000.json','["門外秋來草長科，寂然何止雀堪羅。", "清詩寄和勞相憶，手札俱來仍足多。", "豆飯芋魁吾自有，芒鞋竹杖幾時過。", "相逢不用論餘事，茲道待君相琢磨。"]'),
('24616fef-5094-49d0-b315-894dd3746b85','遊管歷院用喬子遷韻','趙蕃','宋','宋诗','song-poetry','','[]','北沙一勺淺沙泉，三日彎跧厭客船。',64,'全唐诗/poet.song.166000.json','["北沙一勺淺沙泉，三日彎跧厭客船。", "指似殿樓知有寺，經行陂泊見多田。", "清泉方斛快新浴，草屨葛衣便晚天。", "閲遍題名重惆悵，越州何許但雲烟。"]'),
('1d8e0ed7-15ff-4f59-a858-141a168468d7','生米市盡處有寺名演義有二物且得甘叔異鄧南秀簡壽玉詩','趙蕃','宋','宋诗','song-poetry','','[]','往來屢覓肩吾釣，八十初逢演義僧。',64,'全唐诗/poet.song.166000.json','["往來屢覓肩吾釣，八十初逢演義僧。", "香爇黄連雲細細，薜看石柱帔層層。", "何妨杖策往幽步，頻念竹爐眠曲肱。", "海內故人難數見，壁間時得姓名曾。"]'),
('9e372121-00ba-460f-bf4e-582a3b4bfdad','嶺路惡甚問章聖寺蓋欲投宿也書寄周袁州','趙蕃','宋','宋诗','song-poetry','','[]','舉頭易見天邊日，屬目難逢山下村。',64,'全唐诗/poet.song.166000.json','["舉頭易見天邊日，屬目難逢山下村。", "行盡土麤仍石惡，望窮雨黑與雲昏。", "此身何可數茲役，薄宦有誰能見存。", "章聖明朝還曲覩，信知緣契在空門。"]'),
('ac99ec43-b5c4-4e0d-9876-9ebdc8d9ae51','六月五夜斯遠會宿西軒爲賦七言四韻','趙蕃','宋','宋诗','song-poetry','','[]','雨餘信宿尚留凉，况是僧房對竹床。',64,'全唐诗/poet.song.166000.json','["雨餘信宿尚留凉，况是僧房對竹床。", "異日江湖成遠隔，祇今林壑可相忘。", "囊空未易蘇貧極，酒薄聊能衍話長。", "竹樹並簷雖爾密，不妨新月吐華光。"]'),
('6089eb12-5b11-4ff6-b5ce-6ff0e85f63d5','韋南雄惠酒六尊以詩謝之','趙蕃','宋','宋诗','song-poetry','','[]','叩門何處遠行人，撩亂雞飛犬吠鄰。',64,'全唐诗/poet.song.166000.json','["叩門何處遠行人，撩亂雞飛犬吠鄰。", "信有青州六從事，詎多驛使一枝春。", "經秋未愈文園病，晚歲更餘揚子貧。", "愧是無詩堪每誦，意中殊覺丈人真。"]'),
('da3549a3-eae5-46ea-a6bd-2310f587ca83','同簽判謝丈簡寄教授李丈仍用王原慶舊韻','趙蕃','宋','宋诗','song-poetry','','[]','斗酒百篇家有風，故應名墮勝流中。',64,'全唐诗/poet.song.166000.json','["斗酒百篇家有風，故應名墮勝流中。", "從教客論嘲元白，嬾向東華戀軟紅。", "好句舊來傳已熟，並遊今日敢言同。", "看公人物非如我，畢志區區在草豐。"]'),
('19d544d9-03ee-4d4f-b622-3647128bb6f3','簡謝張王臣','趙蕃','宋','宋诗','song-poetry','','[]','病過春風二月時，不知春已到酴醿。',64,'全唐诗/poet.song.166000.json','["病過春風二月時，不知春已到酴醿。", "當公置酒招新社，念我因詩辱舊知。", "豈但讙言慰羈旅，更容醉墨對淋漓。", "寒窗卧想夜來樂，門外卒然風雨馳。"]'),
('24d883f0-27d5-4e59-8a93-f22a926d395e','又簡張王臣','趙蕃','宋','宋诗','song-poetry','','[]','留落殊方少故人，豈其再見愈情親。',64,'全唐诗/poet.song.166000.json','["留落殊方少故人，豈其再見愈情親。", "幾因高論興衰颯，頻藉深杯慰苦辛。", "祇道朝天在長夏，那知奉檄又殘春。", "未聞行日先惆悵，君復何憂慨此身。"]'),
('135c5701-67f2-497a-9519-ca488ef04ef7','白水道間','趙蕃','宋','宋诗','song-poetry','','[]','一源曲折幾成橋，稻隴蔬畦高下澆。',64,'全唐诗/poet.song.166000.json','["一源曲折幾成橋，稻隴蔬畦高下澆。", "水碓暗鳴蛙吠草，綠雲亂點鷺侵苗。", "誰云斗粟可相挽，到處佳山如見招。", "東畝拔秧南畝蒔，樂哉安得助長謠。"]'),
('d3da7f1e-c9c5-49f5-b351-15a940d97a8a','贛州出示馬提刑留題麻姑山次韻','趙蕃','宋','宋诗','song-poetry','','[]','發軔名山三十年，每逄佳處一悠然。',64,'全唐诗/poet.song.166000.json','["發軔名山三十年，每逄佳處一悠然。", "獨於此地欠行迹，始信茲遊亦屬天。", "壇記舊模唐刺史，句題今誦兩詩仙。", "和篇末至夫何敢，勢似求魚乃木緣。"]'),
('407b3d37-1c42-4b61-bd9e-8f25fbd24f99','得邢廣聲書且索近詩走筆報之','趙蕃','宋','宋诗','song-poetry','','[]','春來日日雨兼風，朝暮昏昏抵夢中。',64,'全唐诗/poet.song.166000.json','["春來日日雨兼風，朝暮昏昏抵夢中。", "村巷忽聞喧吠犬，遠書何自落征鴻。", "殷勤每辱寒溫問，邂逅幾思言笑同。", "曲逆不侯繇計拙，相如遊倦欠詞工。"]'),
('1d0d446e-aaf4-453a-80dd-afccb944a565','吳仲權相別詩云欲少留桃川山中昨日同在伯懷之作詩約在伯同賦以寄并屬徐季純于去非','趙蕃','宋','宋诗','song-poetry','','[]','詩卷方欣見管斑，酒杯已復動離顔。',64,'全唐诗/poet.song.166000.json','["詩卷方欣見管斑，酒杯已復動離顔。", "余當火傘朱冠際，君政清虛爽氣間。", "逸興飄飄難並駕，好風發發待吹還。", "如舟可使長身久，有竹懸知不用關。"]'),
('27ca7778-1564-4a2b-9a3c-2dd813c59028','題湘鄉道中梅花','趙蕃','宋','宋诗','song-poetry','','[]','道上梅花無數株，似能相與慰窮途。',64,'全唐诗/poet.song.166000.json','["道上梅花無數株，似能相與慰窮途。", "色嚴不畏晨霜勁，馥賸寧須愛日敷。", "落落卒無詞客賦，紛紛只了酒家沽。", "雖然根本故亡恙，猶愈松明日夜刳。"]'),
('edeb899f-e2dd-42fe-8a80-9eb5635d9e76','長田道中梅花','趙蕃','宋','宋诗','song-poetry','','[]','臘前已賦憶梅詩，年後才能見好枝。',64,'全唐诗/poet.song.166000.json','["臘前已賦憶梅詩，年後才能見好枝。", "我亦嗟渠苦孤瘦，渠應怪我底清羸。", "雖然故有臨風趣，政爾難忘覓句癡。", "回首江東在何許，故人相遠費相思。"]'),
('97e8c254-0333-4188-94b6-25408f01a233','梅已開猶未知之簡斯遠','趙蕃','宋','宋诗','song-poetry','','[]','問梅頗復恨開遲，及至開時病不知。',64,'全唐诗/poet.song.166000.json','["問梅頗復恨開遲，及至開時病不知。", "何自折來相料理，似憐一見苦參差。", "君今政草凌雲賦，我又初無却月詩。", "風月孰於風日愈，要須一語爲評之。"]'),
('6715f46c-1daf-452f-87da-29037b66a6b6','初見梅懷玉山友弟','趙蕃','宋','宋诗','song-poetry','','[]','江路野梅初折來，班班已有數花開。',64,'全唐诗/poet.song.166000.json','["江路野梅初折來，班班已有數花開。", "細看渾覺風神在，且老空驚鬢髮摧。", "我所思兮千萬里，知其趣爾五三杯。", "半年未有音書至，未過衡陽雁已回。"]'),
('c7e4615e-d653-41f2-9dae-73b15721671c','挽李子永二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','靈山山下初逢處，溧水水邊重見時。',64,'全唐诗/poet.song.166000.json','["靈山山下初逢處，溧水水邊重見時。", "草草猶傳出山句，勤勤更枉送行詩。", "傳聞恍惚疑昇報，問訊凄凉自越醫。", "畧計別離能幾日，誰知生死遂分岐。"]'),
('60578b65-9aac-4b0f-bfec-0f315b65d357','挽李子永二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','封侯寂寞空飛將，佳句流傳自謫僊。',64,'全唐诗/poet.song.166000.json','["封侯寂寞空飛將，佳句流傳自謫僊。", "半世作民纔六考，他年垂世有千篇。", "篋中酬唱都無恙，天外音書不復傳。", "五嶺三苗底處所，千巖萬壑若何邊。"]'),
('52c7f95a-dd6a-452d-b253-311c9b6ffdf6','去德清十數里阻冰舟行甚艱','趙蕃','宋','宋诗','song-poetry','','[]','常時一夜北新橋，問訊茲來故不遥。',64,'全唐诗/poet.song.166000.json','["常時一夜北新橋，問訊茲來故不遥。", "豈慮堅冰忽成合，更當冷日未能消。", "志存紆直無渠怒，行有艱難自我招。", "頼是晴山有佳色，不然何以慰無聊。"]'),
('7aebb116-2d6d-4c54-a27a-6087dd2dae87','貴溪簡李商叟方元直','趙蕃','宋','宋诗','song-poetry','','[]','李侯佳句似陰鏗，早向茶山識贛曾。',64,'全唐诗/poet.song.166000.json','["李侯佳句似陰鏗，早向茶山識贛曾。", "滌器寧同長卿逸，閉門不學玉川憎。", "平居尚憶尋君去，南廟應還訪我能。", "詩卷當時更誰與，玄英文采被雲仍。"]'),
('04fc38f2-2ab5-4ed5-956a-edd6b2cf528b','十七日晨起簡諸公','趙蕃','宋','宋诗','song-poetry','','[]','年多病暑苦亡聊，夏忽如秋意自消。',64,'全唐诗/poet.song.166000.json','["年多病暑苦亡聊，夏忽如秋意自消。", "竹屋紙窗宵摵摵，雨條風葉曉蕭蕭。", "凶年未易辦五斗，樂處却思甘一瓢。", "幾日詩筒似疏曠，意乘聊復一長謠。"]'),
('5ead1db0-59f4-4afb-8d9f-c758cee4097c','六月十一夜簡孫子肅子儀','趙蕃','宋','宋诗','song-poetry','','[]','暑氣侵人百不堪，晚吹微喜鬢毿毿。',64,'全唐诗/poet.song.166000.json','["暑氣侵人百不堪，晚吹微喜鬢毿毿。", "手持白羽不勝倦，醉潄清泉欣爾甘。", "定夜數鍾隨谷應，臨流幾木與天參。", "况當風月佳如引，祇欠兩公相對談。"]'),
('e345a9e3-cb68-44ea-9df0-4c51f09f5588','簡季純去非','趙蕃','宋','宋诗','song-poetry','','[]','寒食今年兩日晴，已焉疏雨洗清明。',64,'全唐诗/poet.song.166000.json','["寒食今年兩日晴，已焉疏雨洗清明。", "酴醿自後牡丹發，反舌乃先鶗鴂鳴。", "多病未能疏酒盞，畏閒聊復近詩盟。", "相看政爾間何闊，異日書題空敘情。"]'),
('19ef11d4-0a25-4e11-9194-54a61a5ab516','簡斯遠兼懷成父','趙蕃','宋','宋诗','song-poetry','','[]','聞道籃輿出行田，歸來藥裹手親煎。',64,'全唐诗/poet.song.166000.json','["聞道籃輿出行田，歸來藥裹手親煎。", "旱而不雨熱尤劇，節且立秋凉未便。", "我亦南山成卧疾，弟猶北闕未迴船。", "江南已自傷流落，何况湖南路渺然。"]'),
('1dc61ffd-8592-4b96-a756-3da26cd8f3c3','簡贈吳仲權鎰','趙蕃','宋','宋诗','song-poetry','','[]','江西名士多所識，盡道延陵有異孫。',64,'全唐诗/poet.song.166000.json','["江西名士多所識，盡道延陵有異孫。", "賦就早能傳學子，詩成晚更徹宗門。", "經過縣郭辦相覓，邂逅心期欲暫論。", "禁省催君詠紅藥，江湖要我擷芳蓀。"]'),
('4599ade6-61b7-4ef9-a89c-d436d8d7b7dc','簡賈新之','趙蕃','宋','宋诗','song-poetry','','[]','君詩耻作閬仙瘦，頗厭飄零其故何。',64,'全唐诗/poet.song.166000.json','["君詩耻作閬仙瘦，頗厭飄零其故何。", "求士近聞勞仄席，斯人未用豈懸科。", "交情滿眼盡今雨，世態由來俱一波。", "所願深持後凋節，傳書獨行不爲過。"]'),
('627c84de-6330-4b66-a564-015c4d7c4156','用賒韻簡賈新之','趙蕃','宋','宋诗','song-poetry','','[]','洛陽人物舊傳誇，殊縣相依得賈嘉。',64,'全唐诗/poet.song.166000.json','["洛陽人物舊傳誇，殊縣相依得賈嘉。", "魯殿獨餘多劫火，玄都看盡幾番花。", "寓懷不但篇章好，評古猶多論議譁。", "問我若爲成間闊，路經墟落苦嫌賒。"]'),
('86cafcce-09ee-4b96-9728-746e303aa56d','驟寒簡明叔聞仲威數過之','趙蕃','宋','宋诗','song-poetry','','[]','相逢日日訝冬暄，爲此陰寒僅覆翻。',64,'全唐诗/poet.song.166000.json','["相逢日日訝冬暄，爲此陰寒僅覆翻。", "破屋未愁茅盡卷，近林無奈鳥相喧。", "馳驅短景貪黄卷，咫尺梅花憶故園。", "聞道頻迂長者轍，教兒勿掩席爲門。"]'),
('714ed9b2-7bcc-4557-b0f0-a9dc1d160d2f','用前韻再簡明叔仲威','趙蕃','宋','宋诗','song-poetry','','[]','晨興襖子欠黄綿，宿火灰深更苦翻。',64,'全唐诗/poet.song.166000.json','["晨興襖子欠黄綿，宿火灰深更苦翻。", "官冷自疏鳬鶩進，兒饑不作鴈鵝喧。", "孰云數口須微祿，已料此身終灌園。", "二子交期非勢利，故能衝雀屢排門。"]'),
('4f964cb6-05f6-4eeb-a086-bfdcffcf9fa0','藥圃舊無竹僕爲作詩從閑止乞栽','趙蕃','宋','宋诗','song-poetry','','[]','如聞舊隠竹多有，想見頻年筍更添。',64,'全唐诗/poet.song.166000.json','["如聞舊隠竹多有，想見頻年筍更添。", "一日借居無不可，數竿分我未傷廉。", "懸知影可連書屋，便恐山無到野簷。", "如許作謀還自笑，未應於此是真潛。"]'),
('569b38bc-6e00-4d00-a291-4c2ea9a7511e','重懷思隠之作因回使寄明叔兼呈從禮景立','趙蕃','宋','宋诗','song-poetry','','[]','問訊新篁今幾長，高應出屋下侵廊。',64,'全唐诗/poet.song.166000.json','["問訊新篁今幾長，高應出屋下侵廊。", "遥憐初日弄碎影，相見午風傳細香。", "卧看行吟君得意，晝思宵寐我回腸。", "譍門爲戒須高眼，有客能來儻姓王。"]'),
('290e7f51-b678-4b89-a088-77a82d0b478e','去非尉曹於廨舍之側鑿池種竹爲亭其上名曰有竹取文公詩云也','趙蕃','宋','宋诗','song-poetry','','[]','舊日南州於去非，一官黄綬不嫌卑。',64,'全唐诗/poet.song.166000.json','["舊日南州於去非，一官黄綬不嫌卑。", "要爲賓主壺觴地，因著胸中水竹期。", "怪底不同東野耄，政由深得退之奇。", "過君池草生春日，憶我叢篁長夏時。"]'),
('f41f0e43-f42c-4f6a-8f5c-bcd9bc25d4ed','乞竹亡有藥圃主人買以種之','趙蕃','宋','宋诗','song-poetry','','[]','時人蘄惜千金費，肯似俞郎買竹栽。',64,'全唐诗/poet.song.166000.json','["時人蘄惜千金費，肯似俞郎買竹栽。", "老節尚封南磵雪，定交新得北枝梅。", "幽禽亦自知人意，度日頻能爲我來。", "十飯未妨全不肉，上番春筍待新雷。"]'),
('40e48118-2c76-4b9f-b588-e4d72a679d0f','建德道間','趙蕃','宋','宋诗','song-poetry','','[]','婦並蠶筐候蠶浴，兒眠牛背趁牛行。',64,'全唐诗/poet.song.166000.json','["婦並蠶筐候蠶浴，兒眠牛背趁牛行。", "要知比屋俱無事，看取人家盡樂生。", "麥畦就熟黄雲委，秧壠初齊綠浪生。", "快活收聲聞布穀，可憐鳥語近人情。"]'),
('e8ca3004-fb79-4b97-93df-6b7de4d4991b','蕃來湖州連與叔驥和叔明父叔寶相從又從和叔獲見先給事遺墨輒賦二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','東南名勝白蘋州，人物咸推故國劉。',64,'全唐诗/poet.song.166000.json','["東南名勝白蘋州，人物咸推故國劉。", "往歎賦歸何勇决，今觀遺翰許風流。", "遠齋視我曾青眼，酒正今年成白頭。", "尚喜君家文墨事，到今三世未能休。"]'),
('857f7190-f931-4919-9c82-dce379fe8bb7','蕃來湖州連與叔驥和叔明父叔寶相從又從和叔獲見先給事遺墨輒賦二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','邂逅忽成三癸亥，就中和也少三年。',64,'全唐诗/poet.song.166000.json','["邂逅忽成三癸亥，就中和也少三年。", "諸公濯濯故如許，老我蕭蕭真足憐。", "少住政當愁雪日，欲行翻是喜晴天。", "東南故舊多離闊，猶喜丞能共此筵。"]'),
('a9668b03-d047-478d-ba7a-8eadd59a38b1','登李叔器家見一亭','趙蕃','宋','宋诗','song-poetry','','[]','別駕當年蚤見幾，郎君久亦棄文闈。',64,'全唐诗/poet.song.166000.json','["別駕當年蚤見幾，郎君久亦棄文闈。", "閉門幽徑滋蒼蘚，杖策高亭接翠微。", "試問丘園返初服，定勝風雨蓋征衣。", "一官政爲饑寒計，未免饑寒故不歸。"]'),
('8b01e1c1-ecc5-4c21-bc45-9a7a65f0086b','贛丞陳擇之官滿歸清江追餞珠林','趙蕃','宋','宋诗','song-poetry','','[]','經行此地幾維舟，我亦飄零苦倦遊。',64,'全唐诗/poet.song.166000.json','["經行此地幾維舟，我亦飄零苦倦遊。", "旱久未教梅破臘，霜遲留得草含秋。", "離懷不似殘年促，細雨何如驟雪收。", "底事令人重分首，自茲出處恐殊謀。"]'),
('0854119b-6076-460b-bc67-c531a67665b2','程季儀沈儉夫携酒見餞於湘中館借用季儀所次五峰先生舊韻見懷之作','趙蕃','宋','宋诗','song-poetry','','[]','擬和題詩畧未成，卒然風雨暗前津。',64,'全唐诗/poet.song.166000.json','["擬和題詩畧未成，卒然風雨暗前津。", "高秋政應凉如水，餘溽胡爲暖似春。", "載酒肯來真好事，艤舟聊爲駐行人。", "異時懷玉山前過，一訪耕桑老病身。"]'),
('ff391ff3-16b4-49a2-9545-059dafb723fd','謝李正之惠潘墨','趙蕃','宋','宋诗','song-poetry','','[]','地爐窮日坐寒灰，顧與貍奴爭席隈。',64,'全唐诗/poet.song.166000.json','["地爐窮日坐寒灰，顧與貍奴爭席隈。", "硯少磨研塵滿面，筆疏驅使腐生莓。", "慇懃不記玄圭覓，邂逅欣同賜璧來。", "藥裹關心廢詩久，恐因詩械却爲災。"]'),
('2c780553-27e8-440e-ae01-81dd6d0013f2','曾郢州携和詩見過次韻謝之','趙蕃','宋','宋诗','song-poetry','','[]','家世風流翰墨林，政和佛祖務傳心。',64,'全唐诗/poet.song.166000.json','["家世風流翰墨林，政和佛祖務傳心。", "浮辭肯作齊梁體，古調直諧韶濩音。", "入社敢期陪唱屬，贈言從此得參尋。", "惠然更辱高軒過，不問春溪綠漲深。"]'),
('c15593f7-37d9-417b-a288-dfd8456af686','留別周參政詩二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','元祐登瀛盛古今，祇今衰冷媿諸任。',64,'全唐诗/poet.song.166000.json','["元祐登瀛盛古今，祇今衰冷媿諸任。", "聖朝既有徐州相，得路仍知異日心。", "齷齪更無微價市，鷦鷯自愛一枝深。", "故同坎軻荆蠻徙，昔所悲歌今放吟。"]'),
('b47b9d81-1fb0-4767-8232-4bedb43fcde9','留別周參政詩二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','故意還叨累十觴，諸家所歷信踰常。',64,'全唐诗/poet.song.166000.json','["故意還叨累十觴，諸家所歷信踰常。", "黄塵倦馬久非地，野水白鷗終是鄉。", "勾漏不惟兼採藥，長沙更欲訪沉湘。", "憑虛便謂神仙近，却覺仕途真渺茫。"]'),
('ffc46722-d351-4e44-a85a-24ab1949968b','程士和和詩送酒復用韻','趙蕃','宋','宋诗','song-poetry','','[]','半夜詩成疾置看，甚思走筆退知難。',64,'全唐诗/poet.song.166000.json','["半夜詩成疾置看，甚思走筆退知難。", "我如楓葉非關伐，君比梅花不带酸。", "豈是獨醒羞衆醉，政由尚白懼朱丹。", "一尊重辱相料理，不爾何緣罄一歡。"]'),
('474dff7c-97c6-4ff4-b306-565575ff3080','趣成父寄酒','趙蕃','宋','宋诗','song-poetry','','[]','如聞已熟遂初泉，日日江頭數過船。',64,'全唐诗/poet.song.166000.json','["如聞已熟遂初泉，日日江頭數過船。", "梅嶺望來能止渴，麴車逢處解流涎。", "故人海內忘形少，風味杯中到手賢。", "遥想容齋對陳子，有時醉倒竹騷然。"]'),
('ffdb5507-d46b-487b-a8c6-6e80475af71f','喜俞玉汝見過','趙蕃','宋','宋诗','song-poetry','','[]','秋風起我友朋思，倚樹談君語未移。',64,'全唐诗/poet.song.166000.json','["秋風起我友朋思，倚樹談君語未移。", "祇道窮年上湖海，那知今日會茅茨。", "病多止酒家無釀，貧乏贏糧甑罕炊。", "作底勤渠相勞苦，倒囊共出別來詩。"]'),
('3f32a023-2874-4faa-93c5-78ed68303af6','明叔今日不過書齋','趙蕃','宋','宋诗','song-poetry','','[]','竹屋深深晝亦陰，病多無復短長吟。',64,'全唐诗/poet.song.166000.json','["竹屋深深晝亦陰，病多無復短長吟。", "三年肯住見君意，一日不來關我心。", "蟬噪未知秋日晚，雀投如識故枝深。", "殘書亂帙慷能整，倚頼殘樽尚可斟。"]'),
('ed57706b-16ab-4548-9479-217a50d9a7d1','呈衡州使君先生二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','當年月以秋中過，今歲凉因閏故遲。',64,'全唐诗/poet.song.166000.json','["當年月以秋中過，今歲凉因閏故遲。", "渴想話言思亟見，暑侵鞍馬敢云疲。", "曾聞遺俗有存者，豈若吾身親見之。", "少不如人今老矣，朝聞夕死庶幾爲。"]'),
('13277452-cc72-441d-ab26-0aa202fc26ca','呈衡州使君先生二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','常州何乃又衡州，或謂茲行乃勝遊。',64,'全唐诗/poet.song.166000.json','["常州何乃又衡州，或謂茲行乃勝遊。", "鍾鼓相聞尋嶽寺，茝蘭無數踏湘流。", "是中夫豈先生樂，此段聊供幽子求。", "嶽麓相望唯石鼓，要令吾輩務藏修。"]'),
('19b13b20-2f1d-4b10-aae5-9f2481a3177d','清江道中','趙蕃','宋','宋诗','song-poetry','','[]','自入西江絕少山，蹔看平遠又彎環。',64,'全唐诗/poet.song.166000.json','["自入西江絕少山，蹔看平遠又彎環。", "望窮浩浩鷗波裏，詩墮蒼蒼暮色間。", "網戶謾多魚踴價，酒壚雖少客酡顔。", "兒時所歷今重過，無復衣斑徒鬢斑。"]'),
('6e1e7708-03a7-488a-91fe-962ac0668f94','次韻陳縣丞謝送筍','趙蕃','宋','宋诗','song-poetry','','[]','官曹常恐廢書勳，頼是相看有竹君。',64,'全唐诗/poet.song.166000.json','["官曹常恐廢書勳，頼是相看有竹君。", "送筍但知修歲例，辱詩還喜繼前聞。", "饞涎肯爲口腹計，幽處要期風月分。", "我事且然成忤俗，奈何君復露奇文。"]'),
('84303176-9926-439d-b2b9-2247ae83f764','晚晴四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','殘風落日蟬亂鳴，細履小園欣晚晴。',64,'全唐诗/poet.song.166000.json','["殘風落日蟬亂鳴，細履小園欣晚晴。", "投林倦鳥分暝色，滿地落葉無秋聲。", "衛尉一錢曾不直，阮郎幾屐畢此生。", "三十六中第一策，脫却世故甘傭耕。"]'),
('9d7f539d-4026-4f1d-9e61-d2b4c2f665d4','晚晴四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','五日舟行雨間晴，晚逢寒日上晴林。',64,'全唐诗/poet.song.166000.json','["五日舟行雨間晴，晚逢寒日上晴林。", "山因絕翳修眉展，水得無風墜鏡深。", "可恨飄零獨南北，不如水鳥共浮沈。", "向來止酒緣多病，新爲清羸又一斟。"]'),
('acb7626f-c7f1-4c05-b9bf-93b929842185','晚晴四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','度月陰霾增病苦，重陽開霽見秋新。',64,'全唐诗/poet.song.166000.json','["度月陰霾增病苦，重陽開霽見秋新。", "菌生康樂登山屐，塵敗淵明漉酒巾。", "强擬扶持成小憇，路逢借問一何頻。", "莫驚老瘦非前日，看即推遷類昔人。"]'),
('eead34f6-3fb3-4df2-ab10-e5045e816482','晚晴四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','不知林薄上新月，但見村墟生遠烟。',64,'全唐诗/poet.song.166000.json','["不知林薄上新月，但見村墟生遠烟。", "滿地蟬聲爭嘒嘒，連溪鷺影落翩翩。", "舊時不負登臨集，未老還爲疾病纏。", "頼得一晴供節物，未妨七字發孤妍。"]'),
('d9e77f16-8eee-4c29-9d33-3e126a5c63b7','孝揚成父約見過屢展期云須晴也','趙蕃','宋','宋诗','song-poetry','','[]','雨到叢篁忽暗鳴，譙門應已載傳更。',64,'全唐诗/poet.song.166000.json','["雨到叢篁忽暗鳴，譙門應已載傳更。", "伯淮被冷睡難著，孺子榻空塵欲生。", "幾戒樵青成痛掃，屢聞黄耳遞虛聲。", "逢迎可待休形歎，祇恐窮冬無好晴。"]'),
('40057ebd-b8a8-4519-966c-674ca8a7bfe7','呈劉通判  其一','趙蕃','宋','宋诗','song-poetry','','[]','自昔旴江妙人物，未容修水擅璵璠。',64,'全唐诗/poet.song.166000.json','["自昔旴江妙人物，未容修水擅璵璠。", "獄平冤滯繇仁勇，衆息讙譁頼德言。", "謂繼更生校中秘，却追子驥問桃源。", "神仙天上多官府，盍鄉蓬萊蹔弭轅。"]'),
('9e9f6b62-a73b-465d-9ae4-3d4591bd8062','呈劉通判  其二','趙蕃','宋','宋诗','song-poetry','','["\u6cf0\u5c71"]','陰伏陽升直泰辰，當年猶想降庚寅。',64,'全唐诗/poet.song.166000.json','["陰伏陽升直泰辰，當年猶想降庚寅。", "泰山北斗人皆仰，和氣春風德有鄰。", "會即吹噓九天上，豈徒風月五溪濱。", "不惟相國同年契，更有齊年相國人。"]'),
('448ef034-89d5-41ff-ae84-6066a403d1fb','過在伯於學中','趙蕃','宋','宋诗','song-poetry','','["\u8861\u5c71"]','曉出城南日映光，水烟橫截樹烟長。',64,'全唐诗/poet.song.166000.json','["曉出城南日映光，水烟橫截樹烟長。", "多聞政欲從君語，造請寧能遣我忙。", "勝可作亭攄意匠，醉因種竹試傳方。", "規摹豈止衡山小，安得高歌題屋梁。"]'),
('934cdeaa-3dcb-4828-a833-2347cca2906a','呈廣仲運幹','趙蕃','宋','宋诗','song-poetry','','[]','招真巖畔菊花秋，憶昨賦詩相贈投。',64,'全唐诗/poet.song.166000.json','["招真巖畔菊花秋，憶昨賦詩相贈投。", "不但居民思憇樹，每令客子擊行舟。", "只言騰踏已云遠，豈料轉輸由爾留。", "我亦老焉猶昔日，倚樓看鏡兩悠悠。"]'),
('0b89abdb-418b-4f3f-8be4-728fc1b1337c','負暄','趙蕃','宋','宋诗','song-poetry','','[]','天公知我寒無褐，惠以簷間百尺裘。',64,'全唐诗/poet.song.166000.json','["天公知我寒無褐，惠以簷間百尺裘。", "挾纊固殊如是想，索衣不歎晚爲謀。", "神融遽合莊周夢，意氣俄乘竹葉舟。", "側聽屋山雞正午，又愁寒雀暮啾啾。"]'),
('960bffc3-82b4-4a7f-a59e-42bf20fcd33d','送潘湖南二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','湖海頻年歷四遷，治聲往往遂無前。',64,'全唐诗/poet.song.166000.json','["湖海頻年歷四遷，治聲往往遂無前。", "長沙夜席喜今召，右史素風追昔傳。", "要識平治端有道，不知論奏孰爲先。", "豈惟人士想風采，聞說天心正渴賢。"]'),
('f5ecc0dc-de2e-4506-b954-39014156d6c2','送潘湖南二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','名世公今第一流，百年端見幾人不。',64,'全唐诗/poet.song.166000.json','["名世公今第一流，百年端見幾人不。", "臨民不作子桑簡，好善咸推樂正優。", "侍從近臣方妙選，林園勝事未宜休。", "曾聞王貢彈冠事，無奈相如故倦遊。"]'),
('c725a129-3375-4a6a-a5ee-2aab84239688','和青田劉令同年見答寄茶之作','趙蕃','宋','宋诗','song-poetry','','[]','越國春芽舊有聞，換來佳句益堪珍。',64,'全唐诗/poet.song.166000.json','["越國春芽舊有聞，換來佳句益堪珍。", "主張品格曾無過，吟寫工夫直有神。", "鴻漸烹煎應巧密，玉川才調本清新。", "索居海角凄凉甚，時得吟哦慰此身。"]'),
('5d0545ef-19ef-4a09-b12d-728a46cf0444','周愚卿求所藏靈壁石名堆雲','趙蕃','宋','宋诗','song-poetry','','[]','一自風塵沒泗濱，英遺何敢漫嶙峋。',64,'全唐诗/poet.song.166000.json','["一自風塵沒泗濱，英遺何敢漫嶙峋。", "崩騰直自天邊落，拳握空夸席上珍。", "好事了知真是癖，傾家務買不論貧。", "不來俗客仍須鑰，夜半負舟端有人。"]'),
('f8bdab08-76ed-41cd-9bad-9b28dd0aeb86','六月初九日晚大雨簡文顯子暢','趙蕃','宋','宋诗','song-poetry','','[]','千里歸來病作勞，偶因好雨試揮毫。',64,'全唐诗/poet.song.166000.json','["千里歸來病作勞，偶因好雨試揮毫。", "凉聲何止到草木，秋意直將侵鬢毛。", "坐念司功狂欲叫，更懷元亮卧方高。", "何當過我茅簷底，不獨譚詩亦具醪。"]'),
('89b9b746-8a5c-4276-8bd8-7aaf8d078465','午風大作已雨甚微','趙蕃','宋','宋诗','song-poetry','','[]','老屋支風懼壓焉，若爲吹雨但疏然。',64,'全唐诗/poet.song.166000.json','["老屋支風懼壓焉，若爲吹雨但疏然。", "池蛙閤閤自得意，圃蝶飛飛人故憐。", "玩物不妨尋物理，得閑聊爾賦閑篇。", "枕書幾欲成幽睡，又怕饑鼯攪夜眠。"]'),
('141aac6f-5456-4348-b316-3afa0374a8d8','莫萬安以甘雨應候用社日韻作詩見貽次韻','趙蕃','宋','宋诗','song-poetry','','[]','今君憂樂皆農務，信有雨來晴便晴。',64,'全唐诗/poet.song.166000.json','["今君憂樂皆農務，信有雨來晴便晴。", "寧似倦遊傷偪仄，不堪終日屢昏明。", "歸舟凈綠不可唾，舊舍小灘渾欲平。", "元是江湖竿釣伴，可須釣叟自爲名。"]'),
('4aa2ae86-2be4-4eb0-aeda-bc668f254953','子暢雨中見過且惠以詩乃用蕃謝文顯載酒之韻復用韻爲答併簡文顯  其一','趙蕃','宋','宋诗','song-poetry','','[]','草本荒凉門半掩，故人誰肯爲予來。',64,'全唐诗/poet.song.166000.json','["草本荒凉門半掩，故人誰肯爲予來。", "要師原憲安非病，敢學襄陽怨不才。", "春自堂堂花更落，髮今種種老其催。", "謝安故有東山志，過我題詩拭硯埃。"]'),
('12bba833-cd4a-42b3-94c0-2d7baf47337b','子暢雨中見過且惠以詩乃用蕃謝文顯載酒之韻復用韻爲答併簡文顯  其二','趙蕃','宋','宋诗','song-poetry','','[]','雨合茅簷書罷看，惠然君乃過蘇端。',64,'全唐诗/poet.song.166000.json','["雨合茅簷書罷看，惠然君乃過蘇端。", "澆胸細酌杯中物，洗耳飽聽溪上湍。", "近喜同參詩有味，晚期偕隠谷名盤。", "因聲寄謝周夫子，文行如斯古亦難。"]'),
('9fc86037-c478-4a84-8ba6-63b8c80dccab','畢叔文以雙頭白蓮送程士和錄唱酬詩以求次韻','趙蕃','宋','宋诗','song-poetry','','[]','是間何處有漣漪，况復雙蓮爲出奇。',64,'全唐诗/poet.song.166000.json','["是間何處有漣漪，况復雙蓮爲出奇。", "要使惔焚成一洗，政須冰雪露多姿。", "折來不許從君玩，賦就空能喚我爲。", "已見神人出姑射，定煩朝日避咸池。"]'),
('a7a04e06-54c4-4cff-92fa-28535b332215','次韻簽判丈牡丹','趙蕃','宋','宋诗','song-poetry','','[]','長紅小白總堪珍，一見名芳歎絕塵。',64,'全唐诗/poet.song.166000.json','["長紅小白總堪珍，一見名芳歎絕塵。", "疇昔空傳醉翁譜，祇今如訪洛陽春。", "重跗固已稱尤美，徑尺真成出斬新。", "好物堅牢世那有，莫嗔採掇付厨人。"]'),
('421155bc-78f2-4a1b-bd6b-ef07edaa8e12','次韻畢叔文牡丹','趙蕃','宋','宋诗','song-poetry','','[]','春來不雨即衝風，紙貴衝陽欠此工。',64,'全唐诗/poet.song.166000.json','["春來不雨即衝風，紙貴衝陽欠此工。", "未問姚黄并魏紫，但思澗碧與山紅。", "敲門惠我枉新作，展卷想君恰遶叢。", "舊事與誰談洛下，倦遊聊爾話黔中。"]'),
('59e0bfa5-806e-448f-a3f9-56c7fe82a89d','嚴從禮折送牡丹且副以詩次韻','趙蕃','宋','宋诗','song-poetry','','[]','幾日雲昏病亦昏，問春咫尺負名園。',64,'全唐诗/poet.song.166000.json','["幾日雲昏病亦昏，問春咫尺負名園。", "兩枝何自落書几，一笑爲之開酒尊。", "怪底江南新種得，未饒洛下舊名喧。", "不然故有栽培力，能使芳根學返魂。"]'),
('8fdb975d-e959-4ed5-8bc1-2608ef25b679','水仙','趙蕃','宋','宋诗','song-poetry','','[]','楚辭香草費磨研，何獨無言到水仙。',64,'全唐诗/poet.song.166000.json','["楚辭香草費磨研，何獨無言到水仙。", "薦菊要令和靖配，思鱸更儗步兵賢。", "未應玉樹能回死，寧與梅花作導前。", "多坐未能空結習，故遭天女散諸天。"]'),
('6740181d-4d02-43cf-9f1e-5ad472aa37ea','倪先輩送水仙一科數花','趙蕃','宋','宋诗','song-poetry','','[]','倪郎知我愁無度，故遣水仙來叩關。',64,'全唐诗/poet.song.166000.json','["倪郎知我愁無度，故遣水仙來叩關。", "悄悄如逢度相遠，亭亭似直待夫還。", "飄流歌舞餘杯斝，脫略簪筓失珮環。", "寒眼何堪重對此，一軒風月閉窮山。"]'),
('a817c2e4-29dc-468d-9ea7-29ce2364228e','詠書齋梅','趙蕃','宋','宋诗','song-poetry','','[]','憶昨看梅恨不早，而今顧索晚方開。',64,'全唐诗/poet.song.166000.json','["憶昨看梅恨不早，而今顧索晚方開。", "朝來已作二月暖，花事應憐老境催。", "防護可加人漫巧，飄零未免句空哀。", "夜深耿耿欲忘寐，明日更憂風雨來。"]'),
('c780394e-d856-49a3-a517-634743e4b38e','陳嚴二君頻送蠟梅因以成詠','趙蕃','宋','宋诗','song-poetry','','[]','綴蠟爲花荆作枝，列爲梅種自何時。',64,'全唐诗/poet.song.166000.json','["綴蠟爲花荆作枝，列爲梅種自何時。", "詩多草木初無與，賢比蘭荃又見遺。", "祇道品題終不遇，豈期坡谷解相知。", "却憐二士空齊魯，不及西都講盛儀。"]'),
('d5c96d6c-650f-439b-b181-1621db24b678','觀邢園梅偶成長句錄呈上饒故人段元衡鈞','趙蕃','宋','宋诗','song-poetry','','[]','今年未省賦梅詩，疾病侵陵道路疲。',64,'全唐诗/poet.song.166000.json','["今年未省賦梅詩，疾病侵陵道路疲。", "兩日喜逢新霽後，數株還見欲開時。", "色香於汝寧能盡，心迹如余只自知。", "不是新來苦耽酒，捨渠何以慰支離。"]'),
('23877694-f9a6-4ab9-86d7-cd97bf4ddcec','早歲','趙蕃','宋','宋诗','song-poetry','','[]','早歲耽詩老不工，但餘多難似詩窮。',64,'全唐诗/poet.song.166000.json','["早歲耽詩老不工，但餘多難似詩窮。", "忽來數紙丁寧甚，怳憶他時繾綣同。", "幕府十年公勿厭，風霜滿面我思東。", "幾因江發蠻夷漲，欲問漁翁借短篷。"]'),
('6db0cddc-728d-47fd-8f07-761297606441','田家即事','趙蕃','宋','宋诗','song-poetry','','[]','漫道詩書可起家，未知田舍足生涯。',64,'全唐诗/poet.song.166000.json','["漫道詩書可起家，未知田舍足生涯。", "不辭傴僂翁栽稻，能作紛耘婦剝麻。", "口腹定繇勤力許，衣裘寧怕大寒加。", "罔知耕稼求溫飽，行役雖勞莫重嗟。"]'),
('14cd8175-6174-4a58-b857-be7ac013ee58','聞桑葉賤甚感歎有作','趙蕃','宋','宋诗','song-poetry','','[]','種得桑栽接始成，剃鋤長及夏時營。',64,'全唐诗/poet.song.166000.json','["種得桑栽接始成，剃鋤長及夏時營。", "葉黄已說都無價，蠶老那知轉更平。", "自是初頭放種薄，曷能斷手有絲贏。", "田租減放猶科校，况此全催可後程。"]'),
('27c21aae-0b00-48d9-86b1-3c6d578f4be1','偶成','趙蕃','宋','宋诗','song-poetry','','[]','落盡羣芳未肯晴，重尋破褐尚寒生。',64,'全唐诗/poet.song.166000.json','["落盡羣芳未肯晴，重尋破褐尚寒生。", "風輕簷廡頻來燕，雨合林園未有鶑。", "慷慨董生悲不遇，蕭條靖節賦閒情。", "倚樓看鏡徒增歎，散髮采薇真是清。"]'),
('29f302f3-5ec8-443d-a9b0-81c688bd258b','即事','趙蕃','宋','宋诗','song-poetry','','[]','秋日勝春句匪誇，信春無頼覺秋佳。',64,'全唐诗/poet.song.166000.json','["秋日勝春句匪誇，信春無頼覺秋佳。", "睡餘對客霏談屑，茶罷卷書揩眼花。", "寂歷斜陽簷影斷，蕭疎黄葉雀聲譁。", "家貧尊酒雖無舊，多謝鄰翁許屢賒。"]'),
('36906ebe-8db9-4f5a-8275-19803e606172','寄周內翰','趙蕃','宋','宋诗','song-poetry','','[]','一自春風辱報書，後來安否定何如。',64,'全唐诗/poet.song.166000.json','["一自春風辱報書，後來安否定何如。", "江山我敢涪翁後，事業公真六一餘。", "百年半途過九十，千間大厦豈無廬。", "不知蹀躞天街馬，孰愈崎嶇經壑車。"]'),
('b0277acb-f976-47d4-9fac-dbb452d3f4ef','上七里嶺','趙蕃','宋','宋诗','song-poetry','','[]','天公知我行良苦，垂上嶺時容少晴。',64,'全唐诗/poet.song.166000.json','["天公知我行良苦，垂上嶺時容少晴。", "登山著履自不惡，卧遊作圖空復情。", "此來豈止試脚力，政坐久不尋詩盟。", "山礬雪白藤花赤，高樹木蘭低紫荆。"]'),
('47b6b376-086a-402c-b1af-5ccdd167aae5','晨起聞徐應卿誦季益詩作詩寄季益兼簡公擇','趙蕃','宋','宋诗','song-poetry','','[]','詩工於我貧相似，憇跡招提亦爾同。',64,'全唐诗/poet.song.166000.json','["詩工於我貧相似，憇跡招提亦爾同。", "問訊稍愆書草草，往來長恨馬匆匆。", "黄花紅葉時將晚，衰髮蒼顔道轉公。", "寄謝俞郎近安否，會看摶翮上秋風。"]'),
('bfac5a9d-dfe9-4f32-822a-38ce08264903','呈簡壽玉','趙蕃','宋','宋诗','song-poetry','','[]','門外雙槐日已高，庭中鉅竹與爭豪。',64,'全唐诗/poet.song.166000.json','["門外雙槐日已高，庭中鉅竹與爭豪。", "蕭蕭共倚青雲翰，渺渺仍工白雪操。", "欲向瀟湘訪蘭芷，却從吳越看波濤。", "問君役役胡爲爾，我亦歎嗟出入勞。"]'),
('861134af-a6d7-41ec-8f20-9b7210829d93','簽判丈見約同諸丈携酒過賈新之運屬適以周侍郎過郡附舟謁之比到城周已先去既失見周又失與賈集不勝悵恨因成長句呈簽判丈運屬丈','趙蕃','宋','宋诗','song-poetry','','[]','載酒俱期過閬仙，悵然何事獨求船。',64,'全唐诗/poet.song.166000.json','["載酒俱期過閬仙，悵然何事獨求船。", "春風易遠朝天旆，夜雨空成借榻眠。", "誰謂此行真不遇，了知一笑欠前緣。", "連朝定有新酬唱，到我凡當第幾篇。"]'),
('613a6c71-533b-44ca-bc04-952da9a2a2e9','在伯欲見洪龜父夏均文詩因逸歸玉山取之自常德先寄以來偶得長句遣呈','趙蕃','宋','宋诗','song-poetry','','[]','疾風不雪翻成雨，甚欲相過愁出門。',64,'全唐诗/poet.song.166000.json','["疾風不雪翻成雨，甚欲相過愁出門。", "短日已曛燈未上，曲身難直坐如蹲。", "兒歸尚作他州隔，書到能開病眼昏。", "併致江西洪夏集，一樽徑欲與君論。"]'),
('1c3679b6-4679-414a-a6e2-2a42195ab96c','呈晦菴二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','一紙書來遂隔年，江湖遠地水連天。',64,'全唐诗/poet.song.166000.json','["一紙書來遂隔年，江湖遠地水連天。", "紛紛橫路又逢此，凜凜歲寒嗟獨然。", "學道終期世勳業，抄經蹔了佛因緣。", "白頭下士重來拜，依舊鷗汀鷺渚邊。"]'),
('bf97210d-9d08-4b59-9f75-a72db7f946e1','呈晦菴二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','不上龍門五過秋，袖詩還是覓扁舟。',64,'全唐诗/poet.song.166000.json','["不上龍門五過秋，袖詩還是覓扁舟。", "胡然貧病祇如昔，聽爾行藏隨所由。", "未厭室人能我讁，故防知己作公羞。", "孟郊五十酸寒尉，想見溧陽神尚遊。"]'),
('23fbd6fa-1a92-4ef5-8e70-d38550470c68','呈康職君謨','趙蕃','宋','宋诗','song-poetry','','["\u897f\u6e56"]','高譚自可解人頤，何况携醪烹伏雌。',64,'全唐诗/poet.song.166000.json','["高譚自可解人頤，何况携醪烹伏雌。", "衰白無庸辨鬚髮，困窮端只坐書詩。", "西湖閲境君其訪，南畝深耕我自期。", "異日書來話疇昔，黄溪寺下雨昏時。"]'),
('d3202880-d7cb-439f-849e-f2f79d926df6','呈季承','趙蕃','宋','宋诗','song-poetry','','[]','發舒言笑非關酒，慰藉辛勤一以詩。',64,'全唐诗/poet.song.166000.json','["發舒言笑非關酒，慰藉辛勤一以詩。", "往日追從雖舊矣，祇今夷險更同之。", "真仙巖壑君行訪，快閣江山我亦披。", "但恐衡陽無過鴈，書筒不至費人思。"]'),
('1afc6c2a-9746-48d1-9b81-7a3739a0433d','呈周昭禮二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','自從君發信州船，令我登臨每悵然。',64,'全唐诗/poet.song.166000.json','["自從君發信州船，令我登臨每悵然。", "把臂真成一傾倒，轉頭知隔幾山川。", "憎余况有年年惡，美子詩堪句句傳。", "記取相逢又相別，菊枯荷盡早梅前。"]'),
('ca0f8fb2-15fb-4760-a3d1-6e3d2a901cd5','呈周昭禮二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','又向江頭覓去船，故山歸路反茫然。',64,'全唐诗/poet.song.166000.json','["又向江頭覓去船，故山歸路反茫然。", "秋鴻社燕各千里，落日殘霞同一川。", "酒得老兵猶可飲，詩須我輩始堪傳。", "經行到處無生景，平日夢中今目前。"]'),
('9a5e4841-b452-4f5a-b31a-286a32a583cd','呈劉子後趙行之司理舅二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','南渡凄凉六十年，故家遺俗日蕭然。',64,'全唐诗/poet.song.166000.json','["南渡凄凉六十年，故家遺俗日蕭然。", "不應門戶端如此，政坐吾曹欠勉旃。", "斗食我今悲白髮，束書今喜繼青氈。", "鄉來未識衡州士，閭里皆推有此賢。"]'),
('8ae025f0-8925-4ca2-b85c-81d9f9da07fa','呈劉子後趙行之司理舅二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','忽忽江頭住一旬，敢疏請謁恐煩人。',64,'全唐诗/poet.song.166000.json','["忽忽江頭住一旬，敢疏請謁恐煩人。", "肯敦宿昔論交舊，更辱慇懃枉句新。", "已向清澌看流水，更從高節撫霜筠。", "白醪煮餠留終日，吾舅於今驚座陳。"]'),
('4e44f924-d842-456c-8793-cab6427bb0d3','告別晦菴晦菴有惜別語因用張志和答陸羽問作詩呈之','趙蕃','宋','宋诗','song-poetry','','[]','負笈初忘道阻長，求船翻爲歲犇忙。',64,'全唐诗/poet.song.166000.json','["負笈初忘道阻長，求船翻爲歲犇忙。", "一尊故惜時重與，四海當知別未嘗。", "渭北江東無異轍，太虛明月本同光。", "屬公忽諱輕爲別，遣客仍知醉不忘。"]'),
('1d9a799f-7896-4141-900f-71bdf0ad7e46','用文顯秋字韻呈簽判丈兼簡子暢兄','趙蕃','宋','宋诗','song-poetry','','[]','林園瑟縮似高秋，門巷蕭條若故侯。',64,'全唐诗/poet.song.166000.json','["林園瑟縮似高秋，門巷蕭條若故侯。", "粗有百篇兒可誦，何須四海轍能周。", "憐才滿世今誰是，好士如公獨見優。", "父子曾聞自知己，朅來敢意許同遊。"]'),
('7fe56678-67f0-4931-940a-8943c282cc16','雨後呈斯遠','趙蕃','宋','宋诗','song-poetry','','[]','已是霜凝更雨溫，春其漸起但無痕。',64,'全唐诗/poet.song.166000.json','["已是霜凝更雨溫，春其漸起但無痕。", "莫嗟草色有垂死，定自梅花當返魂。", "小駐要須窮日日，細尋無惜遍村村。", "揩摩病目從茲始，併待君詩洗睡昏。"]'),
('021f4050-bd2d-42fc-b24e-3f9d40c1876d','呈慶伯','趙蕃','宋','宋诗','song-poetry','','[]','開到牡丹春十分，不堪風雨尚紛紛。',64,'全唐诗/poet.song.166000.json','["開到牡丹春十分，不堪風雨尚紛紛。", "酒杯强適誰知我，藥裹關心更念君。", "老去青衫甚藍縷，愁來白髮嬾鋤耘。", "稻鍼出水蠶初掃，慚愧耕桑每廢勤。"]'),
('73ef2b58-de97-47e4-b333-25db0c25221f','用韻呈明叔','趙蕃','宋','宋诗','song-poetry','','[]','白鷗自倚占深灣，亦有幽人此照顔。',64,'全唐诗/poet.song.166000.json','["白鷗自倚占深灣，亦有幽人此照顔。", "豈但襟期非世俗，要知吟嘯奪天慳。", "江天見處從教闊，松竹栽成不要刪。", "我若賦詩君爲寫，絕人翰墨勝高閑。"]'),
('747aaaa7-e73d-49d5-af76-a20ceff767ed','用簽判丈送徐大雅之韻呈簽判丈兼簡子暢兄','趙蕃','宋','宋诗','song-poetry','','[]','年高端已輩吾翁，况倚通家夙好同。',64,'全唐诗/poet.song.166000.json','["年高端已輩吾翁，况倚通家夙好同。", "長夏江村能數過，論文尊酒未憂窮。", "分趨幕府如工部，耻入帝城因子公。", "聞道郎君亦輕祿，故知難進是家風。"]'),
('31cee403-b5a3-493a-9bf4-eb173a76e789','夜呈欽止審知時欽止歸自三衢','趙蕃','宋','宋诗','song-poetry','','[]','政爾相從問阿兄，忽聞門外竹車鳴。',64,'全唐诗/poet.song.166000.json','["政爾相從問阿兄，忽聞門外竹車鳴。", "對床縱復無今雨，展卷不妨同短檠。", "頗念興乘聊一詣，却憐侍立苦頻更。", "風微佛屋琅璫絕，古柏陰中看月明。"]'),
('7be96adb-813e-4d02-9101-65d2174a85ed','呈慶伯','趙蕃','宋','宋诗','song-poetry','','[]','顧藉微官無一分，强能從俗亦徒紛。',64,'全唐诗/poet.song.166000.json','["顧藉微官無一分，强能從俗亦徒紛。", "他鄉驟喜逢詩伯，故里渾疑對竹君。", "莫爲饑寒常道路，要留精力事耕耘。", "如君少壯端宜勉，老我衰摧直漫勤。"]'),
('79df8bc2-0b0f-416c-9503-7783f6dd1175','呈梁從善','趙蕃','宋','宋诗','song-poetry','','[]','飄流老矣謂知津，邂逅欣然願卜鄰。',64,'全唐诗/poet.song.166000.json','["飄流老矣謂知津，邂逅欣然願卜鄰。", "不但梁邢丈人行，更吾騷雅社中人。", "前秋一見遽爲別，今日重來情倍親。", "政自論詩得歡喜，更因話舊忽酸辛。"]'),
('526fee54-3157-4b97-8b78-e67ff64cfe75','呈審知二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','秋風已作重陽雨，客子將回下水船。',64,'全唐诗/poet.song.166000.json','["秋風已作重陽雨，客子將回下水船。", "卒歲褐裘悲破篋，豐年稌黍欠多田。", "平生漫說詩書學，滿眼不祛兒女煎。", "頗怪淵明瓶乏粟，若爲猶送酒家錢。"]'),
('91534572-fd12-408f-b93f-8f7fe0aea8d9','呈審知二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','樓前木葉下繽紛，樓上長吟獨有人。',64,'全唐诗/poet.song.166000.json','["樓前木葉下繽紛，樓上長吟獨有人。", "勿漫悲秋成楚些，要知達識自天真。", "從渠屐著一生幾，莫問錐無今歲貧。", "平日相期定何事，君今到岸我迷津。"]'),
('ce54ff4d-5b37-4514-beec-0516ec51f5d4','九日王越卿司法置酒要客始約登武安之塔爲遊人所先已過圓通晚更集於彥博之居越卿醉後作畫其先大夫公亦能畫云作詩二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','登高有約乃相違，故遣村船逆上溪。',64,'全唐诗/poet.song.166000.json','["登高有約乃相違，故遣村船逆上溪。", "寺與松篁元不隔，路經蓬藋却成迷。", "數君放逸仍懷古，老我悲凉况哭妻。", "鄭重莫逃雞黍社，又隨新月共扶藜。"]'),
('7e9a63b7-7dd2-4467-bcbb-bf6f7b1d4cf8','九日王越卿司法置酒要客始約登武安之塔爲遊人所先已過圓通晚更集於彥博之居越卿醉後作畫其先大夫公亦能畫云作詩二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','王家父子竹林期，談笑初無世俗姿。',64,'全唐诗/poet.song.166000.json','["王家父子竹林期，談笑初無世俗姿。", "戲搦敗毫成凍羽，醉回老力出枯枝。", "解吟秀句寰區滿，不擬常稱老畫師。", "大令右軍疑只爾，外人笑怪若能知。"]'),
('61ca3406-2003-4ee1-91a1-ad1586d31711','九日莫令置酒縣齋余以病不飲作詩呈坐客','趙蕃','宋','宋诗','song-poetry','','[]','孰使庭花未肯黄，政應知我鬢新霜。',64,'全唐诗/poet.song.166000.json','["孰使庭花未肯黄，政應知我鬢新霜。", "茫茫永夜無時旦，索索窮愁曾斷腸。", "坐久支吾催煮藥，飲豪絡驛看傳觴。", "廢遊不但因公事，風雨連朝故覺妨。"]'),
('73e1d220-e65b-4df8-969a-c87dbb9c7555','李商叟舉似用南澗山字韻茶山星字韻數詩輒借韻呈商叟二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','已悲傲吏失南山，尚喜王儦峙舊壇。',64,'全唐诗/poet.song.166000.json','["已悲傲吏失南山，尚喜王儦峙舊壇。", "感愴自應新髮白，乖離可使舊盟寒。", "篙師徑欲通宵發，我輩深嗟會面難。", "月底婆娑燈下語，怳然還是昔年看。"]'),
('c2a9d6f4-a672-4078-b111-677e052808f6','李商叟舉似用南澗山字韻茶山星字韻數詩輒借韻呈商叟二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','吾州疇昔聚文星，我已後之君有聲。',64,'全唐诗/poet.song.166000.json','["吾州疇昔聚文星，我已後之君有聲。", "丹筆未讎天祿閣，白頭猶住錦官城。", "舊諳林麓深堪隠，今見溪山遠更明。", "賸欲相投小盤礴，溪頭亡那櫓雙鳴。"]'),
('d72e33f7-bca1-463e-b8dd-9dcb9a8816fd','蕃嘗以閏九日約謝章二丈會南堂有事而止既欲復理前約乏酒未能因見唱酬嘉字韻詩卷借韻呈章丈','趙蕃','宋','宋诗','song-poetry','','[]','已後兒曹疾走誇，分同杜叟客忠嘉。',64,'全唐诗/poet.song.166000.json','["已後兒曹疾走誇，分同杜叟客忠嘉。", "白衣莫致有名物，青眼謾看無數花。", "念我豈無巖壑暇，從君恐及簿書譁。", "不唯孤負登臨約，亦覺詩筒到眼賒。"]'),
('1319c497-2d77-433d-a3dd-cb8fb0d55085','九月十一夜雨中讀吳夢與詩書以示之','趙蕃','宋','宋诗','song-poetry','','[]','疾風吹雨過江干，老屋闕牀無處乾。',64,'全唐诗/poet.song.166000.json','["疾風吹雨過江干，老屋闕牀無處乾。", "切切冷蛩深撼壁，纍纍饑鼠下窺簞。", "枕衾屢撫眠難著，燈火重呼詩細看。", "謾說爲官猶我似，念君懷抱若何寬。"]'),
('976ae93d-2dcb-4fed-95e1-378acdf90465','九月十六日文興折贈綠萼梅數枝花多而甚香非尋常梅花比也','趙蕃','宋','宋诗','song-poetry','','[]','舊聞良月似春時，真有梅花如許枝。',64,'全唐诗/poet.song.166000.json','["舊聞良月似春時，真有梅花如許枝。", "綠萼深宜翠羽宿，靜香獨許蜜蜂知。", "木犀莫道開能再，庭菊無嗟晚乃移。", "不是南方地偏暖，寵光潛已落天涯。"]'),
('6ac23f4e-3e48-4ca9-8521-b064255cc2ff','十月晨雨','趙蕃','宋','宋诗','song-poetry','','[]','昨夕斜陽照墟落，今晨細雨暗簷楹。',64,'全唐诗/poet.song.166000.json','["昨夕斜陽照墟落，今晨細雨暗簷楹。", "田夫荷笠趨田去，織婦連機競織聲。", "畏餒但憂瓶粟罄，怕寒聊倚鬢絲明。", "古來名士多如此，底事於予亦麽生。"]'),
('ee111fda-3d82-4f87-a7ea-baea41d1ccb6','十月三日鄭秀才惠菊植之晏齋窗前尊酒偶乏與稚子烹茶作重九','趙蕃','宋','宋诗','song-poetry','','[]','旋斫寒梢縛短籬，菊窠三兩带花移。',64,'全唐诗/poet.song.166000.json','["旋斫寒梢縛短籬，菊窠三兩带花移。", "莫嗟已落重陽後，自是江南秋到遲。", "菊開便是東坡節，酒盡空哦清晝詩。", "竹隠異時尋故事，送花常憶鄭當時。"]'),
('41564712-78fa-4f3c-9b7f-a533f0141df7','十一月初五日晨起書呈葉德章司法','趙蕃','宋','宋诗','song-poetry','','[]','卧聞落葉疑飄雨，起對空庭蓋卷風。',64,'全唐诗/poet.song.166000.json','["卧聞落葉疑飄雨，起對空庭蓋卷風。", "政自摧頹同病鶴，况堪吟颯類寒蟲。", "忽思有客渾如我，却念題詩不似公。", "已分虀鹽終白首，可因霜雪媿青銅。"]'),
('d524dcf5-c284-4053-b010-97882aa8f93a','德章法曹再用銅字韻作詩爲報復用韻奉答','趙蕃','宋','宋诗','song-poetry','','[]','人窮往往咎文窮，歷數前賢半此風。',64,'全唐诗/poet.song.166000.json','["人窮往往咎文窮，歷數前賢半此風。", "春去林園乃啼鴂，秋來牆壁自鳴蟲。", "世悲工瑟如齊客，我嘆好龍多葉公。", "苦節期君類松柏，根能如石幹如銅。"]'),
('3033fea3-7014-495a-bcf0-71796a33f7f2','十二月一日同陳明叔修絕江遊古城白泉','趙蕃','宋','宋诗','song-poetry','','[]','快閣呼舟渡碧江，舉篙驚破白鷗雙。',64,'全唐诗/poet.song.166000.json','["快閣呼舟渡碧江，舉篙驚破白鷗雙。", "謾云擇勝心如渴，不待窮幽意已降。", "試遣折梅巡野圃，少須酌茗坐僧窗。", "欲將韻語題今日，筆力輸君九鼎扛。"]'),
('312d2bde-5268-47b1-aa9b-ce0d7a34f57f','十二月初四夜同吳資深陳明叔宿觀山','趙蕃','宋','宋诗','song-poetry','','[]','一源何自發嵌空，漱月流風晝夜中。',64,'全唐诗/poet.song.166000.json','["一源何自發嵌空，漱月流風晝夜中。", "故有松聲雜清越，獨無梅影照玲瓏。", "鄉人但說觀山寺，客子深懷太史公。", "好事陳吳不易得，冒寒襆被肯來同。"]'),
('69538bc3-0bf6-4e00-becf-92a5b6663a04','呈辛卿二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','詩老當年聚此州，邇來零落盡山邱。',64,'全唐诗/poet.song.166000.json','["詩老當年聚此州，邇來零落盡山邱。", "公雖蹔爾淹時用，天豈特令繼夙游。", "幽事儻多塵事絕，靈山孰與博山優。", "林棲相去無百里，窈窕崎嶇可後不。"]'),
('58f8b316-5c46-4449-8ebe-4dcb3d3947b9','呈辛卿二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','今昔名流幾許人，况於室邇更身親。',64,'全唐诗/poet.song.166000.json','["今昔名流幾許人，况於室邇更身親。", "南州行卷雖云舊，東閣知名固若新。", "再見每懷風度遠，兩年空恨往來頻。", "其誰爲我談名姓，車轍勤公野水濱。"]'),
('bf1841ec-2c1a-4a79-81bd-8212f09425cb','進之復有湘潭之役二詩見惜別意  其一','趙蕃','宋','宋诗','song-poetry','','[]','歲盡君當又一歸，開正我亦具征衣。',64,'全唐诗/poet.song.166000.json','["歲盡君當又一歸，開正我亦具征衣。", "祇今湖北地非遠，異日江東書恐稀。", "酬唱未能相數數，別離於此再依依。", "到家無事還宜早，柳弄色時梅片飛。"]'),
('f2a010d6-4662-4606-9caa-391a028b93ba','進之復有湘潭之役二詩見惜別意  其二','趙蕃','宋','宋诗','song-poetry','','[]','君詩悟入已多年，信手拈來總自然。',64,'全唐诗/poet.song.166000.json','["君詩悟入已多年，信手拈來總自然。", "靜似幽人居在谷，勇如壯士起臨邊。", "波瀾收卷雖餘地，光豔發舒終屬天。", "笑我饑吟空白首，亂蛩衰草晚風蟬。"]'),
('22790ef5-359e-4d4a-9e36-73c4dd2cae1b','湖洲贈別劉叔驥昆仲','趙蕃','宋','宋诗','song-poetry','','[]','吳楚相望信不通，謾憑雙眼送歸鴻。',64,'全唐诗/poet.song.166000.json','["吳楚相望信不通，謾憑雙眼送歸鴻。", "豈知留落江湖外，又得從容笑語同。", "賸把詩篇攄別恨，莫辜杯酒對秋風。", "明朝徑問吳松路，恨不與君俱短篷。"]'),
('6d8ebb79-da96-4069-94a1-de3c2a2b74e6','別趙常德','趙蕃','宋','宋诗','song-poetry','','[]','舊詩零落似前生，豈意公能識姓名。',64,'全唐诗/poet.song.166000.json','["舊詩零落似前生，豈意公能識姓名。", "青眼何堪辱如故，白頭自覺已無成。", "普天無復歸耕處，薄祿謾爲餬口營。", "今日違離定何往，壺頭路險更秦城。"]'),
('f19d1ea6-7c48-4503-8a8c-4caa710cce99','別晦菴','趙蕃','宋','宋诗','song-poetry','','[]','身墮南州已覺賒，五溪從此更天涯。',64,'全唐诗/poet.song.166000.json','["身墮南州已覺賒，五溪從此更天涯。", "別腸何止成萬轉，霜鬢不堪今半加。", "頗念客留同此日，絕憐歸夢每還家。", "公如踵赴仙都約，猶擬頡頏飛佩霞。"]'),
('01f5cfdb-6db9-431c-aeb6-06caa86067fe','留別邢大聲昆仲','趙蕃','宋','宋诗','song-poetry','','[]','再歲春風把酒杯，今年更覺倍遲回。',64,'全唐诗/poet.song.166000.json','["再歲春風把酒杯，今年更覺倍遲回。", "海棠消息知渠負，楊柳風流笑我衰。", "舟過重湖定安否，書來一紙勿悠哉。", "是身老矣腰仍折，寧待田園歸未來。"]'),
('d2ae6c2f-e12d-495c-a0ac-66d40f3cce4e','留別趙南紀','趙蕃','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','少時未識廬山好，老去知山却遠山。',64,'全唐诗/poet.song.166000.json','["少時未識廬山好，老去知山却遠山。", "白鹿何繇與絃誦，紫霄還復共躋攀。", "林巒有失君何意，松菊猶存我得還。", "俱是江東巡管內，異時書札願無慳。"]'),
('4b6f0647-cd01-429c-9661-729b7c5db332','留別俞孝顯孝揚','趙蕃','宋','宋诗','song-poetry','','[]','生事平生非我謀，饑寒長是費君憂。',64,'全唐诗/poet.song.166000.json','["生事平生非我謀，饑寒長是費君憂。", "相如自厭遊成倦，曲逆人知老不侯。", "盡室經年曾未厭，一官千里去難留。", "異時安否如相憶，一問溪頭上水舟。"]'),
('feef8caa-bead-4147-a974-8f7e26da778b','留別在伯','趙蕃','宋','宋诗','song-poetry','','[]','準擬梅花共賦詩，那知人事有乖離。',64,'全唐诗/poet.song.166000.json','["準擬梅花共賦詩，那知人事有乖離。", "交情自謂惟君厚，世態于今猶我知。", "盡室飄飄雖匪計，此心烱烱幸無欺。", "一官謾浪端何以，從此歸耕已自遲。"]'),
('1704e072-e67b-4275-8749-354265a9c119','鍾子崧己丑歲簿秩滿去今自饒州教授還猶選人也感嘆之餘賦以別','趙蕃','宋','宋诗','song-poetry','','[]','十四年中三別君，別君每輒嘆離群。',64,'全唐诗/poet.song.166000.json','["十四年中三別君，別君每輒嘆離群。", "案惟占位崔斯立，客乃無氈鄭廣文。", "給札不能因狗監，校書從昔老揚雲。", "君顔得酒猶能少，我髮如霜不可耘。"]'),
('1f75eebb-6376-4002-bf71-c000a970508b','贈別徐永叔','趙蕃','宋','宋诗','song-poetry','','[]','憶曾看竹過焦山，重記同舟駭浪間。',64,'全唐诗/poet.song.166000.json','["憶曾看竹過焦山，重記同舟駭浪間。", "邂逅真成肺肝熱，別離空益鬢毛斑。", "芻青飯白吾能設，車殆馬煩君莫還。", "此去江淮兩蕭瑟，爲言無遣尺書慳。"]'),
('a4646582-038f-4224-9902-e43f731a36d9','別范建康','趙蕃','宋','宋诗','song-poetry','','[]','早日學詩才得窮，人窮乃復媿詩工。',64,'全唐诗/poet.song.166000.json','["早日學詩才得窮，人窮乃復媿詩工。", "如公久已獨步外，顧我何堪猥誦中。", "歲晚人家方墐戶，地長客子尚飄蓬。", "如聞深講救荒政，忍使簞瓢獨屢空。"]'),
('78b7a1c4-1be2-4b64-b8db-c2deaa0cf0bc','別朱子大蘇召叟昆仲','趙蕃','宋','宋诗','song-poetry','','[]','薄宦塵埃易滿襟，問盟猶喜盍朋簪。',64,'全唐诗/poet.song.166000.json','["薄宦塵埃易滿襟，問盟猶喜盍朋簪。", "只今風月一杯酒，明日雲山千里心。", "楊柳陰疎秋舘凈，芙蓉香冷暮江深。", "潮回一信西興渡，頻寄相思別後吟。"]'),
('53f1ccc3-db99-4264-aab4-e1c5e0380406','留別周愚卿兄弟','趙蕃','宋','宋诗','song-poetry','','[]','四海雖云皆弟昆，悵茲薄俗與誰論。',64,'全唐诗/poet.song.166000.json','["四海雖云皆弟昆，悵茲薄俗與誰論。", "平生泛愛老逾厭，獨覺君家久更敦。", "百里闌干山作几，數家籬落竹爲村。", "異時相憶相思處，明月清風同酒樽。"]'),
('9ae1de92-d957-4e83-9062-5ce58c4af0c3','留別叔驥和叔','趙蕃','宋','宋诗','song-poetry','','[]','一見梅花醒病昏，重逢雙璧競清溫。',64,'全唐诗/poet.song.166000.json','["一見梅花醒病昏，重逢雙璧競清溫。", "占風占雨行未已，看水看山心故存。", "亹亹愛渠談緒遠，班班覺我髩絲繁。", "江天何處不須買，畝蕙畹蘭期並門。"]'),
('a999c803-1eb8-41ce-bce3-aecc135c40e8','寄周昭禮','趙蕃','宋','宋诗','song-poetry','','[]','都城飲別四年餘，寥闊無因問起居。',64,'全唐诗/poet.song.166000.json','["都城飲別四年餘，寥闊無因問起居。", "聞道客游猶往昔，不知生理比何如。", "謾從詩卷追還往，肯向書筒計密疎。", "折得梅花睇江水，驛程千萬渺愁予。"]'),
('8723392f-1039-4c40-8390-b009bda97545','寄劉凝遠丈二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','清時二浙湖山主，合在公家不屬人。',64,'全唐诗/poet.song.166000.json','["清時二浙湖山主，合在公家不屬人。", "求去非貪鏡湖賜，歸來便作許由鄰。", "喜聞吾黨有高退，頓使幽居忘賤貧。", "想見詩題硬黄紙，更無夢到軟紅塵。"]'),
('a24dc521-ed45-40d3-82d4-68e23842f1e0','寄劉凝遠丈二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','水雲痛飲玉光詩，勝踐那容俗子知。',64,'全唐诗/poet.song.166000.json','["水雲痛飲玉光詩，勝踐那容俗子知。", "此樂祇今寧夢見，臨風空爾費懷思。", "蘇門長嘯誰能和，赤壁成功顧已遲。", "當日唱酬誰復與，皆云驥子好男兒。"]'),
('38cd60c9-93a5-4af4-8e39-a655eca38a1f','得周畏知書病久不報以詩寄之','趙蕃','宋','宋诗','song-poetry','','[]','莫道寒溫祇素書，也於朋友見親疎。',64,'全唐诗/poet.song.166000.json','["莫道寒溫祇素書，也於朋友見親疎。", "自從一反南昌役，無復能安古寺居。", "憔悴直爲人所棄，殷勤獨肯問何如。", "缺然不報非緣懶，瘧癘經秋未掃除。"]'),
('7f2ebb7e-2fd2-4541-89ee-26b122555eea','去年過鉛山一見季承自後邈不相聞秋試度必入城因成父行寄之以詩','趙蕃','宋','宋诗','song-poetry','','[]','去歲飄然反自閩，訪君曾爲駐征輪。',64,'全唐诗/poet.song.166000.json','["去歲飄然反自閩，訪君曾爲駐征輪。", "尺書不至知殊縣，五字可追如隔晨。", "秦論舊聞追廼祖，漢庭那得棄平津。", "行當過我一飯去，要話別來長苦辛。"]'),
('c6739548-562e-4151-b3ec-e250de22376d','以孟夏唱酬陳子高詩寄季承并借窮愁志及其兄興化集四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','莫嗔不寄一行書，半百光陰伏枕餘。',64,'全唐诗/poet.song.166000.json','["莫嗔不寄一行書，半百光陰伏枕餘。", "寂寞瓶儲同靖節，荒凉壁立類相如。", "君今爲况復何似，秋盡想應成定居。", "穫稻讒終還墐戶，有詩何日定遺予。"]'),
('413d6c23-6755-452b-ad30-7dc1ec66eb9e','以孟夏唱酬陳子高詩寄季承并借窮愁志及其兄興化集四首  其二','趙蕃','宋','宋诗','song-poetry','','[]','東湖共款竹多竿，妙果同登塔幾盤。',64,'全唐诗/poet.song.166000.json','["東湖共款竹多竿，妙果同登塔幾盤。", "衝雨衝風總幽事，一談一笑盡詩端。", "隨人似我空爲計，出語如君當不刊。", "派後江西有驚坐，封題併與略評看。"]'),
('bb890af4-9307-4c1e-8f0e-c37afae8a110','以孟夏唱酬陳子高詩寄季承并借窮愁志及其兄興化集四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','故家不復見中州，插架聞君似鄴侯。',64,'全唐诗/poet.song.166000.json','["故家不復見中州，插架聞君似鄴侯。", "往事誰能論牛李，舊書聊欲借窮愁。", "薰蕕政自難同器，涇渭懸知卒異流。", "何事古今朋黨禍，力爭終以殺身酬。"]'),
('71e7318c-6274-44d8-b9fd-f241d1b12d1c','以孟夏唱酬陳子高詩寄季承并借窮愁志及其兄興化集四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','著論端能擬過秦，苦吟長學跨馿人。',64,'全唐诗/poet.song.166000.json','["著論端能擬過秦，苦吟長學跨馿人。", "十年不調非求異，三徑爲資本作貧。", "回首浮梁屢還往，斷魂宿草幾陳新。", "藏家有集曾三復，借我流傳莫謾珍。"]'),
('6946d07c-992c-4d4d-b3a8-5c145a42420d','九日寄和父弟','趙蕃','宋','宋诗','song-poetry','','[]','走馬憶登江上臺，聞知興廢使人哀。',64,'全唐诗/poet.song.166000.json','["走馬憶登江上臺，聞知興廢使人哀。", "遥憐冷澹黄花節，遠對飄零白雁來。", "念爾不堪懷爲惡，思余應是首頻回。", "詩成寄與憨申誦，句累難教心孔開。"]'),
('d6149b71-1170-4a85-92bd-94ad6c50e268','寄懷畏知二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','湘山峻刻湘流深，中有騷人憤世音。',64,'全唐诗/poet.song.166000.json','["湘山峻刻湘流深，中有騷人憤世音。", "弔古自爲吾輩事，宦游端識故人心。", "別來未有音書至，歲晚勿令霜露侵。", "聞道元戎今仲舉，定除塵榻伴登臨。"]'),
('25879309-1360-4d33-bd97-e5c02ce15beb','寄懷畏知二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','共旅長安暑未徂，到家忽已秋風初。',64,'全唐诗/poet.song.166000.json','["共旅長安暑未徂，到家忽已秋風初。", "十詩道別心期遠，千里相望魂夢疎。", "驛使梅來應寄我，衡陽鴈渺更愁予。", "如君乃作諸侯客，顧使誰讎東觀書。"]'),
('1b19bf64-d444-44eb-a972-f9e05af7be76','久不聞表叔張平子安否覓使寄此','趙蕃','宋','宋诗','song-poetry','','[]','一自書題闕寄將，不知今度幾飛霜。',64,'全唐诗/poet.song.166000.json','["一自書題闕寄將，不知今度幾飛霜。", "空云梅嶺有驛使，可奈衡陽無雁行。", "好趁薦章求北闕，莫因文價滯南荒。", "已今快閣治詩板，準擬歸舟略繫傍。"]'),
('92592603-dc00-49fe-ad40-e37cbd21fef7','寄懷子進昆仲三首  其一','趙蕃','宋','宋诗','song-poetry','','[]','晚雨催寒著破裘，官梅應是動揚州。',64,'全唐诗/poet.song.166000.json','["晚雨催寒著破裘，官梅應是動揚州。", "相思不見蘇門隠，好在當年玉局遊。", "擬向會稽探禹穴，却從吳會下扁舟。", "不須幸甚門亡恙，翻到舊詩容我不。"]'),
('8559a6aa-f2a7-4091-a04e-6763a0e4fe69','寄懷子進昆仲三首  其二','趙蕃','宋','宋诗','song-poetry','','[]','鴈不歸時聞有行，鴈南飛處更關情。',64,'全唐诗/poet.song.166000.json','["鴈不歸時聞有行，鴈南飛處更關情。", "三年有句說還往，半載無書存死生。", "莫歎河山殊舉目，會須童僕爲歡迎。", "四方取友吾非乏，孰若君家賢弟兄。"]'),
('42c3a871-171a-4e2d-8a99-7e0811ef7cbf','寄懷子進昆仲三首  其三','趙蕃','宋','宋诗','song-poetry','','[]','聞道築堂名遂初，規模渾是退居圖。',64,'全唐诗/poet.song.166000.json','["聞道築堂名遂初，規模渾是退居圖。", "藏書自有三萬軸，種橘何多二百株。", "我似杜陵寧老蜀，君如張翰已歸吳。", "詩成把酒遥相屬，門外北風方怒呼。"]'),
('78b6c3ce-e65f-4dce-a549-0974c486fee6','寄懷畏知二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','憶昨題詩歲且更，路長誰與附書行。',64,'全唐诗/poet.song.166000.json','["憶昨題詩歲且更，路長誰與附書行。", "登樓見說同王粲，爲賦懸知似賈生。", "杜老性非真傲誕，元龍氣自舊崢嶸。", "天寒萬物皆收歛，惟有孤松獨向榮。"]'),
('c6141875-4b20-4706-9acb-3205a294dfe3','寄懷畏知二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','馳檄傳聞思一來，溪頭幾立望檣桅。',64,'全唐诗/poet.song.166000.json','["馳檄傳聞思一來，溪頭幾立望檣桅。", "黄花又作霜前槁，白酒空留秋後醅。", "早歲交遊今孰在，暮年林壑要深陪。", "世間名宦豈不好，只恐勢移成溺灰。"]'),
('eb61752e-fa3b-4021-bde6-a8d207e40b49','過吉水問蕭伯和兄弟云在縣四十里之羅陂遠不及見以詩寄之併呈仲和','趙蕃','宋','宋诗','song-poetry','','[]','憶昨携詩辱報詩，再來有約竟乖期。',64,'全唐诗/poet.song.166000.json','["憶昨携詩辱報詩，再來有約竟乖期。", "不應置我毋庸友，何自令人極所思。", "千里葉舟黄落後，一官斗粟倦游時。", "訪尋不見蕭齊處，風雨何由話別離。"]'),
('55a08944-1f52-488b-9291-0a11d4e91a90','寄南安李使君三章  其一','趙蕃','宋','宋诗','song-poetry','','[]','頻宵爲月卧風前，異世風流懷謫仙。',64,'全唐诗/poet.song.166000.json','["頻宵爲月卧風前，異世風流懷謫仙。", "半年且闊書郵置，六輩肯來從事賢。", "白衣不但覓陶令，春草因之感惠連。", "醉裏悠悠更何夢，南池水長疊荷錢。"]'),
('d5f57607-99ae-49a3-b990-a6e7bc287f5d','寄南安李使君三章  其二','趙蕃','宋','宋诗','song-poetry','','[]','臼擣紛紛何所如，碾成更自治家模。',64,'全唐诗/poet.song.166000.json','["臼擣紛紛何所如，碾成更自治家模。", "不盡粉身兼碎骨，爲看落雪又霏珠。", "體用同歸人力致，粗精孰愈磨工夫。", "舊聞此物獨君地，要伴筆牀能寄無。"]'),
('241257e6-1a58-47af-97a0-270d00833e18','寄南安李使君三章  其三','趙蕃','宋','宋诗','song-poetry','','[]','如聞舍策已蹁躚，神物護持非藥痊。',64,'全唐诗/poet.song.166000.json','["如聞舍策已蹁躚，神物護持非藥痊。", "爲州莫漫貪良醖，把節何遲復舊氈。", "但期米許頻仍乞，敢望舟同縹緲僊。", "別久未能成一詣，故憐終日泥陳編。"]'),
('14ff95b7-f835-46ec-a5b0-bd38601a9a4d','寄贈孫教授兄弟','趙蕃','宋','宋诗','song-poetry','','[]','籍甚所聞三桂堂，向來相與但南昌。',64,'全唐诗/poet.song.166000.json','["籍甚所聞三桂堂，向來相與但南昌。", "橫經重識泮宮老，捧檄仍思幕府良。", "日暮酒尊勤洒掃，竹邊談几愛蒼凉。", "梅江父子風流舊，今見君家鴻鴈行。"]'),
('2940194c-055e-4540-b7b8-dba34daf0446','成父自太和來相看復回既別有作寄之','趙蕃','宋','宋诗','song-poetry','','[]','一馬能來破遠愁，送歸還是上扁舟。',64,'全唐诗/poet.song.166000.json','["一馬能來破遠愁，送歸還是上扁舟。", "鴒原眷眷急難義，菟裘切切將老求。", "吾兒可使齊書帙，汝歸仍堪爲酒謀。", "把玩餘齡無幾許，可如罝兔媿江鷗。"]'),
('54cf598a-8f12-4cb8-8963-3e727727d93c','寄俞玉汝','趙蕃','宋','宋诗','song-poetry','','[]','晦庵寄我溧陽書，報道今爲建業居。',64,'全唐诗/poet.song.166000.json','["晦庵寄我溧陽書，報道今爲建業居。", "作客遽經三歲久，賦詩應盡六朝餘。", "莫將明月誇魚目，自昔鹽車羨蹇馿。", "期子歸來趁鮮健，老無筋力事犂鋤。"]'),
('4dac6425-8611-4d75-a2a4-1f748826f6eb','十二月初六夜夢客溧陽半月而未見晦菴夢中以見遲爲併作詩謝之首句云平生知己晦菴老歲晚方懷見晚羞寐而診曰羈於一官久去師門精神之感形見如此耶用其句賦詩一章寄上','趙蕃','宋','宋诗','song-poetry','','[]','平生知己晦菴老，歲晚方懷見晚羞。',64,'全唐诗/poet.song.166000.json','["平生知己晦菴老，歲晚方懷見晚羞。", "題詩寄公夏始盛，遣弟持書春又浮。", "謝安東山豈我舍，迂叟洛中常國憂。", "蟠桃結實動千載，朝菌不與晦朔謀。"]'),
('846f20ae-6a26-43c1-9063-c3ae35c097cd','聞劉彥說率友生過別業以詩寄之與彥說之約者皆當和此詩也','趙蕃','宋','宋诗','song-poetry','','[]','柿栗當收穫稻終，駕言野適興何窮。',64,'全唐诗/poet.song.166000.json','["柿栗當收穫稻終，駕言野適興何窮。", "門生二子歸來晝，張丈殷兄鄰舍翁。", "豆飯芋魁吾豈乏，鷄豚社酒歲仍豐。", "家山日日長牽念，何况傳聞襆被同。"]'),
('3f0c0ae0-2637-49bd-bf5d-0ef204fd9456','因誠齋寄張三十叔','趙蕃','宋','宋诗','song-poetry','','[]','韶石馳書歲屢終，浮湛渺渺聽殷洪。',64,'全唐诗/poet.song.166000.json','["韶石馳書歲屢終，浮湛渺渺聽殷洪。", "長年苦望吾地涉，寧料它途馬首東。", "鴻鴈又當辭瘴海，孔鸞端合在高桐。", "忽逢玉節春江上，再拜題詩覓寓公。"]'),
('e471775a-164e-4eca-9048-59e63d7be234','寄孫從之','趙蕃','宋','宋诗','song-poetry','','[]','顧使斯人墨綬腰，不知誰合上丹霄。',64,'全唐诗/poet.song.166000.json','["顧使斯人墨綬腰，不知誰合上丹霄。", "得非疲瘵要摩撫，是遣循良頒詔條。", "聞道過家猶數月，尚期論薦出公朝。", "過予不作一飯去，政倚相望非甚遥。"]'),
('60c967de-d32b-4446-8ce5-cb717c6443ff','寄趙著作','趙蕃','宋','宋诗','song-poetry','','[]','有客東來爲我言，詔書傳已下修門。',64,'全唐诗/poet.song.166000.json','["有客東來爲我言，詔書傳已下修門。", "幡然要識朝廷意，易此方明父子恩。", "物望祇今誰得似，道行寧負夙心存。", "公其大作斯民庇，我亦耕桑安故園。"]'),
('6eca8c49-70b0-4b0b-aec9-d16ac42a04e5','寄彭元思','趙蕃','宋','宋诗','song-poetry','','[]','憶昨寄書今幾日，缺然無地接殷勤。',64,'全唐诗/poet.song.166000.json','["憶昨寄書今幾日，缺然無地接殷勤。", "秋風紅葉堪題句，寒夜青燈憶對君。", "三徑吾將歸問路，一尊何日再論文。", "番湖政與冰溪接，雞犬雖遥亦共聞。"]'),
('f7f5fb20-5882-4cd5-89b2-9f16f4638e79','寄黄子耕','趙蕃','宋','宋诗','song-poetry','','[]','誰能一枉林間寺，君獨屢過湖上村。',64,'全唐诗/poet.song.166000.json','["誰能一枉林間寺，君獨屢過湖上村。", "先世文章出遺逸，當家句法有淵源。", "平生所識蓋無幾，盛意若何如見存。", "元祐蘭臺妙人物，我今寂寞媿諸孫。"]'),
('d2b866db-f118-4df3-97a5-ff040acb4ac3','寄曾季永','趙蕃','宋','宋诗','song-poetry','','[]','水竹懸知屬所思，風埃遥想未忘詩。',64,'全唐诗/poet.song.166000.json','["水竹懸知屬所思，風埃遥想未忘詩。", "萬言何有一杯直，三徑寧須五斗爲。", "安否頻來道州札，緘封更得白鵝碑。", "政和父老猶存否，煩與殷勤訪逸遺。"]'),
('e121555e-1501-4b75-bdd9-9b41b0dce288','寄愚卿兄弟兼屬伯威','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','樓上長江江上山，烟雲鷗鳥尚班班。',64,'全唐诗/poet.song.166000.json','["樓上長江江上山，烟雲鷗鳥尚班班。", "歸來靖節荒三徑，已矣盧仝屋數間。", "書肯細行知義立，夢能頻見識心關。", "因聲重謝窮岡叟，太息劉郎去不還。"]'),
('eb7a3bbe-f410-4fbc-a5a0-5c2be5546315','寄趙文鼎','趙蕃','宋','宋诗','song-poetry','','[]','殷勤寄謝湖州牧，五馬誰能鬢未斑。',64,'全唐诗/poet.song.166000.json','["殷勤寄謝湖州牧，五馬誰能鬢未斑。", "民事雖云急期會，登臨要不負溪山。", "如公詎免帝城入，有詔不遲旬歲間。", "人士端能客張賈，聲名自不減蘇顔。"]'),
('c241bc72-eff7-4ce8-90e6-b15dd9e358ec','寄道正闍黎二老師并帖季蕭兄','趙蕃','宋','宋诗','song-poetry','','[]','三年光景一篇詩，此世何堪作許離。',64,'全唐诗/poet.song.166000.json','["三年光景一篇詩，此世何堪作許離。", "一代聲名屬韓呂，百年衣鉢付嚴黎。", "風生佛屋朝談處，月滿仙壇夜步時。", "珍重陵陽老孫子，當時酬唱亦同之。"]'),
('a5debd03-c276-41c0-9c97-4ecc5168e668','寄倪好問','趙蕃','宋','宋诗','song-poetry','','[]','問訊永州倪戶曹，別來歲月已滔滔。',64,'全唐诗/poet.song.166000.json','["問訊永州倪戶曹，別來歲月已滔滔。", "賢居幕府定餘暇，舟過浯溪今幾遭。", "頌出次山微自顯，詩成太史貶無褒。", "因來打寄山中本，併以張秦翰墨豪。"]'),
('f65c2600-9f8e-479b-8093-44dadac3690d','寄贈侯宿彥明','趙蕃','宋','宋诗','song-poetry','','[]','晁鄭風流俱外家，源流如此見津涯。',64,'全唐诗/poet.song.166000.json','["晁鄭風流俱外家，源流如此見津涯。", "難兄竟沒荒三徑，吾叔重嗟書五車。", "家世詩聲繼叔起，古來材秀滯長沙。", "順寧不作南軒死，吾道傷哉鬢已華。"]'),
('d107f207-c795-424c-99ab-cb727446c72b','李商叟傳錄臨川與黎師侯唱酬懷曾文清公長句用韻作四首  其一','趙蕃','宋','宋诗','song-poetry','','[]','欲訪臨川苦恨遲，一官窘束費符移。',64,'全唐诗/poet.song.166000.json','["欲訪臨川苦恨遲，一官窘束費符移。", "臺高納日朝尋勝，蕉合生風夜語離。", "別後有懷長入夢，向來未識已傳詩。", "信知習氣難除洗，可怪深悲墨翟絲。"]'),
('1f2fdb04-32bf-42cc-8731-dd05b2a2b39d','李商叟傳錄臨川與黎師侯唱酬懷曾文清公長句用韻作四首  其二','趙蕃','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','生世胡爲爾許遲，况經事變與時移。',64,'全唐诗/poet.song.166000.json','["生世胡爲爾許遲，况經事變與時移。", "論文尚喜兩公在，一見何勝隔歲離。", "落木長江天末恨，清風朗月卷中詩。", "有懷曾子今冥漠，雨淚真成滿面絲。"]'),
('e62b3b6b-0f60-4835-b446-416ff958a00c','李商叟傳錄臨川與黎師侯唱酬懷曾文清公長句用韻作四首  其三','趙蕃','宋','宋诗','song-poetry','','[]','向夕相尋昔步遲，坐殘初月見陰移。',64,'全唐诗/poet.song.166000.json','["向夕相尋昔步遲，坐殘初月見陰移。", "關心去後幾南北，倒指從前屢合離。", "君歎我貧猶爲米，我憐君苦伹耽詩。", "三山堂下冰溪水，何日扁舟兩釣絲。"]'),
('1e1db489-f8b0-4a14-888a-57c12546633c','李商叟傳錄臨川與黎師侯唱酬懷曾文清公長句用韻作四首  其四','趙蕃','宋','宋诗','song-poetry','','[]','歎息茶山識面遲，經過舊宅恨推移。',64,'全唐诗/poet.song.166000.json','["歎息茶山識面遲，經過舊宅恨推移。", "聽泉尚想甘瓢樂，撫竹如親與物離。", "千首未多行世集，數篇纔刻住山詩。", "屬君勉力任茲事，吾道祇今棼若絲。"]'),
('2216daaa-14c6-4071-8e78-72a799586268','寄徐季純于去非兼屬梁和仲曾元之吳仲權','趙蕃','宋','宋诗','song-poetry','','[]','西來政爾歎離居，數士英英端起予。',64,'全唐诗/poet.song.166000.json','["西來政爾歎離居，數士英英端起予。", "情話不遺親且故，高交寧有數能疏。", "詩章許和平反暇，尊酒仍饕簿領餘。", "幕府河南亦名勝，願交煩爲問何如。"]'),
('406657e1-e3d0-4245-97ec-5e02394e4a96','寄甘叔異戶曹賈季承鄧南季教授二首  其一','趙蕃','宋','宋诗','song-poetry','','[]','去年舟上曲江磯，招隠無人詠桂枝。',64,'全唐诗/poet.song.166000.json','["去年舟上曲江磯，招隠無人詠桂枝。", "常恨書題苦寥闊，不堪歲月重流離。", "誰云司戶官雖小，舊說訾洲前所遺。", "登臨想見日成賦，寄我何當爲解頤。"]'),
('932aff6c-7397-4add-bab2-fc3e65636057','寄甘叔異戶曹賈季承鄧南季教授二首  其二','趙蕃','宋','宋诗','song-poetry','','[]','婺女牽牛皆粵分，鬰林合浦屬交州。',64,'全唐诗/poet.song.166000.json','["婺女牽牛皆粵分，鬰林合浦屬交州。", "偶逢人向渠陽去，爲寄書從八桂求。", "率土溥天非不廣，劍山带水祇供愁。", "明年闕下當皆集，誰序盛山今日游。"]'),
('f1c3df37-3e55-4fc0-8290-a403bc7010a6','寄陳擇之','趙蕃','宋','宋诗','song-poetry','','[]','幾向圖經問水源，未知蜀道遠如天。',64,'全唐诗/poet.song.166000.json','["幾向圖經問水源，未知蜀道遠如天。", "書題無自寄鴻鴈，鳥語不堪聞杜鵑。", "已自草堂參句法，更於錦里醉風煙。", "使行萬里無空反，乞與新詩到處傳。"]'),
('dbd133ca-82fe-4eb0-b1a0-37c164fbf1d1','寄周允升','趙蕃','宋','宋诗','song-poetry','','[]','竟孤春碧醉梅前，猶喜囊中有和篇。',64,'全唐诗/poet.song.166000.json','["竟孤春碧醉梅前，猶喜囊中有和篇。", "雪後晚風衡嶽路，雨餘秋色五溪邊。", "一書寥闊忘重寄，小別侵尋過半年。", "頼是時從安道逸，有時共說伯仁賢。"]'),
('e0ddfb7f-5e16-49d2-bd78-f9e76657d0d7','子耕錄寄老圃賦及千秋觀諸詩寄謝','趙蕃','宋','宋诗','song-poetry','','[]','歆向當年苦持難，少卿爲有廣之風。',64,'全唐诗/poet.song.166000.json','["歆向當年苦持難，少卿爲有廣之風。", "求君政合形骸外，笑我猶拘意匠中。", "遠寄一朝成暴富，深藏沒世免終窮。", "客來賸喜誇張事，何幸交游得是公。"]'),
('1d1c7596-d1a8-44a5-bdd1-8b0a35cb9e95','寄謝景英丈','趙蕃','宋','宋诗','song-poetry','','[]','先生豈是愛監州，高興應爲雁蕩游。',64,'全唐诗/poet.song.166000.json','["先生豈是愛監州，高興應爲雁蕩游。", "康樂當年空想望，雲孫今日慰淹留。", "幽人衲子應多識，妙偈名章可寄不。", "兜率蓬萊果同異，不妨歸步在丹丘。"]'),
('fa1dc55e-ae66-4070-891c-2ced54d587b4','子進昆仲俱和寄懷三詩復次韻  其一','趙蕃','宋','宋诗','song-poetry','','[]','此山祇合便終焉，底用心勞學計然。',64,'全唐诗/poet.song.166000.json','["此山祇合便終焉，底用心勞學計然。", "貧賤已安身外事，功名寧顧俗間緣。", "舊遊要紀東南勝，有句須從甲乙編。", "閑向晴窗遮老眼，亦堪時伴結跏禪。"]'),
('3bed6824-96d3-4fd3-9a7a-24a11effc226','子進昆仲俱和寄懷三詩復次韻  其二','趙蕃','宋','宋诗','song-poetry','','[]','古途荆棘少人行，制禮難招魯二生。',64,'全唐诗/poet.song.166000.json','["古途荆棘少人行，制禮難招魯二生。", "世上兒曹俱覆轍，公家伯仲自爭衡。", "一年欲盡見松秀，衆水莫污知渭清。", "保此不渝真有道，更須直以所能鳴。"]'),
('ff42b606-d4e4-4ad8-a6d8-97f273a273f3','子進昆仲俱和寄懷三詩復次韻  其三','趙蕃','宋','宋诗','song-poetry','','[]','有竹相娛道豈孤，信知造物未遺予。',64,'全唐诗/poet.song.166000.json','["有竹相娛道豈孤，信知造物未遺予。", "交游更許得奇士，保社却嗟無定居。", "懷玉近傳酬倡集，荆溪與說往還書。", "世人徇利輕翻覆，我輩百年端一如。"]'),
('246d15ae-7328-4ebf-aea0-673e4c148100','次韻程士和并帖元衡','趙蕃','宋','宋诗','song-poetry','','[]','滿目風埃頓爾清，祇緣朝雨過林聲。',64,'全唐诗/poet.song.166000.json','["滿目風埃頓爾清，祇緣朝雨過林聲。", "興乘政欲蟬連語，酒釅才勝一再行。", "容我不應嗔醉卧，憶君還復有詩成。", "定知今夜江東夢，夢炤冰溪雪鬢生。"]'),
('d1d456b5-7108-4ff4-b40d-83d0c51d3247','審知用由字韻作詩見示次韻','趙蕃','宋','宋诗','song-poetry','','[]','山可屐登溪可浮，崎嶇窈窕悵無由。',64,'全唐诗/poet.song.166000.json','["山可屐登溪可浮，崎嶇窈窕悵無由。", "功名竟爾異吾事，邱壑只然須我流。", "夏日炎蒸端畏病，秋天瀟洒信宜遊。", "關心懷玉山前路，要上諸峯最上頭。"]');
